            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[Field]
                (
                    [id] INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_Field] PRIMARY KEY,
                    -- GroupId INT olmali — FieldGroup.id INT, FK uyumlu olsun (boş DB ilk kurulumda
                    -- UNIQUEIDENTIFIER tip uyumsuzlugu nedeniyle FK patliyodu).
                    [GroupId] INT NULL,
                    [FieldKey] NVARCHAR(60) NOT NULL,
                    [FieldLabel] NVARCHAR(120) NOT NULL,
                    [DataType] NVARCHAR(30) NOT NULL CONSTRAINT [DF_Field_DataType] DEFAULT(N'STRING'),
                    [IsVisible] BIT NOT NULL CONSTRAINT [DF_Field_IsVisible] DEFAULT(1),
                    [IsRequired] BIT NOT NULL CONSTRAINT [DF_Field_IsRequired] DEFAULT(0),
                    [DefaultValue] NVARCHAR(500) NULL,
                    [DisplayOrder] INT NOT NULL CONSTRAINT [DF_Field_DisplayOrder] DEFAULT(0),
                    [ColumnSpan] INT NOT NULL CONSTRAINT [DF_Field_ColumnSpan] DEFAULT(1),
                    [IsSystem] BIT NOT NULL CONSTRAINT [DF_Field_IsSystem] DEFAULT(0),
                    [IsActive] BIT NOT NULL CONSTRAINT [DF_Field_IsActive] DEFAULT(1),
                    [Created] DATETIME NOT NULL,
                    [Updated] DATETIME NULL,
                    CONSTRAINT [FK_Field_FieldGroup]
                        FOREIGN KEY ([GroupId]) REFERENCES [{schemaForSql}].[FieldGroup]([id])
                );

                CREATE UNIQUE INDEX [UX_Field_FieldKey]
                    ON [{schemaForSql}].[Field]([FieldKey]);
            END;

            -- Snake_case → PascalCase migration (Field tablosu legacy schema'dan geliyorsa):
            -- 2.1.8'den önce upgrade edilen kurulumlarda Field tablosu snake_case kolonlarla
            -- yaratılmış olabilir (field_key, data_type, vs.). Sonraki UPDATE/CREATE INDEX
            -- statement'ları PascalCase bekliyor — rename etmezsek "Invalid column name 'FieldKey'"
            -- hatasıyla initializer komple çöker (Web + Worker servisi kalkamaz).
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'field_key') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'FieldKey') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].field_key', N'FieldKey', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'field_label') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'FieldLabel') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].field_label', N'FieldLabel', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'data_type') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'DataType') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].data_type', N'DataType', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'is_visible') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'IsVisible') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].is_visible', N'IsVisible', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'is_required') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'IsRequired') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].is_required', N'IsRequired', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'default_value') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'DefaultValue') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].default_value', N'DefaultValue', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'display_order') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'DisplayOrder') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].display_order', N'DisplayOrder', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'column_span') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'ColumnSpan') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].column_span', N'ColumnSpan', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'is_system') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'IsSystem') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].is_system', N'IsSystem', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'is_active') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'IsActive') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].is_active', N'IsActive', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'group_id') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'GroupId') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].group_id', N'GroupId', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'created_at') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'Created') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].created_at', N'Created', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'updated_at') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'Updated') IS NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Field].updated_at', N'Updated', N'COLUMN';
            END;

            -- Defensive guard: FieldKey hâlâ yoksa (snake_case rename başarısız olduysa veya
            -- tablo tamamen farklı bir schema'daysa), aşağıdaki UPDATE'lerin patlamasını
            -- engellemek için boş bir NVARCHAR(60) FieldKey kolonu ekle. Kullanıcı verisi
            -- bozulmaz, sadece UPDATE 0 satır etkiler.
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'FieldKey') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Field]
                ADD [FieldKey] NVARCHAR(60) NULL;
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'GroupId') IS NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'group_id') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Field]
                ADD [GroupId] INT NULL;
            END;

            -- Migration: eski kurulumlarda GroupId UNIQUEIDENTIFIER kalmis olabilir,
            -- INT'e cevir (FK uyumlu olsun). Once varsa FK'i drop et.
            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND EXISTS (
                   SELECT 1 FROM sys.columns
                   WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[Field]')
                     AND name = 'GroupId'
                     AND system_type_id = TYPE_ID('uniqueidentifier')
               )
            BEGIN
                IF EXISTS (
                    SELECT 1 FROM sys.foreign_keys
                    WHERE name = 'FK_Field_FieldGroup'
                      AND parent_object_id = OBJECT_ID(N'[{schemaForSql}].[Field]')
                )
                BEGIN
                    ALTER TABLE [{schemaForSql}].[Field]
                        DROP CONSTRAINT [FK_Field_FieldGroup];
                END;
                ALTER TABLE [{schemaForSql}].[Field] DROP COLUMN [GroupId];
                ALTER TABLE [{schemaForSql}].[Field] ADD [GroupId] INT NULL;
                ALTER TABLE [{schemaForSql}].[Field]
                    ADD CONSTRAINT [FK_Field_FieldGroup]
                    FOREIGN KEY ([GroupId]) REFERENCES [{schemaForSql}].[FieldGroup]([id]);
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'DataType') IS NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'data_type') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Field]
                ADD [DataType] NVARCHAR(30) NULL;
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'DataType') IS NOT NULL
            BEGIN
                EXEC(N'
                    UPDATE [{schemaForSql}].[Field]
                    SET [DataType] = CASE
                        WHEN [FieldKey] IN (N''sale_ok'', N''purchase_ok'', N''is_configurable'') THEN N''BOOLEAN''
                        WHEN [FieldKey] IN (N''list_price'', N''cost_price'', N''purchase_price'', N''weight'', N''volume'') THEN N''DECIMAL''
                        ELSE N''STRING''
                    END
                    WHERE [DataType] IS NULL OR LTRIM(RTRIM([DataType])) = N'''';
                ');
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'DefaultValue') IS NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'default_value') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Field]
                ADD [DefaultValue] NVARCHAR(500) NULL;
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'ColumnSpan') IS NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'column_span') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Field]
                ADD [ColumnSpan] INT NOT NULL CONSTRAINT [DF_Field_ColumnSpan] DEFAULT(1);
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'ColumnSpan') IS NOT NULL
            BEGIN
                EXEC(N'
                    UPDATE [{schemaForSql}].[Field]
                    SET [ColumnSpan] = 1
                    WHERE [ColumnSpan] IS NULL OR [ColumnSpan] < 1;
                ');
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'IsSystem') IS NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'is_system') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Field]
                ADD [IsSystem] BIT NOT NULL CONSTRAINT [DF_Field_IsSystem] DEFAULT(0);
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'IsActive') IS NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'is_active') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Field]
                ADD [IsActive] BIT NOT NULL CONSTRAINT [DF_Field_IsActive] DEFAULT(1);
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Field]', N'DataType') IS NOT NULL
            BEGIN
                EXEC(N'
                    ALTER TABLE [{schemaForSql}].[Field]
                    ALTER COLUMN [DataType] NVARCHAR(30) NOT NULL;
                ');
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1
                   FROM sys.foreign_keys
                   WHERE [name] = N'FK_Field_FieldGroup'
                     AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[Field]')
               )
            BEGIN
                ALTER TABLE [{schemaForSql}].[Field]
                ADD CONSTRAINT [FK_Field_FieldGroup]
                    FOREIGN KEY ([GroupId]) REFERENCES [{schemaForSql}].[FieldGroup]([id]);
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Field]', N'U') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1
                   FROM sys.indexes
                   WHERE [name] = N'UX_Field_FieldKey'
                     AND [object_id] = OBJECT_ID(N'[{schemaForSql}].[Field]')
               )
            BEGIN
                CREATE UNIQUE INDEX [UX_Field_FieldKey]
                    ON [{schemaForSql}].[Field]([FieldKey]);
            END;

            -- Eski schema migrate: field_definition_id UNIQUEIDENTIFIER kalmissa drop edip recreate
            IF OBJECT_ID(N'[{schemaForSql}].[MaterialCardFieldOption]', N'U') IS NOT NULL
               AND EXISTS (
                   SELECT 1 FROM sys.columns
                   WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[MaterialCardFieldOption]')
                     AND name = 'field_definition_id'
                     AND system_type_id = TYPE_ID('uniqueidentifier')
               )
            BEGIN
                IF EXISTS (
                    SELECT 1 FROM sys.foreign_keys
                    WHERE name = 'fk_material_card_field_options_field_definition_id'
                      AND parent_object_id = OBJECT_ID(N'[{schemaForSql}].[MaterialCardFieldOption]')
                )
                BEGIN
                    ALTER TABLE [{schemaForSql}].[MaterialCardFieldOption]
                        DROP CONSTRAINT [fk_material_card_field_options_field_definition_id];
                END;
                DROP TABLE [{schemaForSql}].[MaterialCardFieldOption];
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[MaterialCardFieldOption]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[MaterialCardFieldOption]
                (
                    [Id] INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_MaterialCardFieldOption] PRIMARY KEY,
                    [FieldDefinitionId] INT NOT NULL,
                    [OptionKey] NVARCHAR(60) NOT NULL,
                    [OptionLabel] NVARCHAR(160) NOT NULL,
                    [SortOrder] INT NOT NULL CONSTRAINT [DF_MaterialCardFieldOption_SortOrder] DEFAULT(0),
                    [IsActive] BIT NOT NULL CONSTRAINT [DF_MaterialCardFieldOption_IsActive] DEFAULT(1),
                    [Created] DATETIME NOT NULL CONSTRAINT [DF_MaterialCardFieldOption_Created] DEFAULT SYSUTCDATETIME(),
                    [Updated] DATETIME NULL,
                    CONSTRAINT [FK_MaterialCardFieldOption_Field]
                        FOREIGN KEY ([FieldDefinitionId]) REFERENCES [{schemaForSql}].[Field]([id])
                );

                CREATE UNIQUE INDEX [UX_MaterialCardFieldOption_FieldDefinition_OptionKey]
                    ON [{schemaForSql}].[MaterialCardFieldOption]([FieldDefinitionId], [OptionKey]);
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[ScreenLayoutDefinition]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[ScreenLayoutDefinition]
                (
                    [Id] INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_ScreenLayoutDefinition] PRIMARY KEY,
                    [ScreenCode] NVARCHAR(80) NOT NULL,
                    [LayoutJson] NVARCHAR(MAX) NOT NULL,
                    [Created] DATETIME NOT NULL CONSTRAINT [DF_ScreenLayoutDefinition_Created] DEFAULT SYSUTCDATETIME(),
                    [Updated] DATETIME NULL
                );

                CREATE UNIQUE INDEX [UX_ScreenLayoutDefinition_ScreenCode]
                    ON [{schemaForSql}].[ScreenLayoutDefinition]([ScreenCode]);
            END;

            -- Legacy rename: Feature -> ItemFeature (idempotent)
            IF OBJECT_ID(N'[{schemaForSql}].[ItemFeature]', N'U') IS NULL
               AND OBJECT_ID(N'[{schemaForSql}].[Feature]', N'U') IS NOT NULL
            BEGIN
                EXEC sp_rename N'[{schemaForSql}].[Feature]', N'ItemFeature';
            END;

            -- Eski schema (UnitId yok = legacy code/name lowercase) tespit edilirse drop et
            -- (kullanici dev'de drop+recreate'e razi). UnitId yerine CompanyId kontrolu — yeni kolon.
            IF OBJECT_ID(N'[{schemaForSql}].[ItemFeature]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[ItemFeature]', N'CompanyId') IS NULL
            BEGIN
                -- Once FeatureValue FK constraint'ini drop et (Feature/ItemFeature'a bagliydi)
                IF EXISTS (SELECT 1 FROM sys.foreign_keys WHERE [name] = N'fk_configuration_property_values_property_id')
                    ALTER TABLE [{schemaForSql}].[FeatureValue] DROP CONSTRAINT [fk_configuration_property_values_property_id];
                IF EXISTS (SELECT 1 FROM sys.foreign_keys WHERE [name] = N'FK_FeatureValue_ItemFeature')
                    ALTER TABLE [{schemaForSql}].[FeatureValue] DROP CONSTRAINT [FK_FeatureValue_ItemFeature];
                DROP TABLE [{schemaForSql}].[ItemFeature];
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[ItemFeature]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[ItemFeature]
                (
                    [Id]              INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_ItemFeature] PRIMARY KEY,
                    [CompanyId]       INT NOT NULL,
                    [Name]            NVARCHAR(120) NOT NULL,
                    [DataType]        NVARCHAR(30)  NOT NULL,
                    [UnitOfMeasure]   NVARCHAR(20)  NULL,
                    [VisibleInDesign] BIT NOT NULL CONSTRAINT [DF_ItemFeature_VisibleInDesign] DEFAULT(1),
                    [IsActive]        BIT NOT NULL CONSTRAINT [DF_ItemFeature_IsActive] DEFAULT(1),
                    [Created]         DATETIME NOT NULL,
                    [Updated]         DATETIME NOT NULL
                );

                EXEC(N'
                    CREATE INDEX [ix_ItemFeature_CompanyId_Name]
                        ON [{schemaForSql}].[ItemFeature]([CompanyId], [Name]);
                ');
            END;

            -- Backfill UnitOfMeasure / VisibleInDesign kolonlari (eski schema'da yoksa)
            IF OBJECT_ID(N'[{schemaForSql}].[ItemFeature]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[ItemFeature]', N'UnitOfMeasure') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[ItemFeature] ADD [UnitOfMeasure] NVARCHAR(20) NULL;
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[ItemFeature]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[ItemFeature]', N'VisibleInDesign') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[ItemFeature] ADD [VisibleInDesign] BIT NOT NULL CONSTRAINT [df_ItemFeature_VisibleInDesign] DEFAULT(1);
            END;

            -- Eski FeatureValue tablosu UNIQUEIDENTIFIER id'lerle yaratilmis ise drop et
            -- (yeni schema INT id ile uyumsuz; FK ItemFeatureMappings.FeatureValueId INT bekliyor)
            IF OBJECT_ID(N'[{schemaForSql}].[FeatureValue]', N'U') IS NOT NULL
               AND EXISTS (
                   SELECT 1 FROM sys.columns c
                   JOIN sys.types t ON c.system_type_id = t.system_type_id
                   WHERE c.object_id = OBJECT_ID(N'[{schemaForSql}].[FeatureValue]')
                     AND c.name = N'id'
                     AND t.name = N'uniqueidentifier'
               )
            BEGIN
                -- FK constraint'leri varsa drop
                IF EXISTS (SELECT 1 FROM sys.foreign_keys WHERE [name] = N'fk_configuration_property_values_property_id')
                    ALTER TABLE [{schemaForSql}].[FeatureValue] DROP CONSTRAINT [fk_configuration_property_values_property_id];
                IF EXISTS (SELECT 1 FROM sys.foreign_keys WHERE [name] = N'FK_FeatureValue_ItemFeature')
                    ALTER TABLE [{schemaForSql}].[FeatureValue] DROP CONSTRAINT [FK_FeatureValue_ItemFeature];
                IF EXISTS (SELECT 1 FROM sys.foreign_keys WHERE [name] = N'FK_ItemFeatureMappings_FeatureValue')
                    ALTER TABLE [{schemaForSql}].[ItemFeatureMappings] DROP CONSTRAINT [FK_ItemFeatureMappings_FeatureValue];
                DROP TABLE [{schemaForSql}].[FeatureValue];
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[FeatureValue]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[FeatureValue]
                (
                    [Id]          INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_FeatureValue] PRIMARY KEY,
                    [FeatureId]   INT NOT NULL,
                    [Code]        NVARCHAR(30) NOT NULL,
                    [Description] NVARCHAR(160) NOT NULL,
                    [Value]       NVARCHAR(160) NOT NULL,
                    [SortOrder]   INT NOT NULL CONSTRAINT [DF_FeatureValue_SortOrder] DEFAULT(0),
                    [IsActive]    BIT NOT NULL CONSTRAINT [DF_FeatureValue_IsActive] DEFAULT(1),
                    [Created]     DATETIME NOT NULL,
                    [Updated]     DATETIME NULL,
                    CONSTRAINT [FK_FeatureValue_ItemFeature]
                        FOREIGN KEY ([FeatureId]) REFERENCES [{schemaForSql}].[ItemFeature]([Id])
                );

                EXEC(N'
                    CREATE UNIQUE INDEX [UX_FeatureValue_FeatureId_Value]
                        ON [{schemaForSql}].[FeatureValue]([FeatureId], [Value]);
                ');

                EXEC(N'
                    CREATE UNIQUE INDEX [UX_FeatureValue_FeatureId_Code]
                        ON [{schemaForSql}].[FeatureValue]([FeatureId], [Code]);
                ');
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[FeatureValue]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[FeatureValue]', N'code') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[FeatureValue]
                ADD [code] NVARCHAR(30) NULL;
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[FeatureValue]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[FeatureValue]', N'description') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[FeatureValue]
                ADD [description] NVARCHAR(160) NULL;
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[FeatureValue]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[FeatureValue]', N'code') IS NOT NULL
            BEGIN
                EXEC(N'
                    UPDATE [{schemaForSql}].[FeatureValue]
                    SET [code] = LEFT(REPLACE(CONVERT(NVARCHAR(36), [id]), ''-'', ''''), 30)
                    WHERE [code] IS NULL OR LTRIM(RTRIM([code])) = N'''';
                ');
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[FeatureValue]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[FeatureValue]', N'description') IS NOT NULL
            BEGIN
                EXEC(N'
                    UPDATE [{schemaForSql}].[FeatureValue]
                    SET [description] = [value]
                    WHERE [description] IS NULL OR LTRIM(RTRIM([description])) = N'''';
                ');
            END;

            -- Legacy index yalnizca ESKI kolon adi (feature_id) hala mevcutsa olusturulur.
            -- Taze DB'de tablo dogrudan [FeatureId] ile yaratilir ve modern
            -- UX_FeatureValue_FeatureId_Code index'i yukarida kurulur; feature_id guard'i
            -- olmadan bu blok taze DB'de "Column name 'feature_id' does not exist" (1911)
            -- hatasiyla tum init'i durduruyordu (2026-07-10, per-company tam init'te bulundu).
            IF OBJECT_ID(N'[{schemaForSql}].[FeatureValue]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[FeatureValue]', N'feature_id') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[FeatureValue]', N'code') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1
                   FROM sys.indexes
                   WHERE [name] = N'ux_configuration_property_values_property_id_code'
                     AND [object_id] = OBJECT_ID(N'[{schemaForSql}].[FeatureValue]')
               )
            BEGIN
                EXEC(N'
                    CREATE UNIQUE INDEX [ux_configuration_property_values_property_id_code]
                        ON [{schemaForSql}].[FeatureValue]([feature_id], [code]);
                ');
