            IF OBJECT_ID(N'[{schemaForSql}].[ItemFeatureMappings]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[ItemFeatureMappings]', N'PrintDescriptionInDesign') IS NULL
            BEGIN
