                ADD [LocationCode] NVARCHAR(50) NULL;
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Location]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Location]', N'LocationName') IS NULL
            BEGIN
