            IF OBJECT_ID(N'[{schemaForSql}].[Location]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Location]', N'IsMachinePark') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Location]
                ADD [IsMachinePark] BIT NOT NULL CONSTRAINT [df_Locations_IsMachinePark] DEFAULT(0);
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Location]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Location]', N'IsStorageArea') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Location]
                ADD [IsStorageArea] BIT NOT NULL CONSTRAINT [df_Locations_IsStorageArea] DEFAULT(0);
            END;

            -- Eksi bakiye kontrolü: depo bazında izin (üç durumlu: NULL=devral, 1=izin, 0=engelle)
            IF OBJECT_ID(N'[{schemaForSql}].[Location]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Location]', N'AllowNegativeBalance') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[Location]
                ADD [AllowNegativeBalance] BIT NULL;
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Location]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Location]', N'LocationCode') IS NOT NULL
               AND EXISTS (
                   SELECT 1
                   FROM [{schemaForSql}].[Location]
                   WHERE [LocationCode] IS NULL OR LTRIM(RTRIM([LocationCode])) = N''
               )
            BEGIN
                EXEC(N'
                    UPDATE wl
                    SET [LocationCode] = N''LOC-'' + RIGHT(N''000000'' + CAST(wl.[Id] AS NVARCHAR(10)), 6)
                    FROM [{schemaForSql}].[Location] wl
                    WHERE wl.[LocationCode] IS NULL OR LTRIM(RTRIM(wl.[LocationCode])) = N'''';
                ');
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Location]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Location]', N'LocationCode') IS NOT NULL
               AND EXISTS (
                   SELECT 1
                   FROM sys.columns
                   WHERE [object_id] = OBJECT_ID(N'[{schemaForSql}].[Location]')
                     AND [name] = N'LocationCode'
                     AND [is_nullable] = 1
               )
            BEGIN
                EXEC(N'
                    ALTER TABLE [{schemaForSql}].[Location]
                    ALTER COLUMN [LocationCode] NVARCHAR(50) NOT NULL;
                ');
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[Location]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Location]', N'SortOrder') IS NOT NULL
               AND EXISTS (
                   SELECT 1
                   FROM sys.columns
                   WHERE [object_id] = OBJECT_ID(N'[{schemaForSql}].[Location]')
                     AND [name] = N'SortOrder'
