            IF OBJECT_ID(N'[{schemaForSql}].[Location]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.[Location]', N'LocationCode') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1
