               AND COL_LENGTH(N'{schemaLiteral}.[Unit]', N'Created') IS NULL
                EXEC sp_rename N'{schemaLiteral}.[Unit].[CreatedAt]', N'Created', N'COLUMN';
            IF OBJECT_ID(N'[{schemaForSql}].[Unit]', N'U') IS NOT NULL
