    private async Task EnsureNotesTablesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");

        var commandText = $"""
            -- Migration: notes.company_id UNIQUEIDENTIFIER → INT (drop & recreate)
            IF OBJECT_ID(N'[{s}].[notes]', N'U') IS NOT NULL
               AND EXISTS (
                   SELECT 1 FROM sys.columns
                   WHERE object_id = OBJECT_ID(N'[{s}].[notes]')
                     AND name = 'company_id'
                     AND system_type_id = TYPE_ID('uniqueidentifier')
               )
            BEGIN
                IF OBJECT_ID(N'[{s}].[note_shares]', N'U') IS NOT NULL DROP TABLE [{s}].[note_shares];
                IF OBJECT_ID(N'[{s}].[note_reminders]', N'U') IS NOT NULL DROP TABLE [{s}].[note_reminders];
                IF OBJECT_ID(N'[{s}].[note_folders]', N'U') IS NOT NULL DROP TABLE [{s}].[note_folders];
                DROP TABLE [{s}].[notes];
            END;

            IF OBJECT_ID(N'[{s}].[Note]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[Note]
                (
                    [Id]                 UNIQUEIDENTIFIER NOT NULL CONSTRAINT [PK_Note] PRIMARY KEY,
                    [CompanyId]          INT NOT NULL,
                    [UserId]             INT NOT NULL,
                    [Title]              NVARCHAR(200) NOT NULL,
                    [Content]            NVARCHAR(MAX) NULL,
                    [Created]            DATETIME NOT NULL,
                    [Updated]            DATETIME NULL,
                    [IsDeleted]          BIT NOT NULL CONSTRAINT [DF_Note_IsDeleted] DEFAULT(0),
                    [IsFullyEncrypted]   BIT NOT NULL CONSTRAINT [DF_Note_IsFullyEncrypted] DEFAULT(0),
                    [EncryptionHint]     NVARCHAR(300) NULL
                );
                CREATE INDEX [IX_Note_CompanyId_UserId] ON [{s}].[Note]([CompanyId], [UserId]);
            END;

            -- 2026-05-26: Notes ekosistemi PascalCase'e migrate ediliyor (CLAUDE.md uyum).
            -- Eksik UserId varsa ekle (legacy migration ortada cikmis durum icin defansif).
            IF OBJECT_ID(N'[{s}].[notes]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[notes]', N'UserId') IS NULL
               AND COL_LENGTH(N'[{s}].[notes]', N'user_id') IS NULL
            BEGIN
                ALTER TABLE [{s}].[notes] ADD [UserId] INT NULL;
            END;

            -- Idempotent: mevcut tabloya Mod 2 (E2E) kolonlari ekle (PascalCase veya legacy snake_case)
            IF OBJECT_ID(N'[{s}].[notes]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[notes]', N'is_fully_encrypted') IS NULL
               AND COL_LENGTH(N'[{s}].[notes]', N'IsFullyEncrypted') IS NULL
            BEGIN
                ALTER TABLE [{s}].[notes]
                ADD [IsFullyEncrypted] BIT NOT NULL
                    CONSTRAINT [df_notes_is_fully_encrypted] DEFAULT(0);
            END;

            IF OBJECT_ID(N'[{s}].[notes]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[notes]', N'encryption_hint') IS NULL
               AND COL_LENGTH(N'[{s}].[notes]', N'EncryptionHint') IS NULL
            BEGIN
                ALTER TABLE [{s}].[notes] ADD [EncryptionHint] NVARCHAR(300) NULL;
            END;

            -- 2026-07-02: Yarim kalmis PascalCase migration guvencesi. Notes ekosistemi PascalCase'e
            -- gecirilirken bazi DB'lerde rename (MigrateColumnRenamesAsync) uygulanmadan kalmis; repo
            -- bu kolonlari PascalCase sorguladigi icin "Invalid column name" veriyor. Tablo kesin var
            -- oldugu bu noktada snake kalan kolonlari veriyi koruyarak yeniden adlandiriyoruz. Idempotent:
            -- yalniz snake varsa + Pascal yoksa rename; zaten Pascal ise no-op. Index/DF constraint'ler
            -- sp_rename ile otomatik takip eder.
            IF COL_LENGTH(N'[{s}].[notes]', N'CompanyId') IS NULL AND COL_LENGTH(N'[{s}].[notes]', N'company_id') IS NOT NULL
                EXEC sp_rename N'[{s}].[notes].[company_id]', N'CompanyId', N'COLUMN';
            IF COL_LENGTH(N'[{s}].[notes]', N'UserId') IS NULL AND COL_LENGTH(N'[{s}].[notes]', N'user_id') IS NOT NULL
                EXEC sp_rename N'[{s}].[notes].[user_id]', N'UserId', N'COLUMN';
            IF COL_LENGTH(N'[{s}].[notes]', N'IsDeleted') IS NULL AND COL_LENGTH(N'[{s}].[notes]', N'is_deleted') IS NOT NULL
                EXEC sp_rename N'[{s}].[notes].[is_deleted]', N'IsDeleted', N'COLUMN';
            IF COL_LENGTH(N'[{s}].[notes]', N'IsFullyEncrypted') IS NULL AND COL_LENGTH(N'[{s}].[notes]', N'is_fully_encrypted') IS NOT NULL
                EXEC sp_rename N'[{s}].[notes].[is_fully_encrypted]', N'IsFullyEncrypted', N'COLUMN';
            IF COL_LENGTH(N'[{s}].[notes]', N'EncryptionHint') IS NULL AND COL_LENGTH(N'[{s}].[notes]', N'encryption_hint') IS NOT NULL
                EXEC sp_rename N'[{s}].[notes].[encryption_hint]', N'EncryptionHint', N'COLUMN';

            IF OBJECT_ID(N'[{s}].[NoteReminder]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[NoteReminder]
                (
                    [Id]       UNIQUEIDENTIFIER NOT NULL CONSTRAINT [PK_NoteReminder] PRIMARY KEY,
                    [NoteId]   UNIQUEIDENTIFIER NOT NULL,
                    [RemindAt] DATETIME NOT NULL,
                    [IsSent]   BIT NOT NULL CONSTRAINT [DF_NoteReminder_IsSent] DEFAULT(0),
                    [SentAt]   DATETIME NULL,
                    CONSTRAINT [FK_NoteReminder_Note]
                        FOREIGN KEY ([NoteId]) REFERENCES [{s}].[Note]([Id])
                );
                CREATE INDEX [IX_NoteReminder_NoteId] ON [{s}].[NoteReminder]([NoteId]);
                CREATE INDEX [IX_NoteReminder_Unsent] ON [{s}].[NoteReminder]([IsSent], [RemindAt]);
            END;

            IF OBJECT_ID(N'[{s}].[NoteShare]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[NoteShare]
                (
                    [Id]               UNIQUEIDENTIFIER NOT NULL CONSTRAINT [PK_NoteShare] PRIMARY KEY,
                    [NoteId]           UNIQUEIDENTIFIER NOT NULL,
                    [SharedWithUserId] INT NOT NULL,
                    [SharedAt]         DATETIME NOT NULL,
                    CONSTRAINT [FK_NoteShare_Note]
                        FOREIGN KEY ([NoteId]) REFERENCES [{s}].[Note]([Id]),
                    CONSTRAINT [UX_NoteShare_NoteId_UserId]
                        UNIQUE ([NoteId], [SharedWithUserId])
                );
                CREATE INDEX [IX_NoteShare_NoteId] ON [{s}].[NoteShare]([NoteId]);
                CREATE INDEX [IX_NoteShare_SharedWithUserId] ON [{s}].[NoteShare]([SharedWithUserId]);
            END;
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[NoteShare]') AND name = 'CanEdit')
                ALTER TABLE [{s}].[NoteShare] ADD [CanEdit] BIT NOT NULL CONSTRAINT [DF_NoteShare_CanEdit] DEFAULT 0;
            """;

        await using var cmd = connection.CreateCommand();
        cmd.CommandText = commandText;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    private async Task EnsureNoteExtensionsAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var sl = _schema.Replace("'", "''");

        var commandText = $"""
            IF OBJECT_ID(N'[{s}].[NoteFolder]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[NoteFolder]
                (
                    [Id]             UNIQUEIDENTIFIER NOT NULL CONSTRAINT [PK_NoteFolder] PRIMARY KEY,
                    [CompanyId]      INT NOT NULL,
                    [UserId]         INT NOT NULL,
                    [Name]           NVARCHAR(200) NOT NULL,
                    [ParentFolderId] UNIQUEIDENTIFIER NULL,
                    [Created]        DATETIME NOT NULL,
                    [IsDeleted]      BIT NOT NULL CONSTRAINT [DF_NoteFolder_IsDeleted] DEFAULT(0)
                );
                CREATE INDEX [IX_NoteFolder_CompanyId_UserId] ON [{s}].[NoteFolder]([CompanyId], [UserId]);
            END;

            IF OBJECT_ID(N'[{s}].[Note]', N'U') IS NOT NULL
            BEGIN
                IF COL_LENGTH(N'{sl}.Note', N'folder_id') IS NULL
                   AND COL_LENGTH(N'{sl}.Note', N'FolderId') IS NULL
                    ALTER TABLE [{s}].[Note] ADD [FolderId] UNIQUEIDENTIFIER NULL;
            END;

            IF OBJECT_ID(N'[{s}].[Note]', N'U') IS NOT NULL
            BEGIN
                IF COL_LENGTH(N'{sl}.Note', N'is_pinned') IS NULL
                   AND COL_LENGTH(N'{sl}.Note', N'IsPinned') IS NULL
                    ALTER TABLE [{s}].[Note] ADD [IsPinned] BIT NOT NULL CONSTRAINT [df_Note_is_pinned] DEFAULT(0);
            END;

            IF OBJECT_ID(N'[{s}].[NoteReminder]', N'U') IS NOT NULL
            BEGIN
                IF COL_LENGTH(N'{sl}.NoteReminder', N'recurrence_type') IS NULL
                    ALTER TABLE [{s}].[NoteReminder] ADD [recurrence_type] INT NOT NULL CONSTRAINT [df_NoteReminder_recurrence_type] DEFAULT(0);
                IF COL_LENGTH(N'{sl}.NoteReminder', N'recurrence_data') IS NULL
                    ALTER TABLE [{s}].[NoteReminder] ADD [recurrence_data] NVARCHAR(200) NULL;
                IF COL_LENGTH(N'{sl}.NoteReminder', N'delivery_channel') IS NULL
                    ALTER TABLE [{s}].[NoteReminder] ADD [delivery_channel] INT NOT NULL CONSTRAINT [df_NoteReminder_delivery_channel] DEFAULT(0);
                IF COL_LENGTH(N'{sl}.NoteReminder', N'target_user_id') IS NULL
                    ALTER TABLE [{s}].[NoteReminder] ADD [target_user_id] INT NULL;
            END;

            IF OBJECT_ID(N'[{s}].[NoteReminderTarget]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[NoteReminderTarget]
                (
                    [Id]         UNIQUEIDENTIFIER NOT NULL CONSTRAINT [PK_NoteReminderTarget] PRIMARY KEY,
                    [ReminderId] UNIQUEIDENTIFIER NOT NULL,
                    [UserId]     INT NOT NULL,
                    CONSTRAINT [FK_NoteReminderTarget_NoteReminder]
                        FOREIGN KEY ([ReminderId]) REFERENCES [{s}].[NoteReminder]([Id]) ON DELETE CASCADE,
                    CONSTRAINT [UX_NoteReminderTarget_ReminderId_UserId] UNIQUE ([ReminderId], [UserId])
                );
                CREATE INDEX [IX_NoteReminderTarget_ReminderId] ON [{s}].[NoteReminderTarget]([ReminderId]);
                CREATE INDEX [IX_NoteReminderTarget_UserId] ON [{s}].[NoteReminderTarget]([UserId]);
            END;

            IF OBJECT_ID(N'[{s}].[UserNotification]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[UserNotification]
                (
                    [Id]          INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_UserNotification] PRIMARY KEY,
                    [CompanyId]   INT NOT NULL,
                    [UserId]      INT NOT NULL,
                    [Created]     DATETIME NOT NULL CONSTRAINT [DF_UserNotification_Created] DEFAULT SYSUTCDATETIME(),
                    [Title]       NVARCHAR(300) NOT NULL,
                    [Body]        NVARCHAR(MAX) NULL,
                    [SourceType]  NVARCHAR(60) NULL,
                    [SourceId]    INT NULL,
                    [Link]        NVARCHAR(500) NULL,
                    [IsRead]      BIT NOT NULL CONSTRAINT [DF_UserNotification_IsRead] DEFAULT(0),
                    [ReadAt]      DATETIME NULL,
                    [CreatedById]   INT NULL,
                    [UpdatedById]   INT NULL,
                    [Updated]     DATETIME NULL
                );
                CREATE INDEX [IX_UserNotification_User_Unread]
                    ON [{s}].[UserNotification]([UserId], [IsRead], [Created] DESC);
            END;

            -- Migration: [CreatedBy]/[UpdatedBy] NVARCHAR -> [CreatedById]/[UpdatedById] INT
            IF OBJECT_ID(N'[{s}].[UserNotification]', N'U') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[UserNotification]') AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{s}].[UserNotification] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{s}].[UserNotification] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[UserNotification]') AND name = N'CreatedById')
                    ALTER TABLE [{s}].[UserNotification] ADD [CreatedById] INT NULL;
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[UserNotification]') AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{s}].[UserNotification] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{s}].[UserNotification] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[UserNotification]') AND name = N'UpdatedById')
                    ALTER TABLE [{s}].[UserNotification] ADD [UpdatedById] INT NULL;
            END

            IF OBJECT_ID(N'[{s}].[NoteAttachment]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[NoteAttachment]
                (
                    [Id]            UNIQUEIDENTIFIER NOT NULL CONSTRAINT [PK_NoteAttachment] PRIMARY KEY,
                    [NoteId]        UNIQUEIDENTIFIER NOT NULL,
                    [FileName]      NVARCHAR(255) NOT NULL,
                    [StoredName]    NVARCHAR(255) NOT NULL,
                    [ContentType]   NVARCHAR(100) NULL,
                    [FileSize]      BIGINT NOT NULL CONSTRAINT [DF_NoteAttachment_FileSize] DEFAULT(0),
                    [UploadedAt]    DATETIME NOT NULL,
                    [Description]   NVARCHAR(500) NULL,
                    [BinaryContent] VARBINARY(MAX) NULL,
                    CONSTRAINT [FK_NoteAttachment_Note]
                        FOREIGN KEY ([NoteId]) REFERENCES [{s}].[Note]([Id])
                );
                CREATE INDEX [IX_NoteAttachment_NoteId] ON [{s}].[NoteAttachment]([NoteId]);
            END;
            ELSE
            BEGIN
                -- Migration: description kolonu ekle
                IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[NoteAttachment]') AND name = N'description')
                BEGIN
                    ALTER TABLE [{s}].[NoteAttachment] ADD [description] NVARCHAR(500) NULL;
                END;

                -- Migration: binary_content kolonu — dosya icerigini DB'de saklar.
                IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[NoteAttachment]') AND name = N'binary_content')
                   AND NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[NoteAttachment]') AND name = N'BinaryContent')
                BEGIN
                    ALTER TABLE [{s}].[NoteAttachment] ADD [BinaryContent] VARBINARY(MAX) NULL;
                END;

                -- Migration: IsActive kolonu — soft-delete desteği
                IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[NoteAttachment]') AND name = N'IsActive')
                BEGIN
                    ALTER TABLE [{s}].[NoteAttachment] ADD [IsActive] BIT NOT NULL
                        CONSTRAINT [DF_NoteAttachment_IsActive] DEFAULT 1;
                END;
            END;

            -- Migration: Note.Tags kolonu — virgul ayirali etiketler (orn. "proje,toplanti").
            IF OBJECT_ID(N'[{s}].[Note]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[Note]', N'Tags') IS NULL
            BEGIN
                ALTER TABLE [{s}].[Note] ADD [Tags] NVARCHAR(500) NULL;
            END;

            -- Migration: Note — kayit baglantisi + gorunurluk kolonlari.
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='linked_entity_type')
                ALTER TABLE [{s}].[Note] ADD [linked_entity_type] NVARCHAR(50) NULL;
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='linked_entity_id')
                ALTER TABLE [{s}].[Note] ADD [linked_entity_id] INT NULL;
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='linked_entity_label')
                ALTER TABLE [{s}].[Note] ADD [linked_entity_label] NVARCHAR(200) NULL;
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='visibility')
                ALTER TABLE [{s}].[Note] ADD [visibility] TINYINT NOT NULL DEFAULT 0;
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='share_token')
                ALTER TABLE [{s}].[Note] ADD [share_token] NVARCHAR(40) NULL;
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='share_is_public')
                ALTER TABLE [{s}].[Note] ADD [share_is_public] BIT NOT NULL DEFAULT 0;
            IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='UX_Note_share_token')
                EXEC(N'CREATE UNIQUE INDEX [UX_Note_share_token] ON [{s}].[Note] ([share_token]) WHERE [share_token] IS NOT NULL');
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='share_include_attachments')
                ALTER TABLE [{s}].[Note] ADD [share_include_attachments] BIT NOT NULL CONSTRAINT [DF_Note_share_include_attachments] DEFAULT 0;
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='ocr_text')
                ALTER TABLE [{s}].[Note] ADD [ocr_text] NVARCHAR(MAX) NULL;
            -- Not listesi kart ozeti — icerik at-rest sifreli oldugundan kayit aninda uretilir (Protect'li saklanir)
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id=OBJECT_ID(N'[{s}].[Note]') AND name='snippet')
                ALTER TABLE [{s}].[Note] ADD [snippet] NVARCHAR(MAX) NULL;

            IF OBJECT_ID(N'[{s}].[CardGroup]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[CardGroup]
                (
                    [Id]          INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_CardGroup] PRIMARY KEY,
                    [CardType]    TINYINT NOT NULL,
                    [Level]       TINYINT NOT NULL,
                    [ParentId]    INT NULL,
                    [Code]        NVARCHAR(20) NOT NULL,
                    [Description] NVARCHAR(200) NULL
                );
                CREATE INDEX [IX_CardGroup_CardType_Level] ON [{s}].[CardGroup]([CardType], [Level]);
            END;

            IF OBJECT_ID(N'[{s}].[CardGroupMapping]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[CardGroupMapping]
                (
                    [Id]          INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_CardGroupMapping] PRIMARY KEY,
                    [EntityType]  TINYINT NOT NULL,
                    [EntityId]    NVARCHAR(50) NOT NULL,
                    [Level]       TINYINT NOT NULL,
                    [CardGroupId] INT NOT NULL,
                    CONSTRAINT [UX_CardGroupMapping_EntityType_EntityId_Level] UNIQUE ([EntityType], [EntityId], [Level])
                );
                CREATE INDEX [IX_CardGroupMapping_EntityType_EntityId]
                    ON [{s}].[CardGroupMapping]([EntityType], [EntityId]);
            END;
            """;

        await using var cmd = connection.CreateCommand();
        cmd.CommandText = commandText;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    private async Task EnsureBOMTablesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var commandText = $"""
            -- ── BOM migration: legacy code-based kolonlar → FK-based schema ──
            -- Eski: ParentMaterialCode, ConfigurationCode (string)
            -- Yeni: ItemId (FK Items), ConfigId (FK ItemConfiguration), ImageRotation (INT, derece)
            IF OBJECT_ID(N'[{s}].[BOM]', N'U') IS NOT NULL
            BEGIN
                -- 1) Yeni FK kolonlari ekle (nullable initially — backfill icin)
                IF COL_LENGTH(N'[{s}].[BOM]', N'ItemId') IS NULL
                    ALTER TABLE [{s}].[BOM] ADD [ItemId] INT NULL;

                IF COL_LENGTH(N'[{s}].[BOM]', N'ConfigId') IS NULL
                    ALTER TABLE [{s}].[BOM] ADD [ConfigId] INT NULL;

                IF COL_LENGTH(N'[{s}].[BOM]', N'ImageRotation') IS NULL
                    ALTER TABLE [{s}].[BOM] ADD [ImageRotation] INT NOT NULL CONSTRAINT [df_BOM_ImageRotation] DEFAULT(0);

                -- 2) Backfill: ParentMaterialCode → ItemId (Items.code lookup)
                -- EXEC ile sarmalayalim (deferred name resolution: yeni eklenen kolonlar)
                IF COL_LENGTH(N'[{s}].[BOM]', N'ParentMaterialCode') IS NOT NULL
                   AND OBJECT_ID(N'[{s}].[Items]', N'U') IS NOT NULL
                BEGIN
                    EXEC('
                        UPDATE b SET b.[ItemId] = i.[Id]
                        FROM [{s}].[BOM] b
                        INNER JOIN [{s}].[Items] i ON i.[Code] = b.[ParentMaterialCode]
                        WHERE b.[ItemId] IS NULL
                    ');
                END;

                -- 3) Backfill: ConfigurationCode → ConfigId (ItemConfiguration.RecordCode lookup)
                IF COL_LENGTH(N'[{s}].[BOM]', N'ConfigurationCode') IS NOT NULL
                   AND OBJECT_ID(N'[{s}].[ItemConfiguration]', N'U') IS NOT NULL
                BEGIN
                    EXEC('
                        UPDATE b SET b.[ConfigId] = cfg.[Id]
                        FROM [{s}].[BOM] b
                        INNER JOIN [{s}].[ItemConfiguration] cfg ON cfg.[RecordCode] = b.[ConfigurationCode]
                        WHERE b.[ConfigId] IS NULL AND b.[ConfigurationCode] IS NOT NULL
                    ');
                END;

                -- 4) Eski kolonlari drop et
                IF COL_LENGTH(N'[{s}].[BOM]', N'ParentMaterialCode') IS NOT NULL
                    ALTER TABLE [{s}].[BOM] DROP COLUMN [ParentMaterialCode];

                IF COL_LENGTH(N'[{s}].[BOM]', N'ConfigurationCode') IS NOT NULL
                    ALTER TABLE [{s}].[BOM] DROP COLUMN [ConfigurationCode];
            END;

            IF OBJECT_ID(N'[{s}].[BOM]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[BOM]
                (
                    [Id]                   INT            NOT NULL IDENTITY(1,1) PRIMARY KEY,
                    [ItemId]               INT            NOT NULL,
                    [ConfigId]             INT            NULL,
                    [RoutingId]            INT            NULL,   -- 2026-05-20: BOM-Routing baglantisi (header-level)
                    [Description]          NVARCHAR(500)  NULL,
                    [ImageData]            VARBINARY(MAX) NULL,
                    [ImageMimeType]        NVARCHAR(100)  NULL,
                    [ImageFitMode]         NVARCHAR(20)   NULL,
                    [ImageRotation]        INT            NOT NULL CONSTRAINT [df_BOM_ImageRotation] DEFAULT(0),
                    [IsActive]             BIT            NOT NULL CONSTRAINT [df_BOM_IsActive] DEFAULT 1,
                    [CreatedById]            INT  NULL,
                    [Created]              DATETIME      NOT NULL CONSTRAINT [df_BOM_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById]            INT  NULL,
                    [Updated]              DATETIME      NULL,
                    -- Legacy snake/camel kolonlar yeni install'da bile geri uyum icin tutulur
                    -- (eski raporlar/dis araclar bu kolon adlarini bekleyebilir).
                    [CreatedAt]            DATETIME      NOT NULL CONSTRAINT [df_product_trees_created_at]  DEFAULT GETDATE(),
                    [UpdatedAt]            DATETIME      NOT NULL CONSTRAINT [df_product_trees_updated_at]  DEFAULT GETDATE()
                );
            END;

            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'ImageFitMode')
                ALTER TABLE [{s}].[BOM] ADD [ImageFitMode] NVARCHAR(20) NULL;

            -- ── BOM-Routing baglantisi (2026-05-20) ──────────────────────────
            -- Header-level FK: bir recetenin hangi rota ile uretilecegi.
            -- NULL = is emri release sirasinda kullanici sececek (eski davranis).
            -- WorkOrder.RoutingId default'u olarak da kullanilir.
            -- FK ve INDEX olusumu DEFERRED PARSING (sp_executesql) icinde tutulur —
            -- ayni batch'te ALTER ADD'den hemen sonra RoutingId kolonu parser'a
            -- gozukmedigi icin "Invalid column name 'RoutingId'" hatasi olusuyordu.
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'RoutingId')
                ALTER TABLE [{s}].[BOM] ADD [RoutingId] INT NULL;

            -- FK + filtered index (sadece dolu olanlar icin — recete cogunlukla rotasiz baslar)
            EXEC sp_executesql N'
                IF NOT EXISTS (SELECT 1 FROM sys.foreign_keys
                               WHERE name = N''fk_BOM_Routing''
                                 AND parent_object_id = OBJECT_ID(N''[{s}].[BOM]''))
                   AND OBJECT_ID(N''[{s}].[Routing]'', N''U'') IS NOT NULL
                    ALTER TABLE [{s}].[BOM] WITH CHECK
                        ADD CONSTRAINT [fk_BOM_Routing]
                        FOREIGN KEY ([RoutingId]) REFERENCES [{s}].[Routing]([Id]);

                IF NOT EXISTS (SELECT 1 FROM sys.indexes
                               WHERE name = N''ix_BOM_RoutingId''
                                 AND object_id = OBJECT_ID(N''[{s}].[BOM]''))
                    CREATE INDEX [ix_BOM_RoutingId] ON [{s}].[BOM]([RoutingId]) WHERE [RoutingId] IS NOT NULL;
            ';

            -- ── BOM audit + IsActive migration (rapor 2026-05-17 madde 3.5/3.6) ──
            -- Mevcut tablolar icin idempotent ADD COLUMN; eski CreatedAt/UpdatedAt'tan
            -- backfill yapilir. Soft delete bayragi default 1 ile mevcut kayitlari
            -- aktif tutar.
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'IsActive')
                ALTER TABLE [{s}].[BOM] ADD [IsActive] BIT NOT NULL CONSTRAINT [df_BOM_IsActive] DEFAULT 1;

            -- CreatedById migration: NVARCHAR → INT
            IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'CreatedBy')
            BEGIN
                ALTER TABLE [{s}].[BOM] DROP COLUMN [CreatedBy];
                ALTER TABLE [{s}].[BOM] ADD [CreatedById] INT NULL;
            END
            ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'CreatedById')
                ALTER TABLE [{s}].[BOM] ADD [CreatedById] INT NULL;

            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'Created')
                ALTER TABLE [{s}].[BOM] ADD [Created] DATETIME NOT NULL CONSTRAINT [df_BOM_Created] DEFAULT SYSUTCDATETIME();

            -- UpdatedById migration: NVARCHAR → INT
            IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'UpdatedBy')
            BEGIN
                ALTER TABLE [{s}].[BOM] DROP COLUMN [UpdatedBy];
                ALTER TABLE [{s}].[BOM] ADD [UpdatedById] INT NULL;
            END
            ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'UpdatedById')
                ALTER TABLE [{s}].[BOM] ADD [UpdatedById] INT NULL;

            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'Updated')
                ALTER TABLE [{s}].[BOM] ADD [Updated] DATETIME NULL;

            -- Backfill: legacy CreatedAt/UpdatedAt → Created/Updated (idempotent — sadece
            -- yeni kolonlar yeni eklendiyse, default SYSUTCDATETIME yerine eski degeri kullan).
            -- EXEC sp_executesql ile deferred parsing (ALTER ile ayni batch'te yeni kolon
            -- adi parser tarafindan goruluyor olabilir ama guvenli yontem dynamic SQL).
            -- 2026-07-05 FIX: onceki surumde ''0001-01-01'' literal'i vardi — DATETIME
            -- alt siniri 1753 oldugundan tablo ILK SATIRINI alir almaz her acilis
            -- SqlException 242 (out-of-range) ile cokuyordu (satir yokken predicate
            -- hic degerlendirilmedigi icin bos DB'de gorunmuyordu). DATETIME kolonda
            -- 0001-01-01 zaten temsil edilemez; NULL kontrolu tek basina ayni amaci gorur.
            EXEC sp_executesql N'
                IF EXISTS (SELECT 1 FROM [{s}].[BOM] WHERE [Created] IS NULL)
                    UPDATE [{s}].[BOM] SET [Created] = [CreatedAt] WHERE [Created] IS NULL;
                UPDATE [{s}].[BOM] SET [Updated] = [UpdatedAt]
                    WHERE [Updated] IS NULL AND [UpdatedAt] IS NOT NULL AND [UpdatedAt] <> [CreatedAt];
            ';

            -- ── BOMLine migration ──
            IF OBJECT_ID(N'[{s}].[BOMLine]', N'U') IS NOT NULL
            BEGIN
                -- 1) Yeni FK kolonlari ekle
                IF COL_LENGTH(N'[{s}].[BOMLine]', N'ItemId') IS NULL
                    ALTER TABLE [{s}].[BOMLine] ADD [ItemId] INT NULL;

                IF COL_LENGTH(N'[{s}].[BOMLine]', N'ConfigId') IS NULL
                    ALTER TABLE [{s}].[BOMLine] ADD [ConfigId] INT NULL;

                -- 2) Backfill: ComponentMaterialCode → ItemId
                IF COL_LENGTH(N'[{s}].[BOMLine]', N'ComponentMaterialCode') IS NOT NULL
                   AND OBJECT_ID(N'[{s}].[Items]', N'U') IS NOT NULL
                BEGIN
                    EXEC('
                        UPDATE bl SET bl.[ItemId] = i.[Id]
                        FROM [{s}].[BOMLine] bl
                        INNER JOIN [{s}].[Items] i ON i.[Code] = bl.[ComponentMaterialCode]
                        WHERE bl.[ItemId] IS NULL
                    ');
                END;

                -- 3) Backfill: ComponentConfigCode → ConfigId
                IF COL_LENGTH(N'[{s}].[BOMLine]', N'ComponentConfigCode') IS NOT NULL
                   AND OBJECT_ID(N'[{s}].[ItemConfiguration]', N'U') IS NOT NULL
                BEGIN
                    EXEC('
                        UPDATE bl SET bl.[ConfigId] = cfg.[Id]
                        FROM [{s}].[BOMLine] bl
                        INNER JOIN [{s}].[ItemConfiguration] cfg ON cfg.[RecordCode] = bl.[ComponentConfigCode]
                        WHERE bl.[ConfigId] IS NULL AND bl.[ComponentConfigCode] IS NOT NULL
                    ');
                END;

                -- 4) Eski kolonlari drop et
                IF COL_LENGTH(N'[{s}].[BOMLine]', N'ComponentMaterialCode') IS NOT NULL
                    ALTER TABLE [{s}].[BOMLine] DROP COLUMN [ComponentMaterialCode];

                IF COL_LENGTH(N'[{s}].[BOMLine]', N'ComponentConfigCode') IS NOT NULL
                    ALTER TABLE [{s}].[BOMLine] DROP COLUMN [ComponentConfigCode];
            END;

            IF OBJECT_ID(N'[{s}].[BOMLine]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[BOMLine]
                (
                    [Id]                    INT             NOT NULL IDENTITY(1,1) PRIMARY KEY,
                    [BOMId]                 INT             NOT NULL,
                    [ItemId]                INT             NOT NULL,
                    [ConfigId]              INT             NULL,
                    [Quantity]              DECIMAL(18,4)   NOT NULL CONSTRAINT [df_product_tree_lines_qty]   DEFAULT 1,
                    [ScrapRatio]            DECIMAL(18,4)   NOT NULL CONSTRAINT [df_product_tree_lines_scrap] DEFAULT 0,
                    [LineGuid]              UNIQUEIDENTIFIER NOT NULL CONSTRAINT [df_product_tree_lines_guid] DEFAULT NEWID(),
                    [Note]                  NVARCHAR(1000)  NULL,
                    [CreatedById]             INT   NULL,
                    [Created]               DATETIME       NOT NULL CONSTRAINT [df_BOMLine_Created] DEFAULT SYSUTCDATETIME(),
                    CONSTRAINT [fk_product_tree_lines_trees]
                        FOREIGN KEY ([BOMId]) REFERENCES [{s}].[BOM]([Id]) ON DELETE CASCADE
                );
            END;

            -- BOMLine audit migration — idempotent, mevcut satirlar SYSUTCDATETIME default'unu alir.
            -- CreatedById migration: NVARCHAR → INT
            IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOMLine]') AND name = N'CreatedBy')
            BEGIN
                ALTER TABLE [{s}].[BOMLine] DROP COLUMN [CreatedBy];
                ALTER TABLE [{s}].[BOMLine] ADD [CreatedById] INT NULL;
            END
            ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOMLine]') AND name = N'CreatedById')
                ALTER TABLE [{s}].[BOMLine] ADD [CreatedById] INT NULL;

            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOMLine]') AND name = N'Created')
                ALTER TABLE [{s}].[BOMLine] ADD [Created] DATETIME NOT NULL CONSTRAINT [df_BOMLine_Created] DEFAULT SYSUTCDATETIME();

            -- 2026-07-05: satir aciklamasi — UI'da toplanan Not degeri artik persist ediliyor.
            IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[BOMLine]') AND name = N'Note')
                ALTER TABLE [{s}].[BOMLine] ADD [Note] NVARCHAR(1000) NULL;

            -- BOM.IsActive filtered index — soft-delete sonrasi sadece aktif kayitlari
            -- hizla cekmek icin (liste sayfasi WHERE [IsActive]=1 ile sorgulanir).
            IF NOT EXISTS (SELECT 1 FROM sys.indexes
                           WHERE object_id = OBJECT_ID(N'[{s}].[BOM]') AND name = N'ix_BOM_ItemId_Active')
                EXEC sp_executesql N'
                    CREATE INDEX [ix_BOM_ItemId_Active]
                        ON [{s}].[BOM]([ItemId], [ConfigId])
                        WHERE [IsActive] = 1;
                ';
            """;

        await using var cmd = connection.CreateCommand();
        cmd.CommandText = commandText;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

