                    [IsActive]     BIT              NOT NULL CONSTRAINT [DF_SalesQuoteAttachment_IsActive] DEFAULT(1)
                );
                CREATE INDEX [IX_SalesQuoteAttachment_Document] ON [{s}].[SalesQuoteAttachment]([DocumentId]);
