    private async Task EnsureDocumentTablesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var commandText = $"""
            IF OBJECT_ID(N'[{s}].[Document]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[Document]
                (
                    [Id]                INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_Document] PRIMARY KEY,
                    [CompanyId]         INT              NOT NULL CONSTRAINT [DF_Document_CompanyId] DEFAULT({DefaultCompanyId}),
                    [DocumentNumber]    NVARCHAR(15)     NOT NULL,
                    [DocumentTypeId]    INT              NULL,
                    [DocumentDate]      DATETIME     NOT NULL,
                    [ValidUntil]        DATETIME     NULL,
                    [ContactId]         INT              NULL,
                    [ContactAddress]    NVARCHAR(500)    NULL,
                    [SalesRepId]        INT              NULL,
                    [CurrencyId]        INT              NOT NULL CONSTRAINT [DF_Document_CurrencyId] DEFAULT(1),
                    [SubTotal]          DECIMAL(18,4)    NOT NULL DEFAULT(0),
                    [DiscountRate]      DECIMAL(5,2)     NOT NULL DEFAULT(0),
                    [DiscountAmount]    DECIMAL(18,4)    NOT NULL DEFAULT(0),
                    [TaxRate]           DECIMAL(5,2)     NOT NULL DEFAULT(20),
                    [TaxAmount]         DECIMAL(18,4)    NOT NULL DEFAULT(0),
                    [GrandTotal]        DECIMAL(18,4)    NOT NULL DEFAULT(0),
                    [PaymentTerms]      NVARCHAR(500)    NULL,
                    [DeliveryTerms]     NVARCHAR(500)    NULL,
                    [DeliveryAddress]   NVARCHAR(500)    NULL,
                    [Status]            NVARCHAR(20)     NOT NULL DEFAULT(N'Draft'),
                    [RevisionNo]        INT              NOT NULL DEFAULT(0),
                    [ParentDocumentId]  INT              NULL,
                    [Notes]             NVARCHAR(MAX)    NULL,
                    [CreatedById]       INT              NULL,
                    [Created]           DATETIME     NOT NULL,
                    [Updated]           DATETIME     NULL,
                    [IsActive]          BIT              NOT NULL DEFAULT(1)
                );
                CREATE UNIQUE INDEX [UX_Document_Number] ON [{s}].[Document]([DocumentNumber]);
                CREATE INDEX [IX_Document_Status] ON [{s}].[Document]([Status]);
                CREATE INDEX [IX_Document_Contact] ON [{s}].[Document]([ContactId]);
                CREATE INDEX [IX_Document_Company] ON [{s}].[Document]([CompanyId]);
            END;

            -- CreatedById migration: NVARCHAR veya renamed snake_case → INT
            IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[Document]') AND name = N'CreatedBy')
            BEGIN
                ALTER TABLE [{s}].[Document] DROP COLUMN [CreatedBy];
                ALTER TABLE [{s}].[Document] ADD [CreatedById] INT NULL;
            END
            ELSE IF EXISTS (SELECT 1 FROM sys.columns
                            WHERE object_id = OBJECT_ID(N'[{s}].[Document]')
                              AND name = N'CreatedById'
                              AND system_type_id = TYPE_ID(N'nvarchar'))
            BEGIN
                ALTER TABLE [{s}].[Document] DROP COLUMN [CreatedById];
                ALTER TABLE [{s}].[Document] ADD [CreatedById] INT NULL;
            END
            ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[Document]') AND name = N'CreatedById')
                ALTER TABLE [{s}].[Document] ADD [CreatedById] INT NULL;

            -- SalesRepId kolonu ekle (yoksa — eski DB icin)
            IF COL_LENGTH(N'[{s}].[Document]', N'SalesRepId') IS NULL
               AND COL_LENGTH(N'[{s}].[Document]', N'sales_rep_id') IS NULL
                ALTER TABLE [{s}].[Document] ADD [SalesRepId] INT NULL;

            -- DocumentTypeId FK kolonu (Phase 2 konsolidasyon). NULL satirlari
            -- BackfillDocumentTypeIdsAsync tarafindan (document_types seed'inden sonra) doldurulur.
            IF COL_LENGTH(N'[{s}].[Document]', N'DocumentTypeId') IS NULL
               AND COL_LENGTH(N'[{s}].[Document]', N'document_type_id') IS NULL
                ALTER TABLE [{s}].[Document] ADD [DocumentTypeId] INT NULL;

            -- RequesterPersonnelId — Ihtiyac Kaydi (alis_talebi) icin "Talep Eden" (Personnel.Id INT FK).
            -- Diger belge tiplerinde NULL kalir.
            IF COL_LENGTH(N'[{s}].[Document]', N'RequesterPersonnelId') IS NULL
                ALTER TABLE [{s}].[Document] ADD [RequesterPersonnelId] INT NULL;

            -- LocationId — Ihtiyac Kaydi baslik duzeyinde hedef depo (Location.Id INT FK).
            -- Satir bazinda LocationId yoksa bu deger kullanilir. Diger belge tiplerinde NULL kalir.
            IF COL_LENGTH(N'[{s}].[Document]', N'LocationId') IS NULL
                ALTER TABLE [{s}].[Document] ADD [LocationId] INT NULL;

            -- CompanyId FK kolonu — belgenin hangi sirkete ait oldugu.
            -- Mevcut kayitlar DefaultCompanyId (1) ile backfill edilir.
            IF COL_LENGTH(N'[{s}].[Document]', N'CompanyId') IS NULL
               AND COL_LENGTH(N'[{s}].[Document]', N'company_id') IS NULL
            BEGIN
                ALTER TABLE [{s}].[Document]
                ADD [CompanyId] INT NOT NULL
                    CONSTRAINT [df_document_CompanyId] DEFAULT({DefaultCompanyId});
                EXEC(N'UPDATE [{s}].[Document]
                       SET [CompanyId] = {DefaultCompanyId}
                       WHERE [CompanyId] = 0');
            END;
            IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'ix_document_company'
                           AND object_id = OBJECT_ID(N'[{s}].[Document]'))
               AND COL_LENGTH(N'[{s}].[Document]', N'CompanyId') IS NOT NULL
                CREATE INDEX [ix_document_company] ON [{s}].[Document]([CompanyId]);

            -- ── Currency string -> CurrencyId FK migration (2026-05-19) ──
            -- CLAUDE.md kuralı: ID-tabanli FK + CamelCase isimlendirme.
            -- Mevcut snake_case [currency] NVARCHAR kolonu drop edilir, yerine
            -- [CurrencyId] INT NOT NULL FK gelir. Backfill: currency code (TRY/USD/EUR)
            -- -> currencies.id eslemesi yapilir; eslesmeyen kayitlar TRY'ye (default 1)
            -- duser. currencies tablosu seed edilmis olmali (EnsureCurrenciesTableAsync
            -- daha once cagrildi).
            IF COL_LENGTH(N'[{s}].[Document]', N'CurrencyId') IS NULL
            BEGIN
                -- 1) Kolonu nullable ekle (backfill icin)
                ALTER TABLE [{s}].[Document] ADD [CurrencyId] INT NULL;
            END;

            -- 2) Backfill: currency NVARCHAR kolonu hala varsa, eski string degerden
            --    currencies.id'yi lookup et. EXEC sp_executesql ile deferred parsing
            --    (ALTER ile ayni batch'te kolonu kullanmaktan kacinmak icin).
            IF COL_LENGTH(N'[{s}].[Document]', N'currency') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[Document]', N'CurrencyId') IS NOT NULL
            BEGIN
                EXEC sp_executesql N'
                    UPDATE d SET d.[CurrencyId] = ISNULL(c.[id], 1)
                    FROM [{s}].[Document] d
                    LEFT JOIN [{s}].[Currency] c ON c.[code] = d.[currency]
                    WHERE d.[CurrencyId] IS NULL;
                ';
            END;

            -- 3) NULL kalanlari (currency kolonu hic yoksa, fresh row vs.) TRY'ye cek
            EXEC sp_executesql N'
                UPDATE [{s}].[Document] SET [CurrencyId] = 1 WHERE [CurrencyId] IS NULL;
            ';

            -- 4) NOT NULL + DEFAULT 1 constraint
            IF EXISTS (SELECT 1 FROM sys.columns
                       WHERE object_id = OBJECT_ID(N'[{s}].[Document]')
                         AND name = N'CurrencyId' AND is_nullable = 1)
            BEGIN
                ALTER TABLE [{s}].[Document] ALTER COLUMN [CurrencyId] INT NOT NULL;
            END;
            IF NOT EXISTS (SELECT 1 FROM sys.default_constraints
                           WHERE name = N'df_document_CurrencyId'
                             AND parent_object_id = OBJECT_ID(N'[{s}].[Document]'))
                ALTER TABLE [{s}].[Document] ADD CONSTRAINT [df_document_CurrencyId] DEFAULT(1) FOR [CurrencyId];

            -- 5) Foreign key constraint (currencies.id'ye)
            IF NOT EXISTS (SELECT 1 FROM sys.foreign_keys
                           WHERE name = N'fk_document_currency'
                             AND parent_object_id = OBJECT_ID(N'[{s}].[Document]'))
               AND OBJECT_ID(N'[{s}].[Currency]', N'U') IS NOT NULL
                ALTER TABLE [{s}].[Document] WITH CHECK
                    ADD CONSTRAINT [fk_document_currency]
                    FOREIGN KEY ([CurrencyId]) REFERENCES [{s}].[Currency]([Id]);

            -- 6) Index (currency-bazli filtreleme yapan rapor sorgulari icin)
            IF NOT EXISTS (SELECT 1 FROM sys.indexes
                           WHERE name = N'ix_document_currency'
                             AND object_id = OBJECT_ID(N'[{s}].[Document]'))
                CREATE INDEX [ix_document_currency] ON [{s}].[Document]([CurrencyId]);

            -- 7) Eski [currency] string kolonunu drop et — default constraint'i de
            --    once kaldirmak gerekir (eski df_document_currency vs. olabilir).
            IF COL_LENGTH(N'[{s}].[Document]', N'currency') IS NOT NULL
            BEGIN
                DECLARE @dfCur SYSNAME = (
                    SELECT TOP(1) dc.[name]
                    FROM sys.default_constraints dc
                    INNER JOIN sys.columns c ON c.default_object_id = dc.object_id
                    WHERE c.object_id = OBJECT_ID(N'[{s}].[Document]')
                      AND c.[name] = N'currency'
                );
                IF @dfCur IS NOT NULL
                    EXEC(N'ALTER TABLE [{s}].[Document] DROP CONSTRAINT [' + @dfCur + N'];');
                ALTER TABLE [{s}].[Document] DROP COLUMN [currency];
            END;

            -- Faz M: Teslim Tarihi + Teslim Suresi (gun) — Document (ust seviye) + DocumentLine (kalem)
            -- Sipariş için anlamlı (teklifte ValidUntil, siparişte DeliveryDate/DeliveryDays).
            -- DeliveryDays: sipariş tarihinden itibaren teslim süresi. UI'da çift yönlü sync:
            --   gün girilince tarih = DocumentDate + N gün, tarih girilince gün = DATEDIFF.
            -- Kalem bazlı override: DocumentLine.DeliveryDate / DeliveryDays NULL ise üst belge fallback.
            IF COL_LENGTH(N'[{s}].[Document]', N'DeliveryDate') IS NULL
                ALTER TABLE [{s}].[Document] ADD [DeliveryDate] DATETIME NULL;
            IF COL_LENGTH(N'[{s}].[Document]', N'DeliveryDays') IS NULL
                ALTER TABLE [{s}].[Document] ADD [DeliveryDays] INT NULL;

            -- Faz L: Entegrasyon tracking — belge ERP/dis sisteme gonderildi mi?
            -- IntegrationSentAt: son basarili entegrasyon zamani (NULL = hic gonderilmedi)
            -- IntegrationStatus: 'Sent' | 'Failed' | 'Pending' | NULL (hic denenmedi)
            -- LastIntegrationRunId: son IntegrationRun.Id referansi (audit linki)
            -- LastIntegrationId: hangi entegrasyon konfigi calisti (FK -> Integration.Id)
            IF COL_LENGTH(N'[{s}].[Document]', N'IntegrationSentAt') IS NULL
                ALTER TABLE [{s}].[Document] ADD [IntegrationSentAt] DATETIME NULL;
            IF COL_LENGTH(N'[{s}].[Document]', N'IntegrationStatus') IS NULL
                ALTER TABLE [{s}].[Document] ADD [IntegrationStatus] NVARCHAR(20) NULL;
            IF COL_LENGTH(N'[{s}].[Document]', N'LastIntegrationRunId') IS NULL
                ALTER TABLE [{s}].[Document] ADD [LastIntegrationRunId] BIGINT NULL;
            IF COL_LENGTH(N'[{s}].[Document]', N'LastIntegrationId') IS NULL
                ALTER TABLE [{s}].[Document] ADD [LastIntegrationId] INT NULL;
            -- Listede 'gonderilmemis' kayitlari hizli filtre icin
            IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'ix_document_integration_status'
                           AND object_id = OBJECT_ID(N'[{s}].[Document]'))
               AND COL_LENGTH(N'[{s}].[Document]', N'IntegrationStatus') IS NOT NULL
                CREATE INDEX [ix_document_integration_status]
                    ON [{s}].[Document]([IntegrationStatus]) INCLUDE ([IntegrationSentAt]);

            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NULL
            BEGIN
                -- Satir tablosu — material/unit/combination/location display degerleri
                -- tutulmaz; id FK'leri ile Item/Unit/ProductConfiguration/Location'dan okunur.
                CREATE TABLE [{s}].[DocumentLine]
                (
                    [Id]              INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_DocumentLine] PRIMARY KEY,
                    [DocumentId]      INT              NOT NULL,
                    [LineNo]          INT              NOT NULL DEFAULT(0),
                    [ItemId]          INT              NOT NULL,
                    [UnitId]          INT              NULL,
                    [Quantity]        DECIMAL(18,4)    NOT NULL DEFAULT(0),
                    -- Ana birime (Items.UnitId) cevrilmis miktar. Tum stok bakiye/hareket
                    -- hesaplari bunu kullanir; UnitId = girilen birim (gosterim). Yazimda
                    -- Quantity * ItemUnits.Multiplier ile hesaplanir (bkz. StockUnitSql).
                    [BaseQuantity]    DECIMAL(18,4)    NOT NULL DEFAULT(0),
                    -- Satış siparişi rezervasyonu (Faz 2): teslim edilen ana-birim miktar (açık = BaseQuantity - DeliveredQuantity)
                    [DeliveredQuantity] DECIMAL(18,4)  NOT NULL DEFAULT(0),
                    [UnitPrice]       DECIMAL(18,4)    NOT NULL DEFAULT(0),
                    [DiscountRate]    DECIMAL(5,2)     NOT NULL DEFAULT(0),
                    [LineTotal]       DECIMAL(18,4)    NOT NULL DEFAULT(0),
                    [CombinationId]   INT              NULL,
                    [LocationId]      INT              NULL,
                    [Notes]           NVARCHAR(500)    NULL,
                    [NotesPinned]     BIT              NOT NULL CONSTRAINT [DF_DocumentLine_NotesPinned] DEFAULT(0),
                    -- Revize zinciri: bu satir hangi DocumentLine'dan revize edildi?
                    -- NULL => orijinal satir. Zincir geriye takip edilerek kac
                    -- revize oldugu gorulebilir. Self-referencing FK.
                    [RevisedFromId]   INT              NULL,
                    [SourceLineId]    INT              NULL,
                    CONSTRAINT [FK_DocumentLine_Document] FOREIGN KEY ([DocumentId])
                        REFERENCES [{s}].[Document]([id])
                );
                CREATE INDEX [IX_DocumentLine_DocumentId] ON [{s}].[DocumentLine]([DocumentId]);
                -- Revize index dinamik EXEC — SQL Server batch derleme sirasinda
                -- mevcut (eski) sema uzerinde kolon dogrulama yapiyor ve IF blogu
                -- icinde de olsa "kolon yok" hatasi veriyor. Deferred parsing icin
                -- EXEC(N'...') kullaniyoruz; runtime'da kolon olustugundan calisir.
                EXEC(N'CREATE INDEX [IX_DocumentLine_RevisedFromId] ON [{s}].[DocumentLine]([RevisedFromId]) WHERE [RevisedFromId] IS NOT NULL;');
            END;

            -- Faz M: Kalem bazlı teslim tarihi + teslim süresi (gün).
            -- NULL ise üst Document.DeliveryDate / DeliveryDays fallback olur (engine veya UI).
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'DeliveryDate') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [DeliveryDate] DATETIME NULL;
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'DeliveryDays') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [DeliveryDays] INT NULL;

            -- 2026-05-23: Talep karsilama (Fulfillment) takibi — Ihtiyac Kaydi satirinin
            -- ne kadari stoktan transfer ile, ne kadari satin alma ile karsilandi?
            -- Bu kolonlar SADECE talep satirlarinda (alis_talebi) anlam tasir; diger
            -- belgelerde 0 kalir. FulfillmentStatus: 0=Pending, 1=Partial, 2=Full, 3=Cancelled.
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'FulfilledFromStock') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [FulfilledFromStock] DECIMAL(18,4) NOT NULL
                    CONSTRAINT [DF_DocumentLine_FulfilledFromStock] DEFAULT(0);
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'FulfilledByPurchase') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [FulfilledByPurchase] DECIMAL(18,4) NOT NULL
                    CONSTRAINT [DF_DocumentLine_FulfilledByPurchase] DEFAULT(0);
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'FulfillmentStatus') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [FulfillmentStatus] TINYINT NOT NULL
                    CONSTRAINT [DF_DocumentLine_FulfillmentStatus] DEFAULT(0);
            -- Satış siparişi rezervasyonu (Faz 2): teslim edilen ana-birim miktar
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'DeliveredQuantity') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [DeliveredQuantity] DECIMAL(18,4) NOT NULL
                    CONSTRAINT [DF_DocumentLine_DeliveredQuantity] DEFAULT(0);

            -- 2026-07-02: Stok hareketi konsolidasyonu — DocumentLine artik fiilen stok
            -- hareketi yaratan satirlari da tasir (StockMovementType enum reuse: 1=Issue,
            -- 2=Receipt, 3=Transfer, 4=Adjust; NULL = ticari/stok-etkilemez satir).
            -- FromLocationId: transfer/sarf kaynagi (mevcut LocationId hedef/tekil lokasyon
            -- olarak kalir). UnitCost/LotNo: stock_doc_line'dan tasinan deger/parti takibi.
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'MovementType') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [MovementType] TINYINT NULL;
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'FromLocationId') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [FromLocationId] INT NULL;
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'UnitCost') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [UnitCost] DECIMAL(18,4) NULL;
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'LotNo') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [LotNo] NVARCHAR(50) NULL;

            -- 2026-07-06: Baz-birim normalizasyonu — BaseQuantity kolonu + tek seferlik backfill.
            -- Farkli olcu birimleriyle (adet/metre/koli) girilen stok hareketleri baz birimde
            -- tutarli toplansin. Girilen birim = ana birim olan mevcut satirlarda carpan 1 →
            -- BaseQuantity = Quantity (davranis degismez). Backfill deferred EXEC: yeni kolon
            -- ayni batch'te parse-time dogrulanamaz (SqlException 207 — BridgeMsgId dersi).
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'BaseQuantity') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocumentLine] ADD [BaseQuantity] DECIMAL(18,4) NOT NULL
                    CONSTRAINT [DF_DocumentLine_BaseQuantity] DEFAULT(0);
                EXEC(N'UPDATE dl SET dl.[BaseQuantity] = dl.[Quantity] * ISNULL((
                        SELECT TOP 1 CASE WHEN dl.[UnitId] IS NULL OR i.[UnitId] = dl.[UnitId] THEN 1
                                          ELSE ISNULL(iu.[Multiplier], 1) END
                        FROM [{s}].[Items] i
                        LEFT JOIN [{s}].[ItemUnits] iu ON iu.[ItemId] = i.[Id] AND iu.[UnitId] = dl.[UnitId]
                        WHERE i.[Id] = dl.[ItemId]), 1)
                     FROM [{s}].[DocumentLine] dl;');
            END

            -- Stok bakiyesi sorgusu (StockBalances) ItemId+LocationId+MovementType bazinda
            -- filtreli calisir — veri boskken index olusturmak ucuz, sonradan pahali.
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'IX_DocumentLine_Stock'
                               AND object_id = OBJECT_ID(N'[{s}].[DocumentLine]'))
                CREATE INDEX [IX_DocumentLine_Stock]
                    ON [{s}].[DocumentLine]([ItemId], [LocationId], [MovementType])
                    INCLUDE ([Quantity], [FromLocationId]);

            -- 2026-07-09: Lot takibi Faz 1 — Lot ana tablosu (ID tabanli eslestirme kurali:
            -- LotNo string yalniz display, iliskiler LotId uzerinden). Items.TrackingType='Lot'
            -- olan stoklarda ambar hareketleri lot zorunlu tutar; DocumentLine.LotNo denormalize
            -- display kopyasi olarak dolmaya devam eder (ekstre/legacy sorgular degismez).
            -- Bu blok BaseQuantity ALTER'indan SONRA durmali: IX_DocumentLine_Lot INCLUDE'u
            -- BaseQuantity'ye referans verir (taze DB'de kolon ancak yukarida olusur).
            IF OBJECT_ID(N'[{s}].[Lot]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[Lot]
                (
                    [Id]            INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_Lot] PRIMARY KEY,
                    [ItemId]        INT NOT NULL,
                    [LotNo]         NVARCHAR(50) NOT NULL,
                    [ExpiryDate]    DATETIME NULL,
                    [SupplierLotNo] NVARCHAR(50) NULL,
                    [Notes]         NVARCHAR(1000) NULL,
                    [IsActive]      BIT NOT NULL CONSTRAINT [DF_Lot_IsActive] DEFAULT(1),
                    [CreatedById]   INT NULL,
                    [Created]       DATETIME NOT NULL CONSTRAINT [DF_Lot_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById]   INT NULL,
                    [Updated]       DATETIME NULL,
                    CONSTRAINT [FK_Lot_Items] FOREIGN KEY ([ItemId]) REFERENCES [{s}].[Items]([Id])
                );
                CREATE UNIQUE INDEX [UX_Lot_Item_LotNo] ON [{s}].[Lot]([ItemId], [LotNo]);
            END;

            -- FK/INDEX ifadeleri EXEC ile ayrı batch'te: aynı batch'te ALTER ile eklenen
            -- LotId kolonuna sonraki ifadeler compile-time referans veremez (SqlException 207).
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocumentLine]', N'LotId') IS NULL
                ALTER TABLE [{s}].[DocumentLine] ADD [LotId] INT NULL;
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.foreign_keys WHERE name = N'FK_DocumentLine_Lot'
                               AND parent_object_id = OBJECT_ID(N'[{s}].[DocumentLine]'))
                EXEC(N'ALTER TABLE [{s}].[DocumentLine] WITH CHECK
                    ADD CONSTRAINT [FK_DocumentLine_Lot] FOREIGN KEY ([LotId]) REFERENCES [{s}].[Lot]([Id]);');
            -- Index FİLTRESİZ: filtered index (WHERE LotId IS NOT NULL) tabloya yazan tüm
            -- oturumlarda QUOTED_IDENTIFIER ON zorunluluğu getirir — sqlcmd/harici araçların
            -- DocumentLine INSERT'lerini kırar. Filtreli oluşmuş eski sürüm varsa düzelt.
            IF EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'IX_DocumentLine_Lot'
                       AND object_id = OBJECT_ID(N'[{s}].[DocumentLine]') AND has_filter = 1)
                DROP INDEX [IX_DocumentLine_Lot] ON [{s}].[DocumentLine];
            IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'IX_DocumentLine_Lot'
                               AND object_id = OBJECT_ID(N'[{s}].[DocumentLine]'))
                EXEC(N'CREATE INDEX [IX_DocumentLine_Lot]
                    ON [{s}].[DocumentLine]([LotId])
                    INCLUDE ([ItemId], [LocationId], [FromLocationId], [MovementType], [BaseQuantity]);');

            -- 2026-07-10: Seri takibi Faz 2 — ItemSerial (seri ana kaydı) + DocumentLineSerial
            -- (hareket satırı ↔ seri bağı; miktar N ⇒ N bağ satırı). Seri durumu ItemSerial.Status:
            -- 1=InStock (stokta), 2=Issued (çıktı), 3=Blocked, 4=Reserved (sipariş için rezerve, 2026-07-11).
            -- Girişte InStock yaratılır/iade girişinde Issued→InStock döner; çıkışta InStock şart +
            -- Issued'a çekilir; transferde durum değişmez (yalnız bağ). Sipariş seri rezervasyonu:
            -- InStock→Reserved (kaydet), Reserved→Issued (irsaliye), Reserved→InStock (iptal/sil).
            -- DocumentLine delete+reinsert deseninde bağlar ON DELETE CASCADE ile temizlenir,
            -- durum geçişleri SqlStockDocRepository / DocumentService'de yönetilir.
            IF OBJECT_ID(N'[{s}].[ItemSerial]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[ItemSerial]
                (
                    [Id]          INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_ItemSerial] PRIMARY KEY,
                    [ItemId]      INT NOT NULL,
                    [SerialNo]    NVARCHAR(100) NOT NULL,
                    [LotId]       INT NULL,
                    [Status]      TINYINT NOT NULL CONSTRAINT [DF_ItemSerial_Status] DEFAULT(1),
                    [IsActive]    BIT NOT NULL CONSTRAINT [DF_ItemSerial_IsActive] DEFAULT(1),
                    [CreatedById] INT NULL,
                    [Created]     DATETIME NOT NULL CONSTRAINT [DF_ItemSerial_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById] INT NULL,
                    [Updated]     DATETIME NULL,
                    CONSTRAINT [FK_ItemSerial_Items] FOREIGN KEY ([ItemId]) REFERENCES [{s}].[Items]([Id]),
                    CONSTRAINT [FK_ItemSerial_Lot] FOREIGN KEY ([LotId]) REFERENCES [{s}].[Lot]([Id]),
                    CONSTRAINT [CK_ItemSerial_Status] CHECK ([Status] BETWEEN 1 AND 4)
                );
                CREATE UNIQUE INDEX [UX_ItemSerial_Item_SerialNo] ON [{s}].[ItemSerial]([ItemId], [SerialNo]);
                CREATE INDEX [IX_ItemSerial_Item_Status] ON [{s}].[ItemSerial]([ItemId], [Status]);
            END;

            -- 2026-07-11: Reserved (4) durumu için CHECK genişletme (mevcut DB'ler; 1-3 → 1-4).
            IF EXISTS (SELECT 1 FROM sys.check_constraints WHERE name = N'CK_ItemSerial_Status'
                       AND parent_object_id = OBJECT_ID(N'[{s}].[ItemSerial]')
                       AND definition LIKE N'%3%' AND definition NOT LIKE N'%4%')
            BEGIN
                ALTER TABLE [{s}].[ItemSerial] DROP CONSTRAINT [CK_ItemSerial_Status];
                ALTER TABLE [{s}].[ItemSerial] ADD CONSTRAINT [CK_ItemSerial_Status] CHECK ([Status] BETWEEN 1 AND 4);
            END;

            -- 2026-07-11: Sipariş seri rezervasyonu — hangi belge (sipariş) rezerve etti.
            -- Satır cascade-delete edilse bile rezervasyon bu kolonla belge bazında serbest
            -- bırakılabilir (orphan Reserved kalmaz). NULL = rezerve değil.
            IF COL_LENGTH(N'[{s}].[ItemSerial]', N'ReservedForDocumentId') IS NULL
                ALTER TABLE [{s}].[ItemSerial] ADD [ReservedForDocumentId] INT NULL;
            -- Filtered index EXEC ile ertelenmiş derlenir: ALTER ile aynı batch'te yeni kolona
            -- doğrudan referans, kolonu olmayan DB'de compile-time 207 (Invalid column name)
            -- üretir (QI dersi — bkz. Lot/Seri Faz 2 EXEC-batch notu).
            IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'IX_ItemSerial_ReservedForDocument'
                           AND object_id = OBJECT_ID(N'[{s}].[ItemSerial]'))
               AND COL_LENGTH(N'[{s}].[ItemSerial]', N'ReservedForDocumentId') IS NOT NULL
                EXEC(N'CREATE INDEX [IX_ItemSerial_ReservedForDocument] ON [{s}].[ItemSerial]([ReservedForDocumentId])
                    WHERE [ReservedForDocumentId] IS NOT NULL;');

            IF OBJECT_ID(N'[{s}].[DocumentLineSerial]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[DocumentLineSerial]
                (
                    [Id]             INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_DocumentLineSerial] PRIMARY KEY,
                    [DocumentLineId] INT NOT NULL,
                    [SerialId]       INT NOT NULL,
                    [Created]        DATETIME NOT NULL CONSTRAINT [DF_DocumentLineSerial_Created] DEFAULT SYSUTCDATETIME(),
                    CONSTRAINT [FK_DocumentLineSerial_DocumentLine] FOREIGN KEY ([DocumentLineId])
                        REFERENCES [{s}].[DocumentLine]([Id]) ON DELETE CASCADE,
                    CONSTRAINT [FK_DocumentLineSerial_ItemSerial] FOREIGN KEY ([SerialId])
                        REFERENCES [{s}].[ItemSerial]([Id])
                );
                CREATE UNIQUE INDEX [UX_DocumentLineSerial_Line_Serial]
                    ON [{s}].[DocumentLineSerial]([DocumentLineId], [SerialId]);
                CREATE INDEX [IX_DocumentLineSerial_Serial] ON [{s}].[DocumentLineSerial]([SerialId]);
            END;

            -- 2026-05-23: DocumentLineFulfillment — bag tablosu.
            -- Talep satiri (RequestLineId) → karsilama satiri (RefDocLineId, StockDocLine.Id
            -- veya DocumentLine.Id) eslemesi. Bir talep satiri birden cok karsilama satirina
            -- baglanabilir (orn. 100 adet ihtiyac → 30 transfer + 70 satin alma teklif satiri).
            IF OBJECT_ID(N'[{s}].[DocumentLineFulfillment]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[DocumentLineFulfillment]
                (
                    [Id]               INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_DocumentLineFulfillment] PRIMARY KEY,
                    [RequestLineId]    INT           NOT NULL CONSTRAINT [FK_DLF_RequestLine] REFERENCES [{s}].[DocumentLine]([Id]),
                    -- 1=Transfer (StockDocLine), 2=PurchaseQuote (DocumentLine), 3=PurchaseOrder (DocumentLine)
                    [FulfillmentType]  TINYINT       NOT NULL,
                    [RefDocLineId]     INT           NOT NULL,
                    [Quantity]         DECIMAL(18,4) NOT NULL,
                    [Notes]            NVARCHAR(500) NULL,
                    [IsActive]         BIT           NOT NULL CONSTRAINT [DF_DLF_IsActive] DEFAULT(1),
                    [CreatedById]        INT NULL,
                    [Created]          DATETIME     NOT NULL CONSTRAINT [DF_DLF_Created] DEFAULT(SYSUTCDATETIME()),
                    [UpdatedById]        INT NULL,
                    [Updated]          DATETIME     NULL
                );
                CREATE INDEX [IX_DLF_RequestLineId] ON [{s}].[DocumentLineFulfillment]([RequestLineId]) WHERE [IsActive] = 1;
                CREATE INDEX [IX_DLF_RefDocLine] ON [{s}].[DocumentLineFulfillment]([FulfillmentType], [RefDocLineId]) WHERE [IsActive] = 1;
            END;

            -- Migration: [CreatedBy]/[UpdatedBy] NVARCHAR -> [CreatedById]/[UpdatedById] INT
            IF OBJECT_ID(N'[{s}].[DocumentLineFulfillment]', N'U') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[DocumentLineFulfillment]') AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{s}].[DocumentLineFulfillment] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{s}].[DocumentLineFulfillment] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[DocumentLineFulfillment]') AND name = N'CreatedById')
                    ALTER TABLE [{s}].[DocumentLineFulfillment] ADD [CreatedById] INT NULL;
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[DocumentLineFulfillment]') AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{s}].[DocumentLineFulfillment] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{s}].[DocumentLineFulfillment] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[DocumentLineFulfillment]') AND name = N'UpdatedById')
                    ALTER TABLE [{s}].[DocumentLineFulfillment] ADD [UpdatedById] INT NULL;
            END

            -- 2026-07-01: FK_DocumentLine_Document → ON DELETE CASCADE
            -- Document silinince ilgili DocumentLine satirlari da otomatik silinir.
            -- Idempotent: zaten CASCADE ise no-op; yoksa olustur; var ama NO_ACTION ise yeniden yap.
            IF EXISTS (
                SELECT 1 FROM sys.foreign_keys
                WHERE name = N'FK_DocumentLine_Document'
                  AND parent_object_id = OBJECT_ID(N'[{s}].[DocumentLine]')
                  AND delete_referential_action = 0
            )
            BEGIN
                ALTER TABLE [{s}].[DocumentLine] DROP CONSTRAINT [FK_DocumentLine_Document];
                ALTER TABLE [{s}].[DocumentLine] ADD CONSTRAINT [FK_DocumentLine_Document]
                    FOREIGN KEY ([DocumentId]) REFERENCES [{s}].[Document]([id])
                    ON DELETE CASCADE;
            END
            ELSE IF NOT EXISTS (
                SELECT 1 FROM sys.foreign_keys
                WHERE name = N'FK_DocumentLine_Document'
                  AND parent_object_id = OBJECT_ID(N'[{s}].[DocumentLine]')
            )
            BEGIN
                IF OBJECT_ID(N'[{s}].[DocumentLine]', N'U') IS NOT NULL
                    ALTER TABLE [{s}].[DocumentLine] ADD CONSTRAINT [FK_DocumentLine_Document]
                        FOREIGN KEY ([DocumentId]) REFERENCES [{s}].[Document]([id])
                        ON DELETE CASCADE;
            END

            -- 2026-07-01: FK_DLF_RequestLine → ON DELETE CASCADE
            -- DocumentLine silinince ilgili DocumentLineFulfillment satirlari da otomatik silinir.
            IF EXISTS (
                SELECT 1 FROM sys.foreign_keys
                WHERE name = N'FK_DLF_RequestLine'
                  AND parent_object_id = OBJECT_ID(N'[{s}].[DocumentLineFulfillment]')
                  AND delete_referential_action = 0
            )
            BEGIN
                ALTER TABLE [{s}].[DocumentLineFulfillment] DROP CONSTRAINT [FK_DLF_RequestLine];
                ALTER TABLE [{s}].[DocumentLineFulfillment] ADD CONSTRAINT [FK_DLF_RequestLine]
                    FOREIGN KEY ([RequestLineId]) REFERENCES [{s}].[DocumentLine]([Id])
                    ON DELETE CASCADE;
            END
            ELSE IF NOT EXISTS (
                SELECT 1 FROM sys.foreign_keys
                WHERE name = N'FK_DLF_RequestLine'
                  AND parent_object_id = OBJECT_ID(N'[{s}].[DocumentLineFulfillment]')
            )
            BEGIN
                IF OBJECT_ID(N'[{s}].[DocumentLineFulfillment]', N'U') IS NOT NULL
                    ALTER TABLE [{s}].[DocumentLineFulfillment] ADD CONSTRAINT [FK_DLF_RequestLine]
                        FOREIGN KEY ([RequestLineId]) REFERENCES [{s}].[DocumentLine]([Id])
                        ON DELETE CASCADE;
            END
            """;

        await using var cmd = connection.CreateCommand();
        cmd.CommandText = commandText;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    // Faz 2 — Document.contact_name kolonunu kaldirma migration'i.
    // Once contact_id NULL olan satirlarda contact_name = Contact.AccountTitle
    // eslesmesi ile ID backfill edilir; sonra kolon drop edilir.
    //
    // NOT: SQL Server batch-level compile sirasinda kolon referanslari binding
    // edilir — IF ile sarmak yeterli degil. Bu yuzden backfill ve drop komutlari
    // EXEC ile dinamik calistirilir (deferred compile).
    // Idempotent: kolon yoksa no-op.
    private async Task MigrateDocumentContactNameDropAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s  = _schema.Replace("]", "]]");
        var sl = _schema.Replace("'", "''");
        var commandText = $"""
            IF OBJECT_ID(N'[{s}].[Document]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{sl}.[Document]', N'contact_name') IS NOT NULL
            BEGIN
                -- Backfill: contact_id NULL olan kayitlarda contact_name -> Contact eslesmesi
                EXEC(N'
                    UPDATE d
                        SET d.[ContactId] = c.[Id]
                    FROM [{s}].[Document] d
                    JOIN [{s}].[Contact] c
                      ON c.[AccountTitle] COLLATE Turkish_CI_AI = d.[contact_name] COLLATE Turkish_CI_AI
                     AND c.[IsActive] = 1
                    WHERE d.[ContactId] IS NULL
                      AND d.[contact_name] IS NOT NULL
                      AND LEN(LTRIM(RTRIM(d.[contact_name]))) > 0;
                ');

                -- Kolon kaldir — artik Contact join ile okunuyor
                EXEC(N'ALTER TABLE [{s}].[Document] DROP COLUMN [contact_name];');
            END;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = commandText;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    // ── User Settings ─────────────────────────────────────────────────────────

    private async Task EnsureUserSettingsTableAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var commandText = $"""
            IF OBJECT_ID(N'[{s}].[UserSettings]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[UserSettings]
                (
                    [Id]           UNIQUEIDENTIFIER NOT NULL PRIMARY KEY,
                    [UserId]       UNIQUEIDENTIFIER NOT NULL,
                    [SettingKey]   NVARCHAR(200)    NOT NULL,
                    [SettingValue] NVARCHAR(MAX)    NULL,
                    [Updated]      DATETIME     NULL
                );
                CREATE UNIQUE INDEX [UX_UserSettings_UserId_SettingKey]
                    ON [{s}].[UserSettings]([UserId], [SettingKey]);
            END;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = commandText;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    // ── Currencies & Exchange Rates ─────────────────────────────────────────

    private async Task EnsureCurrencyTablesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var sl = _schema.Replace("'", "''");
        var sql = $"""
            IF OBJECT_ID(N'[{s}].[Currency]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[Currency]
                (
                    [Id]       INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_Currency] PRIMARY KEY,
                    [Code]     NVARCHAR(5)       NOT NULL,
                    [Name]     NVARCHAR(100)     NOT NULL,
                    [Symbol]   NVARCHAR(5)       NULL,
                    [IsActive] BIT               NOT NULL DEFAULT(1),
                    [Created]  DATETIME          NOT NULL DEFAULT(GETDATE()),
                    [Updated]  DATETIME          NULL     DEFAULT(GETDATE())
                );
                CREATE UNIQUE INDEX [UX_Currency_Code] ON [{s}].[Currency]([Code]);
            END;

            -- Migration: eski currencies tablosuna PascalCase kolonlar ekle
            -- Once is_active → IsActive rename (eski snake_case kayitlar icin)
            IF OBJECT_ID(N'[{s}].[Currency]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{sl}.Currency', N'is_active') IS NOT NULL
               AND COL_LENGTH(N'{sl}.Currency', N'IsActive') IS NULL
                EXEC sp_rename N'{sl}.[Currency].[is_active]', N'IsActive', N'COLUMN';
            -- Eger ne is_active ne IsActive yoksa yeni kolon ekle (fresh install icin)
            IF OBJECT_ID(N'[{s}].[Currency]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{sl}.Currency', N'IsActive') IS NULL
               AND COL_LENGTH(N'{sl}.Currency', N'is_active') IS NULL
            BEGIN
                ALTER TABLE [{s}].[Currency] ADD [IsActive] BIT NOT NULL CONSTRAINT [df_currencies_IsActive] DEFAULT(1);
            END;
            IF OBJECT_ID(N'[{s}].[Currency]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{sl}.Currency', N'Created') IS NULL
            BEGIN
                ALTER TABLE [{s}].[Currency] ADD [Created] DATETIME NOT NULL CONSTRAINT [df_currencies_Created] DEFAULT GETDATE();
            END;
            IF OBJECT_ID(N'[{s}].[Currency]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{sl}.Currency', N'Updated') IS NULL
            BEGIN
                ALTER TABLE [{s}].[Currency] ADD [Updated] DATETIME NULL;
            END;

            -- Migration: eski exchange_rates tablosu varsa Exchange'e yeniden adlandir (idempotent)
            IF OBJECT_ID(N'[{s}].[exchange_rates]', N'U') IS NOT NULL
               AND OBJECT_ID(N'[{s}].[Exchange]', N'U') IS NULL
            BEGIN
                EXEC sp_rename N'[{s}].[exchange_rates]', N'Exchange';
            END;

            -- Yeni kurulum: tablo henuz yoksa son schema ile olustur (CurrencyId FK + date)
            IF OBJECT_ID(N'[{s}].[Exchange]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[Exchange]
                (
                    [Id]                    INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_Exchange] PRIMARY KEY,
                    [CurrencyId]            INT               NOT NULL,
                    [Date]                  DATE              NOT NULL,
                    [BuyingRate]            DECIMAL(18,6)     NOT NULL,
                    [SellingRate]           DECIMAL(18,6)     NOT NULL,
                    [EffectiveBuyingRate]   DECIMAL(18,6)     NOT NULL DEFAULT(0),
                    [EffectiveSellingRate]  DECIMAL(18,6)     NOT NULL DEFAULT(0),
                    [Source]                NVARCHAR(20)      NOT NULL DEFAULT(N'TCMB'),
                    [Created]               DATETIME          NOT NULL DEFAULT(GETDATE())
                );
            END;

            -- Migration (idempotent): legacy denormalized columns → FK-based schema
            IF OBJECT_ID(N'[{s}].[Exchange]', N'U') IS NOT NULL
            BEGIN
                -- 1) Drop edilecek kolonlara referans veren eski indeksleri drop et
                IF EXISTS (SELECT 1 FROM sys.indexes
                           WHERE object_id = OBJECT_ID(N'[{s}].[Exchange]')
                             AND name = N'ux_exchange_rates_code_date')
                    DROP INDEX [ux_exchange_rates_code_date] ON [{s}].[Exchange];
                IF EXISTS (SELECT 1 FROM sys.indexes
                           WHERE object_id = OBJECT_ID(N'[{s}].[Exchange]')
                             AND name = N'ux_exchange_code_date')
                    DROP INDEX [ux_exchange_code_date] ON [{s}].[Exchange];

                -- 2) Eksik effective alanlari (eski sema icin)
                IF COL_LENGTH(N'[{s}].[Exchange]', N'effective_buying_rate') IS NULL
                    ALTER TABLE [{s}].[Exchange] ADD [effective_buying_rate] DECIMAL(18,6) NOT NULL DEFAULT(0);
                IF COL_LENGTH(N'[{s}].[Exchange]', N'effective_selling_rate') IS NULL
                    ALTER TABLE [{s}].[Exchange] ADD [effective_selling_rate] DECIMAL(18,6) NOT NULL DEFAULT(0);

                -- 3) Yeni FK kolonu (nullable, backfill icin)
                IF COL_LENGTH(N'[{s}].[Exchange]', N'CurrencyId') IS NULL
                    ALTER TABLE [{s}].[Exchange] ADD [CurrencyId] INT NULL;

                -- 4) rate_date → date rename
                IF COL_LENGTH(N'[{s}].[Exchange]', N'rate_date') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[Exchange]', N'date') IS NULL
                    EXEC sp_rename N'[{s}].[Exchange].rate_date', N'date', N'COLUMN';
            END;

            -- 5) Backfill: currency_code (string) → CurrencyId (currencies.id JOIN code).
            -- EXEC ile sarmaliyoruz; deferred name resolution sayesinde batch icinde ALTER ADD'lenen
            -- CurrencyId kolonu parse-time'da sorun cikarmaz.
            IF OBJECT_ID(N'[{s}].[Exchange]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[Exchange]', N'currency_code') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[Exchange]', N'CurrencyId') IS NOT NULL
               AND OBJECT_ID(N'[{s}].[Currency]', N'U') IS NOT NULL
            BEGIN
                EXEC('
                    UPDATE r SET r.[CurrencyId] = c.[id]
                    FROM [{s}].[Exchange] r
                    INNER JOIN [{s}].[Currency] c ON c.[code] = r.[currency_code]
                    WHERE r.[CurrencyId] IS NULL
                ');
            END;

            -- 6) currency_code drop (backfill bittiyse)
            IF OBJECT_ID(N'[{s}].[Exchange]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[Exchange]', N'currency_code') IS NOT NULL
            BEGIN
                ALTER TABLE [{s}].[Exchange] DROP COLUMN [currency_code];
            END;

            -- 7) Yeni unique index (CurrencyId+date) — filtered: orphan (NULL CurrencyId)
            -- kayitlari constraint disinda tutulur. Mapping basarisiz olan eski kayitlar
            -- kalsa bile yeni insert'lerde UNIQUE garantisi saglanir.
            IF OBJECT_ID(N'[{s}].[Exchange]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[Exchange]', N'CurrencyId') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[Exchange]', N'date') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.indexes
                               WHERE object_id = OBJECT_ID(N'[{s}].[Exchange]')
                                 AND name = N'ux_exchange_currency_date')
            BEGIN
                CREATE UNIQUE INDEX [ux_exchange_currency_date]
                    ON [{s}].[Exchange]([CurrencyId], [date])
                    WHERE [CurrencyId] IS NOT NULL;
            END;

            -- 8) FK constraint (data temiz oldugunda)
            IF OBJECT_ID(N'[{s}].[Exchange]', N'U') IS NOT NULL
               AND OBJECT_ID(N'[{s}].[Currency]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[Exchange]', N'CurrencyId') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.foreign_keys
                               WHERE name = N'fk_exchange_currency'
                                 AND parent_object_id = OBJECT_ID(N'[{s}].[Exchange]'))
               AND NOT EXISTS (SELECT 1 FROM [{s}].[Exchange] WHERE [CurrencyId] IS NULL)
            BEGIN
                ALTER TABLE [{s}].[Exchange] ADD CONSTRAINT [fk_exchange_currency]
                    FOREIGN KEY ([CurrencyId]) REFERENCES [{s}].[Currency]([Id]);
            END;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    private async Task SeedCurrenciesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var seeds = new[] {
            ("TRY", "Turk Lirasi",       "₺"),
            ("USD", "Amerikan Dolari",    "$"),
            ("EUR", "Euro",              "€"),
            ("GBP", "Ingiliz Sterlini",  "£"),
        };
        foreach (var (code, name, symbol) in seeds)
        {
            var sql = $"""
                IF NOT EXISTS (SELECT 1 FROM [{s}].[Currency] WHERE [code] = @Code)
                    INSERT INTO [{s}].[Currency] ([code],[name],[symbol],[IsActive],[Created],[Updated])
                    VALUES (@Code, @Name, @Symbol, 1, GETDATE(), GETDATE());
                """;
            await using var cmd = connection.CreateCommand();
            cmd.CommandText = sql;
            cmd.Parameters.AddWithValue("@Code", code);
            cmd.Parameters.AddWithValue("@Name", name);
            cmd.Parameters.AddWithValue("@Symbol", symbol);
            await cmd.ExecuteNonQueryAsync(cancellationToken);
        }
    }

