    /// <summary>
    /// Faz P — Belge Numarası Türetme Kuralları + Sayaç state. Tasarım Kuralı (DocLayoutRule)
    /// pattern'inin birebir kopyası, ama "tasarım seç" yerine "numara formatı seç". Yeni belge
    /// kayıt edildiğinde IDocumentNumberService rule resolution + counter increment yapar.
    ///
    /// Kolonlar PascalCase (CLAUDE.md naming convention) — yeni tablolar.
    /// Idempotent: tablo varsa ALTER ile eksik kolonlar eklenir.
    /// </summary>
    private async Task EnsureDocumentNumberRulesTableAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var sql = $"""
            -- ── DocumentNumberRule: kural tanımı (filtreler + format) ───────────
            IF OBJECT_ID(N'[{s}].[DocumentNumberRule]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[DocumentNumberRule]
                (
                    [Id]              INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_DocumentNumberRule] PRIMARY KEY,
                    [Name]            NVARCHAR(200) NOT NULL,
                    [DocumentTypeId]  INT           NOT NULL,
                    -- Filtreler (Tasarım Kuralı pattern: NULL = wildcard)
                    [ContactId]       INT           NULL,
                    [ContactGroupId]  INT           NULL,
                    [UserId]          INT           NULL,
                    [BranchId]        INT           NULL,
                    [FromDate]        DATETIME     NULL,
                    [ToDate]          DATETIME     NULL,
                    -- Format parçaları
                    [Prefix]          NVARCHAR(20)  NULL,
                    [YearFormat]      NVARCHAR(10)  NULL,
                    [MonthFormat]     NVARCHAR(10)  NULL,
                    [CounterLength]   INT           NOT NULL CONSTRAINT [DF_DocumentNumberRule_CounterLength] DEFAULT(6),
                    [CounterStart]    INT           NOT NULL CONSTRAINT [DF_DocumentNumberRule_CounterStart] DEFAULT(1),
                    [ResetPeriod]     INT           NOT NULL CONSTRAINT [DF_DocumentNumberRule_ResetPeriod] DEFAULT(0),
                    [TotalLength]     INT           NULL,
                    [Weight]          INT           NOT NULL CONSTRAINT [DF_DocumentNumberRule_Weight] DEFAULT(0),
                    [IsActive]        BIT           NOT NULL CONSTRAINT [DF_DocumentNumberRule_IsActive] DEFAULT(1),
                    [CreatedById]       INT NULL,
                    [Created]         DATETIME     NOT NULL CONSTRAINT [DF_DocumentNumberRule_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById]       INT NULL,
                    [Updated]         DATETIME     NULL
                );
                -- Rule lookup index (en sık sorgu): aktif kurallar belge tipine göre
                CREATE INDEX [IX_DocumentNumberRule_DocumentType]
                    ON [{s}].[DocumentNumberRule]([DocumentTypeId], [IsActive], [Weight] DESC);
            END;

            -- Migration: [CreatedBy]/[UpdatedBy] NVARCHAR -> [CreatedById]/[UpdatedById] INT
            IF OBJECT_ID(N'[{s}].[DocumentNumberRule]', N'U') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[DocumentNumberRule]') AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{s}].[DocumentNumberRule] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{s}].[DocumentNumberRule] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[DocumentNumberRule]') AND name = N'CreatedById')
                    ALTER TABLE [{s}].[DocumentNumberRule] ADD [CreatedById] INT NULL;
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[DocumentNumberRule]') AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{s}].[DocumentNumberRule] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{s}].[DocumentNumberRule] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[DocumentNumberRule]') AND name = N'UpdatedById')
                    ALTER TABLE [{s}].[DocumentNumberRule] ADD [UpdatedById] INT NULL;
            END

            -- ── DocumentNumberCounter: kural başına anlık sayaç state ───────────
            IF OBJECT_ID(N'[{s}].[DocumentNumberCounter]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[DocumentNumberCounter]
                (
                    [Id]            INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_DocumentNumberCounter] PRIMARY KEY,
                    [RuleId]        INT           NOT NULL,
                    [ResetKey]      NVARCHAR(20)  NOT NULL CONSTRAINT [DF_DocumentNumberCounter_ResetKey] DEFAULT(N''),
                    [CurrentValue]  BIGINT        NOT NULL CONSTRAINT [DF_DocumentNumberCounter_CurrentValue] DEFAULT(0),
                    [LastUpdated]   DATETIME     NOT NULL CONSTRAINT [DF_DocumentNumberCounter_LastUpdated] DEFAULT SYSUTCDATETIME(),
                    CONSTRAINT [FK_DocumentNumberCounter_Rule] FOREIGN KEY ([RuleId])
                        REFERENCES [{s}].[DocumentNumberRule]([Id]) ON DELETE CASCADE
                );
                CREATE UNIQUE INDEX [UX_DocumentNumberCounter_Rule_Reset]
                    ON [{s}].[DocumentNumberCounter]([RuleId], [ResetKey]);
            END;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    /// <summary>
    /// 2026-06-21 — Cari/Stok kod türetme kuralları. Tasarım > Tasarım Kuralları altında
    /// 2 yeni tab (Cari Kodu / Stok Kodu) ile yönetilir. Boş gelen Code alanı kural ile
    /// üretilir (Contact.AccountCode, Items.Code). Excel import'ta da geçerlidir.
    ///
    /// Template: free-form string, token'lar:
    ///   {Field:KolonAdi}        → DB kolonu (Contact.City, Item.Category vb.)
    ///   {Widget:WidgetKey}      → WidgetTra değeri (form widget'larından)
    ///   {Counter:N}             → kural-bazlı sayaç (N hane zero-pad), ResetPeriod ile yıllık/aylık reset
    ///   {Year:yyyy|yy}          → current year (4 veya 2 hane)
    ///   {Month:MM}              → current month (2 hane)
    /// Örnek: 'MS-{Field:City}-{Widget:MUSTERI_TIPI}-{Counter:4}' → 'MS-IST-VIP-0001'
    ///
    /// Şart-bazlı kurallar: CodeRuleCondition tablosu ile (örn. Contact.GroupId=5 → 'MS-...',
    /// GroupId=10 → 'TD-...'). Priority en yüksek olan kural önce kontrol edilir.
    /// Çakışma olursa otomatik suffix (-A, -B, ...) eklenir (max 26 deneme).
    /// </summary>
    private async Task EnsureCodeRuleTablesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var sql = $"""
            -- ── CodeRule: Cari/Stok kod türetme kural tanımı ────────────────────
            IF OBJECT_ID(N'[{s}].[CodeRule]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[CodeRule]
                (
                    [Id]            INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_CodeRule] PRIMARY KEY,
                    [EntityType]    NVARCHAR(20)  NOT NULL,  -- 'Contact' | 'Item'
                    [Name]          NVARCHAR(200) NOT NULL,
                    [Template]      NVARCHAR(500) NOT NULL,  -- ornek: MS-Field:City-Counter:4
                    [Priority]      INT           NOT NULL CONSTRAINT [DF_CodeRule_Priority] DEFAULT(0),
                    [ResetPeriod]   INT           NOT NULL CONSTRAINT [DF_CodeRule_ResetPeriod] DEFAULT(0),  -- 0=None, 1=Yearly, 2=Monthly, 3=Daily (DocumentNumberResetPeriod enum reuse)
                    [IsActive]      BIT           NOT NULL CONSTRAINT [DF_CodeRule_IsActive] DEFAULT(1),
                    [CreatedById]   INT           NULL,
                    [Created]       DATETIME      NOT NULL CONSTRAINT [DF_CodeRule_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById]   INT           NULL,
                    [Updated]       DATETIME      NULL
                );
                CREATE INDEX [IX_CodeRule_Entity_Priority]
                    ON [{s}].[CodeRule]([EntityType], [IsActive], [Priority] DESC);
            END;

            -- ── CodeRuleCondition: kural uygulanma şartları (Contact.GroupId=5 gibi) ──
            IF OBJECT_ID(N'[{s}].[CodeRuleCondition]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[CodeRuleCondition]
                (
                    [Id]         INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_CodeRuleCondition] PRIMARY KEY,
                    [RuleId]     INT           NOT NULL,
                    [FieldType]  NVARCHAR(20)  NOT NULL,  -- 'Field' (DB kolonu) | 'Widget' (WidgetTra)
                    [FieldName]  NVARCHAR(120) NOT NULL,  -- 'GroupId' | 'MUSTERI_TIPI'
                    [Operator]   NVARCHAR(20)  NOT NULL,  -- '=' | '!=' | 'in' | 'notin' | 'startsWith' | 'isNull' | 'isNotNull'
                    [Value]      NVARCHAR(500) NULL,      -- tek deger veya JSON array (in/notin icin)
                    CONSTRAINT [FK_CodeRuleCondition_Rule] FOREIGN KEY ([RuleId])
                        REFERENCES [{s}].[CodeRule]([Id]) ON DELETE CASCADE
                );
                CREATE INDEX [IX_CodeRuleCondition_Rule]
                    ON [{s}].[CodeRuleCondition]([RuleId]);
            END;

            -- ── CodeRuleCounter: kural başına anlık sayaç state (DocumentNumberCounter pattern) ──
            IF OBJECT_ID(N'[{s}].[CodeRuleCounter]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[CodeRuleCounter]
                (
                    [Id]           INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_CodeRuleCounter] PRIMARY KEY,
                    [RuleId]       INT           NOT NULL,
                    [ResetKey]     NVARCHAR(20)  NOT NULL CONSTRAINT [DF_CodeRuleCounter_ResetKey] DEFAULT(N''),  -- '' = global, '2026' = yearly, '202606' = monthly, '20260621' = daily
                    [CurrentValue] BIGINT        NOT NULL CONSTRAINT [DF_CodeRuleCounter_CurrentValue] DEFAULT(0),
                    [LastUpdated]  DATETIME      NOT NULL CONSTRAINT [DF_CodeRuleCounter_LastUpdated] DEFAULT SYSUTCDATETIME(),
                    CONSTRAINT [FK_CodeRuleCounter_Rule] FOREIGN KEY ([RuleId])
                        REFERENCES [{s}].[CodeRule]([Id]) ON DELETE CASCADE
                );
                CREATE UNIQUE INDEX [UX_CodeRuleCounter_Rule_Reset]
                    ON [{s}].[CodeRuleCounter]([RuleId], [ResetKey]);
            END;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    /// <summary>
    /// DecimalSetting: form bazinda ondalik hane ayari (miktar/fiyat/tutar/oran/kur).
    /// FormCode '*' = sirket geneli varsayilan. Etkili ayar cozumleme sirasi:
    /// (CompanyId, FormCode) → (CompanyId, '*') → hardcoded fallback (2,2,2,2,4).
    /// CompanyId kolonu bilinçli: sirket yalnizca kendi ayarlarini okur/yazar.
    /// </summary>
    private async Task EnsureDecimalSettingTableAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var sql = $"""
            IF OBJECT_ID(N'[{s}].[DecimalSetting]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[DecimalSetting]
                (
                    [Id]                   INT          IDENTITY(1,1) NOT NULL CONSTRAINT [PK_DecimalSetting] PRIMARY KEY,
                    [CompanyId]            INT          NOT NULL,
                    [FormCode]             NVARCHAR(50) NOT NULL,  -- Forms.FormCode veya '*' (sirket geneli varsayilan)
                    [QuantityDecimals]     INT          NOT NULL CONSTRAINT [DF_DecimalSetting_QuantityDecimals] DEFAULT(2),
                    [UnitPriceDecimals]    INT          NOT NULL CONSTRAINT [DF_DecimalSetting_UnitPriceDecimals] DEFAULT(2),
                    [FxUnitPriceDecimals]  INT          NOT NULL CONSTRAINT [DF_DecimalSetting_FxUnitPriceDecimals] DEFAULT(4),
                    [AmountDecimals]       INT          NOT NULL CONSTRAINT [DF_DecimalSetting_AmountDecimals] DEFAULT(2),
                    [RateDecimals]         INT          NOT NULL CONSTRAINT [DF_DecimalSetting_RateDecimals] DEFAULT(2),
                    [ExchangeRateDecimals] INT          NOT NULL CONSTRAINT [DF_DecimalSetting_ExchangeRateDecimals] DEFAULT(4),
                    [IsActive]             BIT          NOT NULL CONSTRAINT [DF_DecimalSetting_IsActive] DEFAULT(1),
                    [CreatedById]          INT          NULL,
                    [Created]              DATETIME     NOT NULL CONSTRAINT [DF_DecimalSetting_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById]          INT          NULL,
                    [Updated]              DATETIME     NULL
                );
                CREATE UNIQUE INDEX [UX_DecimalSetting_Company_Form]
                    ON [{s}].[DecimalSetting]([CompanyId], [FormCode]);
            END;

            -- Migration: FxUnitPriceDecimals — ilk kurulumdan sonra eklendi (2026-07-05)
            IF OBJECT_ID(N'[{s}].[DecimalSetting]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{s}.DecimalSetting', N'FxUnitPriceDecimals') IS NULL
                ALTER TABLE [{s}].[DecimalSetting]
                    ADD [FxUnitPriceDecimals] INT NOT NULL CONSTRAINT [DF_DecimalSetting_FxUnitPriceDecimals] DEFAULT(4);
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);

        // Migration (2026-07-07): belge-ailesi konsolidasyonu — üst/kalem/yeni/düzenleme
        // kodlarına (X_LINES/X_EDIT/X_NEW) kaydedilmiş ayarlar tek kök koda (X) indirgenir.
        // DecimalSettingService.NormalizeFormCode ile aynı kural. Kök kaydı olmayan
        // şirketlerde en anlamlı alias (_LINES > _EDIT > _NEW) köke kopyalanır; alias
        // satırları her durumda silinir. Idempotent — ikinci çalışmada alias kalmaz.
        // Ayrı komut: FxUnitPriceDecimals ALTER'ı ile aynı batch'te kolon referansı
        // compile hatası vermesin diye.
        var consolidateSql = $"""
            IF OBJECT_ID(N'[{s}].[DecimalSetting]', N'U') IS NOT NULL
            BEGIN
                ;WITH alias AS (
                    SELECT *,
                        CASE
                            WHEN [FormCode] LIKE N'%[_]LINES' THEN LEFT([FormCode], LEN([FormCode]) - 6)
                            WHEN [FormCode] LIKE N'%[_]EDIT'  THEN LEFT([FormCode], LEN([FormCode]) - 5)
                            ELSE LEFT([FormCode], LEN([FormCode]) - 4)
                        END AS [RootCode],
                        CASE
                            WHEN [FormCode] LIKE N'%[_]LINES' THEN 0
                            WHEN [FormCode] LIKE N'%[_]EDIT'  THEN 1
                            ELSE 2
                        END AS [Pri]
                    FROM [{s}].[DecimalSetting]
                    WHERE [FormCode] LIKE N'%[_]LINES' OR [FormCode] LIKE N'%[_]EDIT' OR [FormCode] LIKE N'%[_]NEW'
                ),
                best AS (
                    SELECT *, ROW_NUMBER() OVER (PARTITION BY [CompanyId], [RootCode] ORDER BY [Pri]) AS rn
                    FROM alias
                )
                INSERT INTO [{s}].[DecimalSetting]
                    ([CompanyId],[FormCode],[QuantityDecimals],[UnitPriceDecimals],[FxUnitPriceDecimals],
                     [AmountDecimals],[RateDecimals],[ExchangeRateDecimals],[CreatedById],[UpdatedById])
                SELECT b.[CompanyId], b.[RootCode], b.[QuantityDecimals], b.[UnitPriceDecimals], b.[FxUnitPriceDecimals],
                       b.[AmountDecimals], b.[RateDecimals], b.[ExchangeRateDecimals], b.[CreatedById], b.[UpdatedById]
                FROM best b
                WHERE b.rn = 1
                  AND NOT EXISTS (SELECT 1 FROM [{s}].[DecimalSetting] r
                                  WHERE r.[CompanyId] = b.[CompanyId] AND r.[FormCode] = b.[RootCode]);

                DELETE FROM [{s}].[DecimalSetting]
                WHERE [FormCode] LIKE N'%[_]LINES' OR [FormCode] LIKE N'%[_]EDIT' OR [FormCode] LIKE N'%[_]NEW';
            END;
            """;
        await using var consolidateCmd = connection.CreateCommand();
        consolidateCmd.CommandText = consolidateSql;
        await consolidateCmd.ExecuteNonQueryAsync(cancellationToken);
    }

    /// <summary>
    /// Adres tanimlamalari (2026-07-06): Country -> City -> District -> Neighborhood/Village.
    /// Genel Tanimlamalar sayfasindaki "Adres Tanimlama" grubu yonetir; ileride
    /// ContactEdit Il/Ilce alanlari buradan beslenecek (PTT katalogu yerine).
    /// Ulke kodu KULLANICI girisli (acik talep — CLAUDE.md kod-girilmez kuralinin
    /// bilinçli istisnasi); CurrencyId Currency tablosuna FK; ForeignName uluslararasi ad.
    /// City.PlateCode il plaka kodu. Koy (Village): DistrictId zorunlu, NeighborhoodId
    /// opsiyonel — koy hem ilce altinda mahalle ile ayni hizada hem mahalle altinda olabilir.
    /// Name uniqueness hiyerarsik. Turkiye idempotent seed edilir (Code='TR').
    /// </summary>
    private async Task EnsureAddressDefinitionTablesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var sql = $"""
            IF OBJECT_ID(N'[{s}].[Country]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[Country]
                (
                    [Id]          INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_Country] PRIMARY KEY,
                    [Code]        NVARCHAR(10)  NULL,
                    [Name]        NVARCHAR(100) NOT NULL,
                    [ForeignName] NVARCHAR(100) NULL,
                    [CurrencyId]  INT           NULL,
                    [IsActive]    BIT           NOT NULL CONSTRAINT [DF_Country_IsActive] DEFAULT(1),
                    [CreatedById] INT           NULL,
                    [Created]     DATETIME      NOT NULL CONSTRAINT [DF_Country_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById] INT           NULL,
                    [Updated]     DATETIME      NULL
                );
                CREATE UNIQUE INDEX [UX_Country_Name] ON [{s}].[Country]([Name]);
            END;

            -- Migration: ForeignName + CurrencyId (ilk kurulumdan sonra eklendi — 2026-07-06)
            IF OBJECT_ID(N'[{s}].[Country]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{s}.Country', N'ForeignName') IS NULL
                ALTER TABLE [{s}].[Country] ADD [ForeignName] NVARCHAR(100) NULL;
            IF OBJECT_ID(N'[{s}].[Country]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{s}.Country', N'CurrencyId') IS NULL
                ALTER TABLE [{s}].[Country] ADD [CurrencyId] INT NULL;

            IF OBJECT_ID(N'[{s}].[City]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[City]
                (
                    [Id]          INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_City] PRIMARY KEY,
                    [CountryId]   INT           NOT NULL,
                    [Code]        NVARCHAR(50)  NULL,
                    [Name]        NVARCHAR(100) NOT NULL,
                    [PlateCode]   NVARCHAR(10)  NULL,
                    [IsActive]    BIT           NOT NULL CONSTRAINT [DF_City_IsActive] DEFAULT(1),
                    [CreatedById] INT           NULL,
                    [Created]     DATETIME      NOT NULL CONSTRAINT [DF_City_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById] INT           NULL,
                    [Updated]     DATETIME      NULL,
                    CONSTRAINT [FK_City_Country] FOREIGN KEY ([CountryId]) REFERENCES [{s}].[Country]([Id])
                );
                CREATE UNIQUE INDEX [UX_City_Country_Name] ON [{s}].[City]([CountryId], [Name]);
                CREATE INDEX [IX_City_Country] ON [{s}].[City]([CountryId]);
            END;

            -- Migration: PlateCode (2026-07-06)
            IF OBJECT_ID(N'[{s}].[City]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{s}.City', N'PlateCode') IS NULL
                ALTER TABLE [{s}].[City] ADD [PlateCode] NVARCHAR(10) NULL;

            IF OBJECT_ID(N'[{s}].[District]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[District]
                (
                    [Id]          INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_District] PRIMARY KEY,
                    [CityId]      INT           NOT NULL,
                    [Code]        NVARCHAR(50)  NULL,
                    [Name]        NVARCHAR(100) NOT NULL,
                    [IsActive]    BIT           NOT NULL CONSTRAINT [DF_District_IsActive] DEFAULT(1),
                    [CreatedById] INT           NULL,
                    [Created]     DATETIME      NOT NULL CONSTRAINT [DF_District_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById] INT           NULL,
                    [Updated]     DATETIME      NULL,
                    CONSTRAINT [FK_District_City] FOREIGN KEY ([CityId]) REFERENCES [{s}].[City]([Id])
                );
                CREATE UNIQUE INDEX [UX_District_City_Name] ON [{s}].[District]([CityId], [Name]);
                CREATE INDEX [IX_District_City] ON [{s}].[District]([CityId]);
            END;

            -- ── Neighborhood: mahalle (ilce altinda) ─────────────────────────
            IF OBJECT_ID(N'[{s}].[Neighborhood]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[Neighborhood]
                (
                    [Id]          INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_Neighborhood] PRIMARY KEY,
                    [DistrictId]  INT           NOT NULL,
                    [Code]        NVARCHAR(50)  NULL,
                    [Name]        NVARCHAR(150) NOT NULL,
                    [IsActive]    BIT           NOT NULL CONSTRAINT [DF_Neighborhood_IsActive] DEFAULT(1),
                    [CreatedById] INT           NULL,
                    [Created]     DATETIME      NOT NULL CONSTRAINT [DF_Neighborhood_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById] INT           NULL,
                    [Updated]     DATETIME      NULL,
                    CONSTRAINT [FK_Neighborhood_District] FOREIGN KEY ([DistrictId]) REFERENCES [{s}].[District]([Id])
                );
                CREATE UNIQUE INDEX [UX_Neighborhood_District_Name] ON [{s}].[Neighborhood]([DistrictId], [Name]);
                CREATE INDEX [IX_Neighborhood_District] ON [{s}].[Neighborhood]([DistrictId]);
            END;

            -- ── Village: koy — DistrictId zorunlu; NeighborhoodId doluysa mahalle
            --    altinda, bos ise ilce altinda (mahalle ile ayni hizada) ──────
            IF OBJECT_ID(N'[{s}].[Village]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[Village]
                (
                    [Id]             INT           IDENTITY(1,1) NOT NULL CONSTRAINT [PK_Village] PRIMARY KEY,
                    [DistrictId]     INT           NOT NULL,
                    [NeighborhoodId] INT           NULL,
                    [Code]           NVARCHAR(50)  NULL,
                    [Name]           NVARCHAR(150) NOT NULL,
                    [IsActive]       BIT           NOT NULL CONSTRAINT [DF_Village_IsActive] DEFAULT(1),
                    [CreatedById]    INT           NULL,
                    [Created]        DATETIME      NOT NULL CONSTRAINT [DF_Village_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById]    INT           NULL,
                    [Updated]        DATETIME      NULL,
                    CONSTRAINT [FK_Village_District] FOREIGN KEY ([DistrictId]) REFERENCES [{s}].[District]([Id]),
                    CONSTRAINT [FK_Village_Neighborhood] FOREIGN KEY ([NeighborhoodId]) REFERENCES [{s}].[Neighborhood]([Id])
                );
                CREATE UNIQUE INDEX [UX_Village_District_Name] ON [{s}].[Village]([DistrictId], [Name])
                    WHERE [NeighborhoodId] IS NULL;
                CREATE UNIQUE INDEX [UX_Village_Neighborhood_Name] ON [{s}].[Village]([NeighborhoodId], [Name])
                    WHERE [NeighborhoodId] IS NOT NULL;
                CREATE INDEX [IX_Village_District] ON [{s}].[Village]([DistrictId]);
                CREATE INDEX [IX_Village_Neighborhood] ON [{s}].[Village]([NeighborhoodId]) WHERE [NeighborhoodId] IS NOT NULL;
            END;

            -- Seed: Türkiye (idempotent). Deferred EXEC: ForeignName kolonu aynı batch'te
            -- ALTER ile eklendiğinden düz INSERT parse-time 207 verir (BridgeMsgId dersi).
            IF NOT EXISTS (SELECT 1 FROM [{s}].[Country] WHERE [Name] = N'Türkiye')
                EXEC(N'INSERT INTO [{s}].[Country] ([Code],[Name],[ForeignName]) VALUES (N''TR'', N''Türkiye'', N''Turkey'');');
            -- Mevcut Türkiye kaydına ForeignName doldur (kolon yeni eklendiyse)
            EXEC(N'UPDATE [{s}].[Country] SET [ForeignName] = N''Turkey'' WHERE [Name] = N''Türkiye'' AND [ForeignName] IS NULL;');
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

