    /// <summary>
    /// WhatsApp Cloud API yapilandirma tablosu — tek satir (id=1). Token DPAPI sifreli saklanir.
    /// Ayrica safety rules + send log tablolari.
    /// </summary>
    private async Task EnsureWhatsAppConfigTableAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var schemaLiteral = _schema.Replace("'", "''");
        var commandText = $"""
            IF OBJECT_ID(N'[{s}].[WhatsAppConfig]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[WhatsAppConfig]
                (
                    [Id]                     INT           NOT NULL CONSTRAINT [PK_WhatsAppConfig] PRIMARY KEY,
                    [Provider]               INT           NOT NULL DEFAULT(0),
                    [AccessTokenEncrypted]   NVARCHAR(MAX) NULL,
                    [PhoneNumberId]          NVARCHAR(64)  NULL,
                    [BusinessAccountId]      NVARCHAR(64)  NULL,
                    [DisplayPhoneNumber]     NVARCHAR(32)  NULL,
                    [WebhookVerifyToken]     NVARCHAR(128) NULL,
                    [WebQrBridgeUrl]         NVARCHAR(256) NULL,
                    [IsEnabled]              BIT           NOT NULL DEFAULT(0),
                    [LastSuccessfulSendAt]   DATETIME      NULL,
                    [LastError]              NVARCHAR(500) NULL,
                    [Created]                DATETIME      NOT NULL,
                    [Updated]                DATETIME      NULL
                );
            END;
            -- Migration: eski tabloya provider + web_qr_bridge_url kolonlari ekle
            IF COL_LENGTH(N'[{s}].[WhatsAppConfig]', N'provider') IS NULL
                ALTER TABLE [{s}].[WhatsAppConfig] ADD [provider] INT NOT NULL DEFAULT(0);
            IF COL_LENGTH(N'[{s}].[WhatsAppConfig]', N'web_qr_bridge_url') IS NULL
                ALTER TABLE [{s}].[WhatsAppConfig] ADD [web_qr_bridge_url] NVARCHAR(256) NULL;
            IF COL_LENGTH(N'[{s}].[WhatsAppConfig]', N'app_secret_encrypted') IS NULL
                ALTER TABLE [{s}].[WhatsAppConfig] ADD [app_secret_encrypted] NVARCHAR(MAX) NULL;
            -- Migration: IsEnabled / LastError PascalCase olmali (repository boyle sorgular; bu tablonun
            -- Created/Updated'i de PascalCase — proje snake→Pascal gecisinde). Tablo yanlis snake_case
            -- (is_enabled/last_error) ile olusmus veya oyle yeniden adlandirilmis olabilir → veriyi
            -- koruyarak Pascal'a cevir; hic yoksa ekle. (COL_LENGTH underscore'u gercek karakter sayar;
            -- 'IsEnabled' ile 'is_enabled' eslesmez, IS NULL kontrolu dogru calisir.)
            IF COL_LENGTH(N'[{s}].[WhatsAppConfig]', N'IsEnabled') IS NULL
            BEGIN
                IF COL_LENGTH(N'[{s}].[WhatsAppConfig]', N'is_enabled') IS NOT NULL
                    EXEC sp_rename N'[{s}].[WhatsAppConfig].[is_enabled]', N'IsEnabled', N'COLUMN';
                ELSE
                    ALTER TABLE [{s}].[WhatsAppConfig] ADD [IsEnabled] BIT NOT NULL DEFAULT(0);
            END;
            IF COL_LENGTH(N'[{s}].[WhatsAppConfig]', N'LastError') IS NULL
            BEGIN
                IF COL_LENGTH(N'[{s}].[WhatsAppConfig]', N'last_error') IS NOT NULL
                    EXEC sp_rename N'[{s}].[WhatsAppConfig].[last_error]', N'LastError', N'COLUMN';
                ELSE
                    ALTER TABLE [{s}].[WhatsAppConfig] ADD [LastError] NVARCHAR(500) NULL;
            END;

            -- Safety rules — tek-row config
            IF OBJECT_ID(N'[{s}].[WhatsAppSafetyRule]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[WhatsAppSafetyRule]
                (
                    [Id]                           INT          NOT NULL CONSTRAINT [PK_WhatsAppSafetyRule] PRIMARY KEY,
                    [MaxPerMinute]                 INT          NOT NULL DEFAULT(5),
                    [MaxPerHour]                   INT          NOT NULL DEFAULT(60),
                    [MaxPerDay]                    INT          NOT NULL DEFAULT(300),
                    [MaxPerRecipientPerDay]        INT          NOT NULL DEFAULT(3),
                    [MinDelaySeconds]              INT          NOT NULL DEFAULT(3),
                    [MaxDelaySeconds]              INT          NOT NULL DEFAULT(15),
                    [MaxConsecutiveFailures]       INT          NOT NULL DEFAULT(5),
                    [FailureCooldownMinutes]       INT          NOT NULL DEFAULT(30),
                    [WarmupDays]                   INT          NOT NULL DEFAULT(7),
                    [WarmupMaxPerDay]              INT          NOT NULL DEFAULT(50),
                    [MaxIdenticalMessagesPerDay]   INT          NOT NULL DEFAULT(10),
                    [Created]                      DATETIME     NOT NULL,
                    [Updated]                      DATETIME     NULL
                );
                INSERT INTO [{s}].[WhatsAppSafetyRule]
                    ([Id],[Created],[Updated])
                VALUES (1, GETUTCDATE(), GETUTCDATE());
            END;

            -- Send log — her gönderim girişimini audit'e kaydeder
            IF OBJECT_ID(N'[{s}].[WhatsAppSendLog]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[WhatsAppSendLog]
                (
                    [Id]           BIGINT        IDENTITY(1,1) NOT NULL CONSTRAINT [PK_WhatsAppSendLog] PRIMARY KEY,
                    [SentAt]       DATETIME      NOT NULL,
                    [ToPhone]      NVARCHAR(32)  NULL,
                    [MessageHash]  NVARCHAR(64)  NULL,
                    [MessageId]    NVARCHAR(128) NULL,
                    [Success]      BIT           NOT NULL,
                    [ErrorMessage] NVARCHAR(500) NULL,
                    [BlockReason]  NVARCHAR(300) NULL
                );
                CREATE INDEX [IX_WhatsAppSendLog_SentAt] ON [{s}].[WhatsAppSendLog]([SentAt] DESC);
                CREATE INDEX [IX_WhatsAppSendLog_ToPhone_SentAt] ON [{s}].[WhatsAppSendLog]([ToPhone],[SentAt]) WHERE [Success]=1;
                CREATE INDEX [IX_WhatsAppSendLog_MessageHash_SentAt] ON [{s}].[WhatsAppSendLog]([MessageHash],[SentAt]) WHERE [Success]=1;
            END;

            -- WhatsApp inbox/giden — Bridge'ten poll'lanan birebir mesajlar (gruplar haric)
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[WaInbox]
                (
                    [Id]            BIGINT        IDENTITY(1,1) NOT NULL CONSTRAINT [PK_WaInbox] PRIMARY KEY,
                    [BridgeMsgId]   NVARCHAR(128) NULL,                  -- whatsapp-web.js msg.id._serialized; UNIQUE for dedup
                    [Direction]     TINYINT       NOT NULL,              -- 0=incoming, 1=outgoing
                    [ContactPhone]  NVARCHAR(32)  NOT NULL,              -- normalize: digits, no '+'
                    [ContactId]     INT           NULL,                  -- Contact.Id eslestirme (phone -> Contact.WaPhone/Mobile/Phone)
                    [ContactName]   NVARCHAR(150) NULL,                  -- WA pushname
                    [Body]          NVARCHAR(MAX) NULL,
                    [MediaType]     NVARCHAR(20)  NULL,                  -- chat|image|video|audio|document|sticker|location
                    [HasMedia]      BIT           NOT NULL DEFAULT 0,
                    [ReceivedAt]    DATETIME      NOT NULL,              -- Bridge'in verdiği timestamp
                    [Created]       DATETIME      NOT NULL,              -- DB'ye yazıldığı an
                    [ReadAt]        DATETIME      NULL,                  -- kullanıcı okuyunca set edilir (sohbet acılınca)
                    [MediaPath]     NVARCHAR(500) NULL,                  -- wwwroot/uploads/whatsapp/yyyy/MM/<id>.<ext>
                    [MediaMime]     NVARCHAR(100) NULL,
                    [MediaFilename] NVARCHAR(200) NULL,
                    [MediaSize]     INT           NULL
                );
                -- Deferred EXEC: BridgeMsgId may not exist on the renamed table at batch-compile time.
                EXEC(N'CREATE UNIQUE INDEX [UX_WaInbox_BridgeMsgId] ON [{s}].[WaInbox]([BridgeMsgId]) WHERE [BridgeMsgId] IS NOT NULL;');
                CREATE INDEX [IX_WaInbox_ContactPhone_ReceivedAt] ON [{s}].[WaInbox]([ContactPhone],[ReceivedAt] DESC);
                -- Deferred EXEC: filtered index WHERE [ReadAt] IS NULL must not be compiled
                -- against the existing table at batch-compile time (ReadAt may not exist yet).
                EXEC(N'CREATE INDEX [IX_WaInbox_Unread] ON [{s}].[WaInbox]([ContactPhone]) WHERE [Direction]=0 AND [ReadAt] IS NULL;');
            END;

            -- Migration: BridgeMsgId unique index — eski ux_wa_inbox_bridge_msg_id drop+rename sonrasi yeniden olustur
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'BridgeMsgId') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.indexes
                               WHERE object_id = OBJECT_ID(N'[{s}].[WaInbox]')
                                 AND name = N'UX_WaInbox_BridgeMsgId')
            BEGIN
                EXEC(N'CREATE UNIQUE INDEX [UX_WaInbox_BridgeMsgId] ON [{s}].[WaInbox]([BridgeMsgId]) WHERE [BridgeMsgId] IS NOT NULL;');
            END;

            -- Migration: ReadAt kolonu eski wa_inbox tablolarında yok — ekle
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'ReadAt') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [ReadAt] DATETIME NULL;
            END;

            -- (Kaldirildi) WhatsApp 2024+ protokolu LID identifier'lari da kullaniyor (15+ basamak).
            -- LID'leri telefon-disi olarak silmek artik dogru degil; modern WA mesajlari LID ile geliyor
            -- ve resolve sirasinda gercek telefonu cikartilamayanlar dogal olarak LID ile kaydediliyor.
            -- Eski kayitlari el ile temizlemek istersen UI'dan sohbeti silebilirsin.

            -- WaContact: WhatsApp kişi master tablosu
            IF OBJECT_ID(N'[{s}].[WaContact]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[WaContact]
                (
                    [Id]             INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_WaContact] PRIMARY KEY,
                    [PrimaryPhone]   NVARCHAR(32)  NULL,
                    [DisplayName]    NVARCHAR(200) NULL,
                    [ProfilePicUrl]  NVARCHAR(500) NULL,
                    [LastSeen]       DATETIME     NULL,
                    [PresenceStatus] NVARCHAR(20)  NULL,
                    [LinkedContactId] INT           NULL,
                    [IsBlocked]      BIT           NOT NULL CONSTRAINT [DF_WaContact_IsBlocked] DEFAULT 0,
                    [IsActive]       BIT           NOT NULL CONSTRAINT [DF_WaContact_IsActive] DEFAULT 1,
                    [CreatedById]      INT NULL,
                    [Created]        DATETIME     NOT NULL CONSTRAINT [DF_WaContact_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById]      INT NULL,
                    [Updated]        DATETIME     NULL
                );
                -- Filtered unique index: NULL PrimaryPhone (LID-only) birden fazla olabilir
                CREATE UNIQUE INDEX [UX_WaContact_PrimaryPhone]
                    ON [{s}].[WaContact]([PrimaryPhone]) WHERE [PrimaryPhone] IS NOT NULL;
            END;

            -- Migration: [CreatedBy]/[UpdatedBy] NVARCHAR -> [CreatedById]/[UpdatedById] INT
            IF OBJECT_ID(N'[{s}].[WaContact]', N'U') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[WaContact]') AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{s}].[WaContact] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{s}].[WaContact] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[WaContact]') AND name = N'CreatedById')
                    ALTER TABLE [{s}].[WaContact] ADD [CreatedById] INT NULL;
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[WaContact]') AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{s}].[WaContact] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{s}].[WaContact] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[WaContact]') AND name = N'UpdatedById')
                    ALTER TABLE [{s}].[WaContact] ADD [UpdatedById] INT NULL;
            END

            -- WaContactJid: bir WaContact'ın sahip olduğu tüm JID'ler
            IF OBJECT_ID(N'[{s}].[WaContactJid]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[WaContactJid]
                (
                    [Id]        INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_WaContactJid] PRIMARY KEY,
                    [ContactId] INT          NOT NULL CONSTRAINT [FK_WaContactJid_WaContact] REFERENCES [{s}].[WaContact]([Id]),
                    [Jid]       NVARCHAR(80) NOT NULL,
                    [JidType]   NVARCHAR(20) NOT NULL,
                    [IsPrimary] BIT          NOT NULL CONSTRAINT [DF_WaContactJid_IsPrimary] DEFAULT 0,
                    [Created]   DATETIME    NOT NULL CONSTRAINT [DF_WaContactJid_Created] DEFAULT SYSUTCDATETIME(),
                    CONSTRAINT [UX_WaContactJid_Jid] UNIQUE ([Jid])
                );
                CREATE INDEX [IX_WaContactJid_Contact] ON [{s}].[WaContactJid]([ContactId]);
            END;

            -- wa_inbox.is_lid: LID identifier içeren satırlar (gerçek telefon numarası değil)
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'is_lid') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [is_lid] BIT NOT NULL CONSTRAINT [DF_wa_inbox_is_lid] DEFAULT 0;
            END;

            -- wa_inbox.wa_contact_id: WaContact FK (contact_id mevcut Contact tablosuna bağlı, bu yeni)
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'wa_contact_id') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [wa_contact_id] INT NULL;
            END;

            -- Medya destek kolonlari (image/video/audio/document)
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'media_path') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [media_path] NVARCHAR(500) NULL;
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'media_mime') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [media_mime] NVARCHAR(100) NULL;
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'media_filename') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [media_filename] NVARCHAR(200) NULL;
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'media_size') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [media_size] INT NULL;
            END;

            -- Faz 2: mesaj türü, alıntı yanıt, reaksiyon, silme, iletim durumu
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'message_type') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [message_type] NVARCHAR(20) NULL;
                -- text|image|audio|video|document|sticker|location|reaction|deleted
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'quoted_msg_id') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [quoted_msg_id] NVARCHAR(80) NULL;
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'reaction_emoji') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [reaction_emoji] NVARCHAR(20) NULL;
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'is_forwarded') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [is_forwarded] BIT NOT NULL CONSTRAINT [DF_wa_inbox_is_forwarded] DEFAULT 0;
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'is_deleted') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [is_deleted] BIT NOT NULL CONSTRAINT [DF_wa_inbox_is_deleted] DEFAULT 0;
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'delivery_status') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [delivery_status] NVARCHAR(20) NULL;
                -- sent|delivered|read|failed
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'delivered_at') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [delivered_at] DATETIME NULL;
            END;
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'read_by_peer_at') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [read_by_peer_at] DATETIME NULL;
            END;

            -- Faz 4: grup mesajları için wa_inbox ek kolonlar
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.WaInbox', N'group_jid') IS NULL
            BEGIN
                ALTER TABLE [{s}].[WaInbox] ADD [group_jid]   NVARCHAR(80)  NULL;
                ALTER TABLE [{s}].[WaInbox] ADD [sender_jid]  NVARCHAR(80)  NULL;
                ALTER TABLE [{s}].[WaInbox] ADD [SenderName] NVARCHAR(200) NULL;
            END;

            -- Performans indexi: Direction + ContactPhone + ReceivedAt
            -- GetConversationsAsync CTE'leri (has_incoming_cte, last_incoming_name) ve
            -- GetMessagesByPhoneAsync direkt esitlik sorgusu icin kullanilir.
            -- 2026-07-10: kolon adlari PascalCase'e cekildi — bu noktada her DB Pascal'dir
            -- (taze CREATE Pascal dogar, legacy kolonlar zincirin 5. adiminda rename edilir).
            -- Eski snake_case referans taze DB'de "Column name 'contact_phone' does not
            -- exist" (1911) ile tum init'i durduruyordu. Index adi ayni kaldi; index'i
            -- zaten olan eski DB'ler NOT EXISTS guard'i ile atlanir.
            IF OBJECT_ID(N'[{s}].[WaInbox]', N'U') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.indexes
                               WHERE object_id = OBJECT_ID(N'[{s}].[WaInbox]')
                                 AND name = N'ix_wa_inbox_direction_phone')
            BEGIN
                CREATE INDEX [ix_wa_inbox_direction_phone]
                    ON [{s}].[WaInbox]([Direction], [ContactPhone], [ReceivedAt] DESC);
            END;

            -- WaGroup: grup master tablosu
            IF OBJECT_ID(N'[{s}].[WaGroup]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[WaGroup]
                (
                    [Id]          INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_WaGroup] PRIMARY KEY,
                    [GroupJid]    NVARCHAR(80)   NOT NULL CONSTRAINT [UX_WaGroup_Jid] UNIQUE,
                    [Subject]     NVARCHAR(200)  NOT NULL,
                    [Description] NVARCHAR(1000) NULL,
                    [MemberCount] INT            NOT NULL CONSTRAINT [DF_WaGroup_MemberCount] DEFAULT 0,
                    [IsActive]    BIT            NOT NULL CONSTRAINT [DF_WaGroup_IsActive]    DEFAULT 1,
                    [Created]     DATETIME      NOT NULL CONSTRAINT [DF_WaGroup_Created]     DEFAULT SYSUTCDATETIME(),
                    [Updated]     DATETIME      NULL
                );
            END;

            -- WaGroupMember: grup üyeleri
            IF OBJECT_ID(N'[{s}].[WaGroupMember]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[WaGroupMember]
                (
                    [Id]        INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_WaGroupMember] PRIMARY KEY,
                    [GroupId]   INT          NOT NULL CONSTRAINT [FK_WaGroupMember_Group]   REFERENCES [{s}].[WaGroup]([Id]),
                    [ContactId] INT          NULL     CONSTRAINT [FK_WaGroupMember_Contact] REFERENCES [{s}].[WaContact]([Id]),
                    [Jid]       NVARCHAR(80) NOT NULL,
                    [Name]      NVARCHAR(200) NULL,
                    [Role]      NVARCHAR(20) NOT NULL CONSTRAINT [DF_WaGroupMember_Role] DEFAULT 'member',
                    [JoinedAt]  DATETIME    NOT NULL CONSTRAINT [DF_WaGroupMember_JoinedAt] DEFAULT SYSUTCDATETIME(),
                    [LeftAt]    DATETIME    NULL,
                    CONSTRAINT [UX_WaGroupMember_Unique] UNIQUE ([GroupId], [Jid])
                );
                CREATE INDEX [IX_WaGroupMember_Group] ON [{s}].[WaGroupMember]([GroupId]);
            END;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = commandText;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

