    private async Task SeedDocumentTypesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");

        // Migration: satis_teklifi eskiden vw_Document'a point ediyordu;
        // yeni vw_ReportDocument turkce semayi + widget kolonlarini tasiyor.
        await using (var migCmd = connection.CreateCommand())
        {
            migCmd.CommandText = $"""
                UPDATE [{s}].[DocumentType]
                   SET [SqlViewName] = 'vw_ReportDocument', [Updated] = GETDATE()
                 WHERE [Code] = 'satis_teklifi' AND [SqlViewName] = 'vw_Document';
                """;
            await migCmd.ExecuteNonQueryAsync(cancellationToken);
        }

        // 2026-05-23 Migration: "Alis Talebi" → "Ihtiyac Kaydi" rename.
        // Belge tipinin kod tarafi (alis_talebi) korunur — sadece kullaniciya gosterilen
        // name + description guncellenir.
        await using (var renameCmd = connection.CreateCommand())
        {
            renameCmd.CommandText = $"""
                UPDATE [{s}].[DocumentType]
                   SET [Name]        = N'Ihtiyac Kaydi',
                       [Description] = N'Ic ihtiyac kaydi — depodan veya satin alma ile karsilanabilir',
                       [Updated]     = GETDATE()
                 WHERE [Code] = 'alis_talebi'
                   AND [Name] IN (N'Alis Talebi', N'Satin Alma Talep', N'Satın Alma Talep');
                """;
            await renameCmd.ExecuteNonQueryAsync(cancellationToken);
        }

        // Migration: mevcut DB'lerde required_key_column bos olanlari default'a set et.
        // Yeni kayitlar INSERT ile dogru deger alir; eski kayitlar burada heal edilir.
        foreach (var (code, _, _, reqKey, _) in DefaultDocumentTypes)
        {
            if (string.IsNullOrWhiteSpace(reqKey)) continue;
            await using var updCmd = connection.CreateCommand();
            updCmd.CommandText = $"""
                UPDATE [{s}].[DocumentType]
                   SET [RequiredKeyColumn] = @ReqKey, [Updated] = GETDATE()
                 WHERE [Code] = @Code AND ([RequiredKeyColumn] IS NULL OR [RequiredKeyColumn] = N'');
                """;
            updCmd.Parameters.AddWithValue("@Code",   code);
            updCmd.Parameters.AddWithValue("@ReqKey", reqKey);
            await updCmd.ExecuteNonQueryAsync(cancellationToken);
        }

        foreach (var (code, name, viewName, reqKey, desc) in DefaultDocumentTypes)
        {
            var commandText = $"""
                IF NOT EXISTS (SELECT 1 FROM [{s}].[DocumentType] WHERE [Code] = @Code)
                    INSERT INTO [{s}].[DocumentType] ([Code],[Name],[SqlViewName],[RequiredKeyColumn],[Description],[IsActive],[Created],[Updated])
                    VALUES (@Code, @Name, @ViewName, @ReqKey, @Description, 1, GETDATE(), GETDATE());
                """;
            await using var cmd = connection.CreateCommand();
            cmd.CommandText = commandText;
            cmd.Parameters.AddWithValue("@Code",        code);
            cmd.Parameters.AddWithValue("@Name",        name);
            cmd.Parameters.AddWithValue("@ViewName",    (object?)viewName ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@ReqKey",      (object?)reqKey   ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@Description", (object?)desc     ?? DBNull.Value);
            await cmd.ExecuteNonQueryAsync(cancellationToken);
        }
    }

    /// <summary>
    /// Her belge tipi için sistem-varsayılan bir DocLayout (orta-süslü tasarım) seed eder.
    /// Idempotent: o tip için zaten IsDefault=1 layout varsa eklemez. OwnerUserId=0 = sistem.
    /// JSON üretimi <see cref="CalibraHub.Application.Services.DesignProvider.DefaultDocLayoutBuilder"/>
    /// üzerinden parametrik yapılır; barkod/etiket için 80x40mm, mail_template için tek-bant
    /// HTML uyumlu, diğerleri A4 belge şablonu üretilir.
    /// </summary>
    private async Task SeedDefaultDocLayoutsAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");

        // OwnerUserId — FK olarak Users.Id'ye bağlı. Admin user'ı bul; yoksa
        // herhangi bir kullanıcının id'sini kullan. Hiç kullanıcı yoksa seed'i skip et
        // (admin user seed'i zaten bizden önce çalışmış olmalı).
        int ownerUserId;
        await using (var ownerCmd = connection.CreateCommand())
        {
            ownerCmd.CommandText = $@"
                SELECT TOP 1 [Id] FROM [{s}].[Users]
                 ORDER BY CASE WHEN [Role] = 'admin' THEN 0 ELSE 1 END, [Id];";
            var raw = await ownerCmd.ExecuteScalarAsync(cancellationToken);
            if (raw == null || raw == DBNull.Value) return;
            ownerUserId = Convert.ToInt32(raw);
        }

        foreach (var (code, name, viewName, reqKey, _) in DefaultDocumentTypes)
        {
            // Bu tip için DocumentType id'si — IsDefault=1 layout zaten varsa skip
            int? docTypeId = null;
            await using (var typeCmd = connection.CreateCommand())
            {
                typeCmd.CommandText = $"SELECT TOP 1 [Id] FROM [{s}].[DocumentType] WHERE [Code] = @Code;";
                typeCmd.Parameters.AddWithValue("@Code", code);
                var raw = await typeCmd.ExecuteScalarAsync(cancellationToken);
                if (raw != null && raw != DBNull.Value) docTypeId = Convert.ToInt32(raw);
            }
            if (docTypeId is null) continue;

            // JSON üret
            var built = global::CalibraHub.Application.Services.DesignProvider.DefaultDocLayoutBuilder.Build(
                docTypeCode: code, docTypeName: name, viewName: viewName, requiredKeyColumn: reqKey);
            var layoutCode = $"default_{code}";
            var layoutName = $"Varsayılan {name}";
            var layoutDesc = $"Sistem tarafından oluşturulan varsayılan {name} tasarımı — kopyalanıp özelleştirilebilir.";

            // UPSERT: "default_<code>" koduyla mevcut SİSTEM default'u varsa JSON'ı güncelle
            // (kullanıcı klonlayıp özelleştirmemişse — Owner=admin ve IsDefault=1 ise sistem'in
            // yönettiği layout'tur). Mevcut değilse INSERT.
            int? existingLayoutId = null;
            await using (var existCmd = connection.CreateCommand())
            {
                existCmd.CommandText = $"SELECT TOP 1 [Id] FROM [{s}].[DocLayout] WHERE [Code] = @LayoutCode;";
                existCmd.Parameters.AddWithValue("@LayoutCode", layoutCode);
                var raw = await existCmd.ExecuteScalarAsync(cancellationToken);
                if (raw != null && raw != DBNull.Value) existingLayoutId = Convert.ToInt32(raw);
            }

            int newLayoutId;
            if (existingLayoutId.HasValue)
            {
                // UPDATE: aynı varsayılan layout, güncel JSON ile yenile.
                await using var updCmd = connection.CreateCommand();
                updCmd.CommandText = $@"
                    UPDATE [{s}].[DocLayout]
                       SET [Name]            = @Name,
                           [DocType]         = @DocType,
                           [DocumentTypeId]  = @DocTypeId,
                           [Description]     = @Description,
                           [LayoutJson]      = @LayoutJson,
                           [PageW]           = @PageW,
                           [PageH]           = @PageH,
                           [MarginTop]       = @MarginTop,
                           [MarginBot]       = @MarginBot,
                           [MarginLeft]      = @MarginLeft,
                           [MarginRight]     = @MarginRight,
                           [IsDefault]       = 1,
                           [IsActive]        = 1,
                           [Updated]         = SYSUTCDATETIME(),
                           [OutputFormat]    = @OutputFormat,
                           [UseAsMailTemplate] = @UseAsMail
                     WHERE [Id] = @Id;";
                updCmd.Parameters.AddWithValue("@Id",          existingLayoutId.Value);
                updCmd.Parameters.AddWithValue("@Name",        layoutName);
                updCmd.Parameters.AddWithValue("@DocType",     code);
                updCmd.Parameters.AddWithValue("@DocTypeId",   docTypeId.Value);
                updCmd.Parameters.AddWithValue("@Description", layoutDesc);
                updCmd.Parameters.AddWithValue("@LayoutJson",  built.LayoutJson);
                updCmd.Parameters.AddWithValue("@PageW",       built.Meta.PageW);
                updCmd.Parameters.AddWithValue("@PageH",       built.Meta.PageH);
                updCmd.Parameters.AddWithValue("@MarginTop",   built.Meta.MarginTop);
                updCmd.Parameters.AddWithValue("@MarginBot",   built.Meta.MarginBot);
                updCmd.Parameters.AddWithValue("@MarginLeft",  built.Meta.MarginLeft);
                updCmd.Parameters.AddWithValue("@MarginRight", built.Meta.MarginRight);
                updCmd.Parameters.AddWithValue("@OutputFormat", code == "mail_template" ? "email" : "pdf");
                updCmd.Parameters.AddWithValue("@UseAsMail",   code == "mail_template");
                await updCmd.ExecuteNonQueryAsync(cancellationToken);

                // Eski DocLayoutDs satırlarını sil (data sources da güncel kuralla yeniden eklenecek)
                await using var dsDelCmd = connection.CreateCommand();
                dsDelCmd.CommandText = $"DELETE FROM [{s}].[DocLayoutDs] WHERE [LayoutId] = @Id;";
                dsDelCmd.Parameters.AddWithValue("@Id", existingLayoutId.Value);
                await dsDelCmd.ExecuteNonQueryAsync(cancellationToken);

                newLayoutId = existingLayoutId.Value;
            }
            else
            {
                await using var insCmd = connection.CreateCommand();
                insCmd.CommandText = $@"
                    INSERT INTO [{s}].[DocLayout]
                        ([Code],[Name],[DocType],[DocumentTypeId],[Description],[LayoutJson],
                         [PageW],[PageH],[MarginTop],[MarginBot],[MarginLeft],[MarginRight],
                         [OwnerUserId],[IsDefault],[IsActive],[Created],[Updated],
                         [OutputFormat],[UseAsMailTemplate])
                    VALUES
                        (@Code,@Name,@DocType,@DocTypeId,@Description,@LayoutJson,
                         @PageW,@PageH,@MarginTop,@MarginBot,@MarginLeft,@MarginRight,
                         @OwnerUserId,1,1,SYSUTCDATETIME(),SYSUTCDATETIME(),
                         @OutputFormat,@UseAsMail);
                    SELECT CAST(SCOPE_IDENTITY() AS INT);";
                insCmd.Parameters.AddWithValue("@Code",        layoutCode);
                insCmd.Parameters.AddWithValue("@Name",        layoutName);
                insCmd.Parameters.AddWithValue("@DocType",     code);
                insCmd.Parameters.AddWithValue("@DocTypeId",   docTypeId.Value);
                insCmd.Parameters.AddWithValue("@Description", layoutDesc);
                insCmd.Parameters.AddWithValue("@LayoutJson",  built.LayoutJson);
                insCmd.Parameters.AddWithValue("@PageW",       built.Meta.PageW);
                insCmd.Parameters.AddWithValue("@PageH",       built.Meta.PageH);
                insCmd.Parameters.AddWithValue("@MarginTop",   built.Meta.MarginTop);
                insCmd.Parameters.AddWithValue("@MarginBot",   built.Meta.MarginBot);
                insCmd.Parameters.AddWithValue("@MarginLeft",  built.Meta.MarginLeft);
                insCmd.Parameters.AddWithValue("@MarginRight", built.Meta.MarginRight);
                insCmd.Parameters.AddWithValue("@OwnerUserId", ownerUserId);
                insCmd.Parameters.AddWithValue("@OutputFormat", code == "mail_template" ? "email" : "pdf");
                insCmd.Parameters.AddWithValue("@UseAsMail",   code == "mail_template");
                newLayoutId = Convert.ToInt32(await insCmd.ExecuteScalarAsync(cancellationToken));
            }

            // DocLayoutDs satırı — master view binding'i (varsa)
            var dataSources = global::CalibraHub.Application.Services.DesignProvider.DefaultDocLayoutBuilder.BuildDataSources(
                layoutId: newLayoutId, docTypeCode: code, viewName: viewName, requiredKeyColumn: reqKey);
            foreach (var ds in dataSources)
            {
                await using var dsCmd = connection.CreateCommand();
                dsCmd.CommandText = $@"
                    IF NOT EXISTS (SELECT 1 FROM [{s}].[DocLayoutDs] WHERE [LayoutId]=@LayoutId AND [Alias]=@Alias)
                    INSERT INTO [{s}].[DocLayoutDs]
                        ([LayoutId],[Alias],[Role],[ViewId],[AdHocSql],[JoinOn],[ParentAlias],[Ordinal])
                    VALUES
                        (@LayoutId,@Alias,@Role,@ViewId,@AdHocSql,@JoinOn,@ParentAlias,@Ordinal);";
                dsCmd.Parameters.AddWithValue("@LayoutId",    ds.LayoutId);
                dsCmd.Parameters.AddWithValue("@Alias",       ds.Alias);
                dsCmd.Parameters.AddWithValue("@Role",        ds.Role);
                dsCmd.Parameters.AddWithValue("@ViewId",      (object?)ds.ViewId ?? DBNull.Value);
                dsCmd.Parameters.AddWithValue("@AdHocSql",    (object?)ds.AdHocSql ?? DBNull.Value);
                dsCmd.Parameters.AddWithValue("@JoinOn",      (object?)ds.JoinOn ?? DBNull.Value);
                dsCmd.Parameters.AddWithValue("@ParentAlias", (object?)ds.ParentAlias ?? DBNull.Value);
                dsCmd.Parameters.AddWithValue("@Ordinal",     ds.Ordinal);
                try
                {
                    await dsCmd.ExecuteNonQueryAsync(cancellationToken);
                }
                catch (Microsoft.Data.SqlClient.SqlException dup) when (dup.Number == 2601 || dup.Number == 2627)
                {
                    // Race: aynı (LayoutId, Alias) başka bir initializer scope tarafından
                    // (örn. Worker + Web paralel startup) eklendi. UNIQUE INDEX 'ux_DocLayoutDs_Alias'.
                    // IF NOT EXISTS check ile INSERT arasında window var; idempotent davran, atla.
                }
            }
        }
    }

    private async Task EnsureReportDataViewsAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");

        // vw_Invoice: satis teklifi verilerinden fatura gorunumu
        var views = new (string ViewName, string Body)[]
        {
            ("vw_Invoice", $"""
                SELECT q.[id], q.[DocumentNumber] AS [DocumentNumber],
                       q.[DocumentDate] AS [DocumentDate], ca.[AccountTitle] AS [CustomerName],
                       q.[ContactAddress] AS [CustomerAddress],
                       q.[CurrencyId] AS [CurrencyId], cur.[code] AS [currency],
                       q.[SubTotal] AS [SubTotal], q.[DiscountRate] AS [DiscountRate],
                       q.[DiscountAmount] AS [DiscountAmount], q.[TaxRate] AS [TaxRate],
                       q.[TaxAmount] AS [TaxAmount], q.[GrandTotal] AS [GrandTotal],
                       q.[PaymentTerms] AS [PaymentTerms], q.[notes] AS [Notes],
                       ql.[LineNo] AS [LineNo], mi.[Code] AS [MaterialCode],
                       mi.[Name] AS [MaterialName], mu.[Name] AS [UnitName],
                       ql.[Quantity] AS [Quantity], ql.[UnitPrice] AS [UnitPrice],
                       ql.[DiscountRate] AS [LineDiscountRate], ql.[LineTotal] AS [LineTotal]
                FROM [{s}].[Document] q
                LEFT JOIN [{s}].[Contact] ca ON ca.[Id] = q.[ContactId]
                LEFT JOIN [{s}].[DocumentLine] ql ON ql.[DocumentId] = q.[id]
                LEFT JOIN [{s}].[Items] mi ON mi.[Id] = ql.[ItemId]
                LEFT JOIN [{s}].[Unit] mu ON mu.[Id] = ql.[UnitId]
                LEFT JOIN [{s}].[Currency] cur ON cur.[Id] = q.[CurrencyId]
                WHERE q.[IsActive] = 1
                """),
            ("vw_DeliveryNote", $"""
                SELECT q.[id], q.[DocumentNumber] AS [DocumentNumber],
                       q.[DocumentDate] AS [DocumentDate], ca.[AccountTitle] AS [CustomerName],
                       q.[ContactAddress] AS [CustomerAddress], q.[DeliveryAddress] AS [DeliveryAddress],
                       q.[DeliveryTerms] AS [DeliveryTerms],
                       ql.[LineNo] AS [LineNo], mi.[Code] AS [MaterialCode],
                       mi.[Name] AS [MaterialName], mu.[Name] AS [UnitName],
                       ql.[Quantity] AS [Quantity]
                FROM [{s}].[Document] q
                LEFT JOIN [{s}].[Contact] ca ON ca.[Id] = q.[ContactId]
                LEFT JOIN [{s}].[DocumentLine] ql ON ql.[DocumentId] = q.[id]
                LEFT JOIN [{s}].[Items] mi ON mi.[Id] = ql.[ItemId]
                LEFT JOIN [{s}].[Unit] mu ON mu.[Id] = ql.[UnitId]
                WHERE q.[IsActive] = 1
                """),
            ("vw_ProductBarcode", $"""
                SELECT m.[Id] AS [id], m.[Code] AS [ProductCode],
                       m.[Name] AS [ProductName],
                       m.[Code] AS [BarcodeValue],
                       N'' AS [UnitName]
                FROM [{s}].[Items] m
                WHERE m.[IsActive] = 1
                """),
            ("vw_ShelfLabel", $"""
                SELECT m.[Id] AS [id], m.[Code] AS [ProductCode],
                       m.[Name] AS [ProductName],
                       m.[Code] AS [BarcodeValue],
                       N'' AS [UnitName]
                FROM [{s}].[Items] m
                WHERE m.[IsActive] = 1
                """),
            ("vw_Document", $"""
                SELECT q.[id], q.[DocumentNumber] AS [DocumentNumber],
                       q.[DocumentDate] AS [DocumentDate], q.[ValidUntil] AS [ValidUntil],
                       ca.[AccountTitle] AS [CustomerName], q.[ContactAddress] AS [CustomerAddress],
                       q.[CurrencyId] AS [CurrencyId], cur.[code] AS [currency],
                       q.[SubTotal] AS [SubTotal],
                       q.[DiscountRate] AS [DiscountRate], q.[DiscountAmount] AS [DiscountAmount],
                       q.[TaxRate] AS [TaxRate], q.[TaxAmount] AS [TaxAmount],
                       q.[GrandTotal] AS [GrandTotal],
                       q.[PaymentTerms] AS [PaymentTerms], q.[DeliveryTerms] AS [DeliveryTerms],
                       q.[DeliveryAddress] AS [DeliveryAddress], q.[notes] AS [Notes],
                       q.[status] AS [Status], q.[RevisionNo] AS [RevisionNo],
                       ql.[LineNo] AS [LineNo], mi.[Code] AS [MaterialCode],
                       mi.[Name] AS [MaterialName], mu.[Name] AS [UnitName],
                       ql.[Quantity] AS [Quantity], ql.[UnitPrice] AS [UnitPrice],
                       ql.[DiscountRate] AS [LineDiscountRate], ql.[LineTotal] AS [LineTotal]
                FROM [{s}].[Document] q
                LEFT JOIN [{s}].[Contact] ca ON ca.[Id] = q.[ContactId]
                LEFT JOIN [{s}].[DocumentLine] ql ON ql.[DocumentId] = q.[id]
                LEFT JOIN [{s}].[Items] mi ON mi.[Id] = ql.[ItemId]
                LEFT JOIN [{s}].[Unit] mu ON mu.[Id] = ql.[UnitId]
                LEFT JOIN [{s}].[Currency] cur ON cur.[Id] = q.[CurrencyId]
                WHERE q.[IsActive] = 1
                """),
            ("vw_MaterialCards", $"""
                SELECT m.[Id] AS [Id], m.[Code] AS [MaterialCode], m.[Name] AS [MaterialName],
                       m.[IsActive] AS [IsActive],
                       m.[Created] AS [CreatedDate], m.[Updated] AS [ModifiedDate]
                FROM [{s}].[Items] m
                """),
        };

        foreach (var (viewName, body) in views)
        {
            try
            {
                var commandText = $"""
                    EXEC(N'CREATE OR ALTER VIEW [{s}].[{viewName}] AS {body.Replace("'", "''")}');
                    """;
                await using var cmd = connection.CreateCommand();
                cmd.CommandText = commandText;
                await cmd.ExecuteNonQueryAsync(cancellationToken);
            }
            catch (SqlException ex)
            {
                Console.Error.WriteLine($"[DB INIT WARN] View '{viewName}' olusturulamadi: {ex.Message}");
            }
        }
    }

    private async Task EnsurePriceListTablesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s  = _schema.Replace("]", "]]");
        var sl = _schema.Replace("'", "''");

        var sql = $"""
            -- Legacy column rename: PriceGroup (group_code -> Code, group_name -> Name, is_active -> IsActive)
            IF OBJECT_ID(N'[{s}].[PriceGroup]', N'U') IS NOT NULL
            BEGIN
                IF COL_LENGTH(N'[{s}].[PriceGroup]', N'group_code') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[PriceGroup]', N'Code') IS NULL
                    EXEC sp_rename N'[{s}].[PriceGroup].[group_code]', N'Code', N'COLUMN';

                IF COL_LENGTH(N'[{s}].[PriceGroup]', N'group_name') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[PriceGroup]', N'Name') IS NULL
                    EXEC sp_rename N'[{s}].[PriceGroup].[group_name]', N'Name', N'COLUMN';

                IF COL_LENGTH(N'[{s}].[PriceGroup]', N'IsActive') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[PriceGroup]', N'IsActive') IS NULL
                    EXEC sp_rename N'[{s}].[PriceGroup].[IsActive]', N'IsActive', N'COLUMN';
                -- created_at/updated_at rename: Initialize basinda generic rename ile yapiliyor

                -- CompanyId migration: tek-sirket DB'lerde mevcut satirlari company_id=1 ile backfill et
                IF COL_LENGTH(N'[{s}].[PriceGroup]', N'CompanyId') IS NULL
                BEGIN
                    ALTER TABLE [{s}].[PriceGroup] ADD [CompanyId] INT NOT NULL CONSTRAINT [df_price_groups_company_id] DEFAULT(1);

                    -- Eski tek-kolon UNIQUE index'i drop et (yeni composite ix yerine gelecek)
                    IF EXISTS (SELECT 1 FROM sys.indexes
                               WHERE object_id = OBJECT_ID(N'[{s}].[PriceGroup]')
                                 AND name = N'ux_price_groups_code')
                        DROP INDEX [ux_price_groups_code] ON [{s}].[PriceGroup];
                END;
            END;

            IF OBJECT_ID(N'[{s}].[PriceGroup]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[PriceGroup]
                (
                    [Id]            INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_PriceGroup] PRIMARY KEY,
                    [CompanyId]     INT NOT NULL,
                    [Code]          NVARCHAR(50)  NOT NULL,
                    [Name]          NVARCHAR(150) NOT NULL,
                    [Description]   NVARCHAR(500) NULL,
                    [IsActive]      BIT NOT NULL CONSTRAINT [DF_PriceGroup_IsActive] DEFAULT(1),
                    [AllowsBuying]  BIT NOT NULL CONSTRAINT [DF_PriceGroup_AllowsBuying]  DEFAULT(1),
                    [AllowsSelling] BIT NOT NULL CONSTRAINT [DF_PriceGroup_AllowsSelling] DEFAULT(1),
                    [AllowsCost]    BIT NOT NULL CONSTRAINT [DF_PriceGroup_AllowsCost]    DEFAULT(1),
                    [IsDefault]     BIT NOT NULL CONSTRAINT [DF_PriceGroup_IsDefault]     DEFAULT(0),
                    [Created]       DATETIME NOT NULL,
                    [Updated]       DATETIME NULL
                );
            END;

            -- Composite UNIQUE: ayni sirket icinde Code unique, farkli sirketler ayni kodu kullanabilir
            IF OBJECT_ID(N'[{s}].[PriceGroup]', N'U') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.indexes
                               WHERE object_id = OBJECT_ID(N'[{s}].[PriceGroup]')
                                 AND name = N'ux_price_groups_company_code')
            BEGIN
                CREATE UNIQUE INDEX [ux_price_groups_company_code] ON [{s}].[PriceGroup]([CompanyId],[Code]);
            END;

            -- AllowsBuying/Selling/Cost kolonlari: idempotent ALTER ADD (mevcut DB'lerde
            -- default 1 ile gelir → backward compatible: tum eski gruplar tum tipleri kabul eder).
            IF OBJECT_ID(N'[{s}].[PriceGroup]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceGroup]', N'AllowsBuying') IS NULL
                ALTER TABLE [{s}].[PriceGroup] ADD [AllowsBuying]  BIT NOT NULL CONSTRAINT [df_price_groups_allows_buying]  DEFAULT(1);
            IF OBJECT_ID(N'[{s}].[PriceGroup]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceGroup]', N'AllowsSelling') IS NULL
                ALTER TABLE [{s}].[PriceGroup] ADD [AllowsSelling] BIT NOT NULL CONSTRAINT [df_price_groups_allows_selling] DEFAULT(1);
            IF OBJECT_ID(N'[{s}].[PriceGroup]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceGroup]', N'AllowsCost') IS NULL
                ALTER TABLE [{s}].[PriceGroup] ADD [AllowsCost]    BIT NOT NULL CONSTRAINT [df_price_groups_allows_cost]    DEFAULT(1);

            -- IsDefault ("Genel Liste" / fallback isareti): idempotent ALTER ADD (mevcut DB'lerde
            -- default 0 ile gelir). CompanyId basina tek default → asagida filtered unique index.
            IF OBJECT_ID(N'[{s}].[PriceGroup]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceGroup]', N'IsDefault') IS NULL
                ALTER TABLE [{s}].[PriceGroup] ADD [IsDefault] BIT NOT NULL CONSTRAINT [DF_PriceGroup_IsDefault] DEFAULT(0);

            -- ── PriceList migration: legacy denormalized columns → FK-based schema ──
            -- Eski schema: price_group_id, item_id (NULL), material_code, material_name, combination_code, combination_name, currency
            -- Yeni schema: GroupId, ItemId (NOT NULL), ConfigId (FK ItemConfiguration), CurrencyId (FK currencies)
            IF OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NOT NULL
            BEGIN
                -- 1) Eski lookup index'lerini drop et (drop edilecek kolonlara referans veriyorlar)
                IF EXISTS (SELECT 1 FROM sys.indexes
                           WHERE object_id = OBJECT_ID(N'[{s}].[PriceList]')
                             AND name = N'ix_price_list_entries_group_mat')
                    DROP INDEX [ix_price_list_entries_group_mat] ON [{s}].[PriceList];

                IF EXISTS (SELECT 1 FROM sys.indexes
                           WHERE object_id = OBJECT_ID(N'[{s}].[PriceList]')
                             AND name = N'ix_price_list_entries_lookup')
                    DROP INDEX [ix_price_list_entries_lookup] ON [{s}].[PriceList];

                -- 2) Yeni FK kolonlari ekle (nullable initially — backfill icin)
                IF COL_LENGTH(N'[{s}].[PriceList]', N'CurrencyId') IS NULL
                    ALTER TABLE [{s}].[PriceList] ADD [CurrencyId] INT NULL;

                IF COL_LENGTH(N'[{s}].[PriceList]', N'ConfigId') IS NULL
                    ALTER TABLE [{s}].[PriceList] ADD [ConfigId] INT NULL;

                -- 3) Backfill: material_code → item_id (eski item_id NULL ise Items.code lookup)
                -- NOT: Kolonlar bu migration tarafindan drop edilebilir; parse-time
                -- resolution problemini onlemek icin UPDATE'i EXEC ile sarmalayalim.
                IF COL_LENGTH(N'[{s}].[PriceList]', N'material_code') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[PriceList]', N'item_id') IS NOT NULL
                   AND OBJECT_ID(N'[{s}].[Items]', N'U') IS NOT NULL
                BEGIN
                    EXEC('
                        UPDATE p SET p.[item_id] = i.[Id]
                        FROM [{s}].[PriceList] p
                        INNER JOIN [{s}].[Items] i ON i.[Code] = p.[material_code]
                        WHERE p.[item_id] IS NULL
                    ');
                END;

                -- 4) Backfill: currency (string) → CurrencyId (currencies.id JOIN code)
                -- NOT: CurrencyId yukarida ayni batch'te ALTER ADD ile eklendi.
                -- SQL Server deferred name resolution parse-time'da kolonu goremez,
                -- bu yuzden UPDATE'i EXEC ile sarmalayip runtime'a erteliyoruz.
                IF COL_LENGTH(N'[{s}].[PriceList]', N'currency') IS NOT NULL
                   AND OBJECT_ID(N'[{s}].[Currency]', N'U') IS NOT NULL
                BEGIN
                    EXEC('
                        UPDATE p SET p.[CurrencyId] = c.[id]
                        FROM [{s}].[PriceList] p
                        INNER JOIN [{s}].[Currency] c ON c.[code] = p.[currency]
                        WHERE p.[CurrencyId] IS NULL
                    ');
                END;

                -- 5) Backfill: combination_code → ConfigId (ItemConfiguration.Id JOIN RecordCode)
                IF COL_LENGTH(N'[{s}].[PriceList]', N'combination_code') IS NOT NULL
                   AND OBJECT_ID(N'[{s}].[ItemConfiguration]', N'U') IS NOT NULL
                BEGIN
                    EXEC('
                        UPDATE p SET p.[ConfigId] = cfg.[Id]
                        FROM [{s}].[PriceList] p
                        INNER JOIN [{s}].[ItemConfiguration] cfg ON cfg.[RecordCode] = p.[combination_code]
                        WHERE p.[ConfigId] IS NULL AND p.[combination_code] IS NOT NULL
                    ');
                END;

                -- 6) Rename kalan kolonlar
                IF COL_LENGTH(N'[{s}].[PriceList]', N'price_group_id') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[PriceList]', N'GroupId') IS NULL
                    EXEC sp_rename N'[{s}].[PriceList].[price_group_id]', N'GroupId', N'COLUMN';

                IF COL_LENGTH(N'[{s}].[PriceList]', N'item_id') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[PriceList]', N'ItemId') IS NULL
                    EXEC sp_rename N'[{s}].[PriceList].[item_id]', N'ItemId', N'COLUMN';

                IF COL_LENGTH(N'[{s}].[PriceList]', N'IsActive') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[PriceList]', N'IsActive') IS NULL
                    EXEC sp_rename N'[{s}].[PriceList].[IsActive]', N'IsActive', N'COLUMN';

                -- 7) Eski denormalized kolonlari drop et
                IF COL_LENGTH(N'[{s}].[PriceList]', N'material_name') IS NOT NULL
                    ALTER TABLE [{s}].[PriceList] DROP COLUMN [material_name];

                IF COL_LENGTH(N'[{s}].[PriceList]', N'combination_name') IS NOT NULL
                    ALTER TABLE [{s}].[PriceList] DROP COLUMN [combination_name];

                IF COL_LENGTH(N'[{s}].[PriceList]', N'material_code') IS NOT NULL
                    ALTER TABLE [{s}].[PriceList] DROP COLUMN [material_code];

                IF COL_LENGTH(N'[{s}].[PriceList]', N'combination_code') IS NOT NULL
                    ALTER TABLE [{s}].[PriceList] DROP COLUMN [combination_code];

                -- currency: drop edebilmek icin once default constraint kaldirilmali
                IF COL_LENGTH(N'[{s}].[PriceList]', N'currency') IS NOT NULL
                BEGIN
                    DECLARE @df_currency NVARCHAR(200);
                    SELECT @df_currency = dc.[name]
                    FROM sys.default_constraints dc
                    INNER JOIN sys.columns c ON c.[default_object_id] = dc.[object_id]
                    WHERE c.[object_id] = OBJECT_ID(N'[{s}].[PriceList]')
                      AND c.[name] = N'currency';
                    IF @df_currency IS NOT NULL
                        EXEC('ALTER TABLE [{s}].[PriceList] DROP CONSTRAINT [' + @df_currency + ']');
                    ALTER TABLE [{s}].[PriceList] DROP COLUMN [currency];
                END;

                -- 8) valid_from → ValidFrom, valid_to → ValidTo rename
                IF COL_LENGTH(N'[{s}].[PriceList]', N'valid_from') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[PriceList]', N'ValidFrom') IS NULL
                    EXEC sp_rename N'[{s}].[PriceList].[valid_from]', N'ValidFrom', N'COLUMN';

                IF COL_LENGTH(N'[{s}].[PriceList]', N'valid_to') IS NOT NULL
                   AND COL_LENGTH(N'[{s}].[PriceList]', N'ValidTo') IS NULL
                    EXEC sp_rename N'[{s}].[PriceList].[valid_to]', N'ValidTo', N'COLUMN';

                -- 8b) created_at/updated_at rename: Initialize basinda generic rename ile yapiliyor

                -- 9) PriceType ve Price kolonlarini ekle (nullable, backfill icin)
                IF COL_LENGTH(N'[{s}].[PriceList]', N'PriceType') IS NULL
                    ALTER TABLE [{s}].[PriceList] ADD [PriceType] NVARCHAR(10) NULL;
                IF COL_LENGTH(N'[{s}].[PriceList]', N'Price') IS NULL
                    ALTER TABLE [{s}].[PriceList] ADD [Price] DECIMAL(18,4) NULL;
            END;

            -- 10) Backfill: mevcut satirlari 's' (selling) olarak isaretle (Price=selling_price)
            -- EXEC ile sarmaliyoruz cunku PriceType/Price ayni batch icinde ALTER ADD'lendi.
            IF OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceList]', N'selling_price') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceList]', N'PriceType') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceList]', N'Price') IS NOT NULL
            BEGIN
                EXEC('
                    UPDATE [{s}].[PriceList]
                    SET [PriceType] = N''s'', [Price] = [selling_price]
                    WHERE [PriceType] IS NULL OR [Price] IS NULL
                ');
            END;

            -- 10b) Legacy data conversion: 'Buying'/'Selling' string'lerini 'b'/'s' kisaltmasiyla degistir
            -- (Onceki migration sirasinda PascalCase ile yazilmis kayitlar varsa)
            IF OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceList]', N'PriceType') IS NOT NULL
            BEGIN
                UPDATE [{s}].[PriceList] SET [PriceType] = N'b' WHERE [PriceType] = N'Buying';
                UPDATE [{s}].[PriceList] SET [PriceType] = N's' WHERE [PriceType] = N'Selling';
                -- Tek harf de buyuk yazilmis olabilir ('B','S','M') — hepsini lowercase'e indir.
                -- COLLATE BIN ile karsilastirma yapiyoruz cunku default CI collation'da
                -- 'B' = LOWER('B') TRUE doner; sadece BIN'de gercek buyuk/kucuk farki anlasilir.
                -- (idempotent; uygulama hep lowercase saklar, eski insert'lerden kalanlar duzelir.)
                UPDATE [{s}].[PriceList] SET [PriceType] = LOWER([PriceType])
                    WHERE [PriceType] COLLATE Latin1_General_BIN
                        <> LOWER([PriceType]) COLLATE Latin1_General_BIN;
            END;

            -- 11) Her 's' (selling) satiri icin paralel 'b' (buying) satiri ekle (Price=buying_price)
            IF OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceList]', N'buying_price') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceList]', N'PriceType') IS NOT NULL
            BEGIN
                EXEC('
                    INSERT INTO [{s}].[PriceList]
                        ([GroupId],[ItemId],[ConfigId],[CurrencyId],[PriceType],[Price],
                         [ValidFrom],[ValidTo],[IsActive],[Created],[Updated])
                    SELECT [GroupId],[ItemId],[ConfigId],[CurrencyId],N''b'',[buying_price],
                           [ValidFrom],[ValidTo],[IsActive],GETDATE(),GETDATE()
                    FROM [{s}].[PriceList]
                    WHERE [PriceType] = N''s''
                      AND NOT EXISTS (
                          SELECT 1 FROM [{s}].[PriceList] b
                          WHERE b.[GroupId] = [{s}].[PriceList].[GroupId]
                            AND b.[ItemId] = [{s}].[PriceList].[ItemId]
                            AND ISNULL(b.[ConfigId], -1) = ISNULL([{s}].[PriceList].[ConfigId], -1)
                            AND b.[CurrencyId] = [{s}].[PriceList].[CurrencyId]
                            AND b.[ValidFrom] = [{s}].[PriceList].[ValidFrom]
                            AND b.[PriceType] = N''b''
                      )
                ');
            END;

            -- 12) buying_price ve selling_price drop (default constraint dahil)
            IF OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceList]', N'buying_price') IS NOT NULL
            BEGIN
                DECLARE @df_buy NVARCHAR(200);
                SELECT @df_buy = dc.[name]
                FROM sys.default_constraints dc
                INNER JOIN sys.columns c ON c.[default_object_id] = dc.[object_id]
                WHERE c.[object_id] = OBJECT_ID(N'[{s}].[PriceList]')
                  AND c.[name] = N'buying_price';
                IF @df_buy IS NOT NULL
                    EXEC('ALTER TABLE [{s}].[PriceList] DROP CONSTRAINT [' + @df_buy + ']');
                ALTER TABLE [{s}].[PriceList] DROP COLUMN [buying_price];
            END;

            IF OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[PriceList]', N'selling_price') IS NOT NULL
            BEGIN
                DECLARE @df_sell NVARCHAR(200);
                SELECT @df_sell = dc.[name]
                FROM sys.default_constraints dc
                INNER JOIN sys.columns c ON c.[default_object_id] = dc.[object_id]
                WHERE c.[object_id] = OBJECT_ID(N'[{s}].[PriceList]')
                  AND c.[name] = N'selling_price';
                IF @df_sell IS NOT NULL
                    EXEC('ALTER TABLE [{s}].[PriceList] DROP CONSTRAINT [' + @df_sell + ']');
                ALTER TABLE [{s}].[PriceList] DROP COLUMN [selling_price];
            END;

            IF OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[PriceList]
                (
                    [Id]          INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_PriceList] PRIMARY KEY,
                    [GroupId]     INT NOT NULL,
                    [ItemId]      INT NOT NULL,
                    [ConfigId]    INT NULL,
                    [CurrencyId]  INT NOT NULL,
                    [PriceType]   NVARCHAR(10)  NOT NULL,
                    [Price]       DECIMAL(18,4) NOT NULL CONSTRAINT [DF_PriceList_Price] DEFAULT(0),
                    [ValidFrom]   DATE NOT NULL,
                    [ValidTo]     DATE NULL,
                    [IsActive]    BIT NOT NULL CONSTRAINT [DF_PriceList_IsActive] DEFAULT(1),
                    [Created]     DATETIME NOT NULL,
                    [Updated]     DATETIME NULL,
                    CONSTRAINT [FK_PriceList_PriceGroup]
                        FOREIGN KEY ([GroupId]) REFERENCES [{s}].[PriceGroup]([Id])
                );
            END;

            -- Lookup index (yeni schema'ya gore: PriceType ekli)
            IF OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.indexes
                               WHERE object_id = OBJECT_ID(N'[{s}].[PriceList]')
                                 AND name = N'ix_pricelist_lookup')
            BEGIN
                CREATE INDEX [ix_pricelist_lookup]
                    ON [{s}].[PriceList]([GroupId],[ItemId],[ConfigId],[PriceType],[ValidFrom]);
            END;

            -- UNIQUE filtered index — aynı (Group + Item + Config + Currency + PriceType + ValidFrom)
            -- kombinasyonu ile ikinci AKTİF kayıt oluşturulamaz. Soft-deleted (IsActive=0)
            -- satırlar haricte tutulur (filtre) — eski iptal edilmiş kayıtlar yeni girişi engellemez.
            -- TRY blok: mevcut duplicate aktif kayıtlar varsa CREATE başarısız olur ama startup
            -- bloklanmaz (kullanıcı manuel temizler, sonraki açılışta migration tekrar dener).
            IF OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.indexes
                               WHERE object_id = OBJECT_ID(N'[{s}].[PriceList]')
                                 AND name = N'ux_pricelist_unique_active')
            BEGIN
                BEGIN TRY
                    CREATE UNIQUE INDEX [ux_pricelist_unique_active]
                        ON [{s}].[PriceList]([GroupId],[ItemId],[ConfigId],[CurrencyId],[PriceType],[ValidFrom])
                        WHERE [IsActive] = 1;
                END TRY
                BEGIN CATCH
                    -- Mevcut duplicate'ler nedeniyle index olusturulamadi.
                    -- Loglamak yerine sessiz gec — migration startup'i kirmasin.
                    PRINT 'WARN: ux_pricelist_unique_active olusturulamadi, mevcut duplicate kayitlar var.';
                END CATCH
            END;
            """;

        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);

        // ── Batch 2 (DDL): IsDefault filtered unique index ──
        // Genel fiyat listesi OTOMATIK olusturulmaz/atanmaz — kullanici, Fiyat Listesi
        // ekranindan ("Genel Liste Yap") mevcut listelerinden birini isaretler (kod eslesmesi
        // YOK). Bu index yalniz "CompanyId basina tek IsDefault=1" tekilligini garanti eder.
        // IsDefault kolonu Batch 1'de eklendi; AYRI ExecuteNonQuery = ayri batch oldugu icin
        // parse-time'da kolon artik semada (deferred name resolution guvenli).
        var defaultIndexSql = $"""
            IF OBJECT_ID(N'[{s}].[PriceGroup]', N'U') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.indexes
                               WHERE object_id = OBJECT_ID(N'[{s}].[PriceGroup]')
                                 AND name = N'UX_PriceGroup_Company_Default')
            BEGIN
                BEGIN TRY
                    CREATE UNIQUE INDEX [UX_PriceGroup_Company_Default]
                        ON [{s}].[PriceGroup]([CompanyId]) WHERE [IsDefault] = 1;
                END TRY
                BEGIN CATCH
                    PRINT 'WARN: UX_PriceGroup_Company_Default olusturulamadi, birden fazla default var.';
                END CATCH
            END;

            -- Onceki surum otomatik 'GENEL' kodlu "Genel Liste" grubu olusturuyordu; bu
            -- yaklasim birakildi (genel liste kullanici tarafindan isaretlenir). Otomatik
            -- olusan BOS (hic fiyat kaydi olmayan) GENEL gruplarini temizle — kullanici o
            -- gruba fiyat girmisse DOKUNMA. Idempotent: eslesen grup yoksa no-op.
            IF OBJECT_ID(N'[{s}].[PriceGroup]', N'U') IS NOT NULL
               AND OBJECT_ID(N'[{s}].[PriceList]', N'U') IS NOT NULL
                DELETE pg FROM [{s}].[PriceGroup] pg
                WHERE pg.[Code] = N'GENEL' AND pg.[Name] = N'Genel Liste'
                  AND NOT EXISTS (SELECT 1 FROM [{s}].[PriceList] pl WHERE pl.[GroupId] = pg.[Id]);
            """;
        await using var cmdDefault = connection.CreateCommand();
        cmdDefault.CommandText = defaultIndexSql;
        await cmdDefault.ExecuteNonQueryAsync(cancellationToken);
    }

    private async Task EnsureFormsTableAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        // ── Batch 1: DDL (CREATE + ALTER) ───────────────────────────────
        // DDL ve DML'i AYNI batch icinde yapamayiz! SQL Server deferred name
        // resolution parse-time'da kolonlari kontrol eder; BaseTable ALTER ile
        // eklendigi halde sonraki UPDATE'te referansi parser'i patlatir.
        // Cozum: Iki ayri ExecuteNonQueryAsync cagrisi.
        var ddlSql = """
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NULL
            BEGIN
                CREATE TABLE dbo.Forms
                (
                    [Id]             INT            NOT NULL IDENTITY(1,1) PRIMARY KEY,
                    [FormCode]       NVARCHAR(50)   NOT NULL,
                    [FormName]       NVARCHAR(200)  NOT NULL,
                    [Module]         NVARCHAR(50)   NOT NULL,
                    [SubModule]      NVARCHAR(50)   NULL,
                    [SortOrder]      INT            NOT NULL DEFAULT(0),
                    [IsActive]       BIT            NOT NULL DEFAULT(1),
                    [BaseTable]      NVARCHAR(120)  NULL,
                    [BaseRecordKey]  NVARCHAR(60)   NULL
                );
                CREATE UNIQUE INDEX [ux_forms_code] ON dbo.Forms([FormCode]);
            END;

            -- Faz H: Flattened View altyapisi — BaseTable + BaseRecordKey kolonlari
            -- Idempotent: kolonlar yoksa eklenir. Bu kolonlar, WidgetTra'nin pivot
            -- edildigi dinamik view'un (v_Flat_<FormCode>) base tablosuna
            -- hangi SQL tablosunun bagli oldugunu tanimlar.
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'BaseTable') IS NULL
            BEGIN
                ALTER TABLE dbo.Forms ADD [BaseTable] NVARCHAR(120) NULL;
            END;
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'BaseRecordKey') IS NULL
            BEGIN
                ALTER TABLE dbo.Forms ADD [BaseRecordKey] NVARCHAR(60) NULL;
            END;

            -- Faz I: Master-Detail entegrasyon — LinesFormCode + LinesParentColumn
            -- Bir "kok form" (orn. SALES_ORDER_NEW) ile baglı kalem form'unu (SALES_ORDER_LINES)
            -- iliskilendirir. Wizard Step 1'de tek form secince kalem form'u otomatik kesfedilir,
            -- entegrasyon runner'i her iki form'un verilerini birlestirip tek body uretir.
            -- NULL = tek seviyeli form (geriye uyum, mevcut tek-form entegrasyonlari calismaya devam eder).
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'LinesFormCode') IS NULL
            BEGIN
                ALTER TABLE dbo.Forms ADD [LinesFormCode] NVARCHAR(50) NULL;
            END;
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'LinesParentColumn') IS NULL
            BEGIN
                ALTER TABLE dbo.Forms ADD [LinesParentColumn] NVARCHAR(100) NULL;
            END;

            -- Faz N: Form metadata hub — UI yonlendirme + entegrasyon ortak kanalı.
            -- Yeni belge tipi eklemek icin sadece bu kolonlari Forms seed'inde doldurmak yeterli.
            -- ListUrl    : save/delete sonrasi geri donulecek liste sayfasi
            -- NewUrl     : "Yeni X" buton URL'i
            -- EditUrl    : edit sayfasi sablonu — runtime "{id}" placeholder'i resolve edilir
            -- Icon       : Lucide icon (ShoppingCart, FileText, Truck, vb.)
            -- IconColor  : tema renk anahtari (emerald/indigo/amber/rose/slate/blue/violet)
            -- IsTransferable : entegrasyon Wizard'da picker'da goster + "ERP'ye Aktar" butonu aktif
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'ListUrl') IS NULL
                ALTER TABLE dbo.Forms ADD [ListUrl] NVARCHAR(200) NULL;
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'NewUrl') IS NULL
                ALTER TABLE dbo.Forms ADD [NewUrl] NVARCHAR(200) NULL;
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'EditUrl') IS NULL
                ALTER TABLE dbo.Forms ADD [EditUrl] NVARCHAR(200) NULL;
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'Icon') IS NULL
                ALTER TABLE dbo.Forms ADD [Icon] NVARCHAR(50) NULL;
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'IconColor') IS NULL
                ALTER TABLE dbo.Forms ADD [IconColor] NVARCHAR(20) NULL;
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'IsTransferable') IS NULL
                ALTER TABLE dbo.Forms
                    ADD [IsTransferable] BIT NOT NULL CONSTRAINT [DF_Forms_IsTransferable] DEFAULT(1);

            -- 2026-05-21: BaseTableFilter — Aktarim Kuyrugu (ve diger base-table tabanli
            -- listeler) icin opsiyonel WHERE fragmani. Iki form ayni BaseTable'a baglandiginda
            -- (orn. SALES_QUOTE_EDIT + SALES_ORDER_EDIT ikisi de dbo.Document) belge tipiyle
            -- ayristirmak gerekir. Format: "[DocumentTypeId] IN (5)" gibi tek bir predicate;
            -- query'de "AND ({BaseTableFilter})" olarak append edilir. NULL = filtresiz.
            IF OBJECT_ID(N'dbo.Forms', N'U') IS NOT NULL
               AND COL_LENGTH(N'dbo.Forms', N'BaseTableFilter') IS NULL
                ALTER TABLE dbo.Forms ADD [BaseTableFilter] NVARCHAR(500) NULL;

            -- Faz 2 (2026-06-09): Menu-driven kolonlar
            -- IsMenuItem: bu form sol menüde bir leaf node'a karşılık geliyorsa 1
            -- MenuKey: MenuDefinition.MenuNode.Key ile eşleşir (ör. 'logistics.materials')
            -- MenuLabel/En: TR/EN menü etiketi
            -- MenuGroupKey: parent grup Key'i (ör. 'logistics.fixed')
            -- MenuGroupName: parent grup TR adı (ör. 'Sabit Tanımlamalar')
            -- MenuGroupIcon: parent grup ikonu (Lucide icon adı)
            -- MenuGroupSortOrder: grup sıralama (menüdeki sıra)
            -- MenuSortOrder: grup içindeki item sırası
            -- MenuMatchPath: Shell tab eşleştirme prefix'i
            -- AdminOnly: true ise sadece admin görür (bu sütun DB'de metadata; kontrol MenuService'te)
            IF COL_LENGTH(N'dbo.Forms', N'IsMenuItem') IS NULL
                ALTER TABLE dbo.Forms ADD [IsMenuItem] BIT NOT NULL CONSTRAINT [DF_Forms_IsMenuItem] DEFAULT(0);
            IF COL_LENGTH(N'dbo.Forms', N'MenuKey') IS NULL
                ALTER TABLE dbo.Forms ADD [MenuKey] NVARCHAR(80) NULL;
            IF COL_LENGTH(N'dbo.Forms', N'MenuLabel') IS NULL
                ALTER TABLE dbo.Forms ADD [MenuLabel] NVARCHAR(100) NULL;
            IF COL_LENGTH(N'dbo.Forms', N'MenuLabelEn') IS NULL
                ALTER TABLE dbo.Forms ADD [MenuLabelEn] NVARCHAR(100) NULL;
            IF COL_LENGTH(N'dbo.Forms', N'MenuGroupKey') IS NULL
                ALTER TABLE dbo.Forms ADD [MenuGroupKey] NVARCHAR(80) NULL;
            IF COL_LENGTH(N'dbo.Forms', N'MenuGroupName') IS NULL
                ALTER TABLE dbo.Forms ADD [MenuGroupName] NVARCHAR(60) NULL;
            IF COL_LENGTH(N'dbo.Forms', N'MenuGroupIcon') IS NULL
                ALTER TABLE dbo.Forms ADD [MenuGroupIcon] NVARCHAR(50) NULL;
            IF COL_LENGTH(N'dbo.Forms', N'MenuGroupSortOrder') IS NULL
                ALTER TABLE dbo.Forms ADD [MenuGroupSortOrder] INT NULL;
            IF COL_LENGTH(N'dbo.Forms', N'MenuSortOrder') IS NULL
                ALTER TABLE dbo.Forms ADD [MenuSortOrder] INT NULL;
            IF COL_LENGTH(N'dbo.Forms', N'MenuMatchPath') IS NULL
                ALTER TABLE dbo.Forms ADD [MenuMatchPath] NVARCHAR(200) NULL;
            IF COL_LENGTH(N'dbo.Forms', N'AdminOnly') IS NULL
                ALTER TABLE dbo.Forms ADD [AdminOnly] BIT NOT NULL CONSTRAINT [DF_Forms_AdminOnly] DEFAULT(0);
            IF COL_LENGTH(N'dbo.Forms', N'IsWidgetForm') IS NULL
                ALTER TABLE dbo.Forms ADD [IsWidgetForm] BIT NOT NULL CONSTRAINT [DF_Forms_IsWidgetForm] DEFAULT(1);
            IF NOT EXISTS (
                SELECT 1 FROM sys.indexes
                WHERE name = N'IX_Forms_MenuKey' AND object_id = OBJECT_ID(N'dbo.Forms'))
                EXEC(N'CREATE UNIQUE INDEX [IX_Forms_MenuKey] ON dbo.Forms([MenuKey]) WHERE [MenuKey] IS NOT NULL');
            """;
        await using (var ddlCmd = connection.CreateCommand())
        {
            ddlCmd.CommandText = ddlSql;
            await ddlCmd.ExecuteNonQueryAsync(cancellationToken);
