            ("AUDIT_LOG",           "İşlem Logları",                    "Ayarlar",              null,                       985,  false), // dosya tabanlı audit trail izleme ekranı

            // ── Genel (yetki kapsamına sonradan alınanlar — 2026-07-06) ─────
            ("CALENDAR",            "Takvim",                           "Genel",                null,                       15,   false),
