    /// <summary>
    /// Mevcut FastReport VIEW'larini (vw_Invoice, vw_DeliveryNote vb.) RptView registry'ye idempotent olarak seed eder.
    /// Her VIEW icin: 1) RptView row'u, 2) INFORMATION_SCHEMA'dan kesfedilen RptViewCol satirlari (varsayilan
    /// IsFilterable/IsGroupable/IsAggregatable heuristigi ile), 3) SystemAdmin icin CanQuery=CanDesign=1 RptViewRole satiri.
    /// </summary>
    private async Task SeedRptViewRegistryAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");

        // Migration: SALES_QUOTE eskiden vw_Document'a point ediyordu; yeni vw_ReportDocument kullanilacak.
        await using (var migCmd = connection.CreateCommand())
        {
            migCmd.CommandText = $"""
                UPDATE [{s}].[RptView]
                   SET [SqlObjectName] = 'vw_ReportDocument'
                 WHERE [Code] = 'SALES_QUOTE' AND [SqlObjectName] = 'vw_Document';
                """;
            await migCmd.ExecuteNonQueryAsync(cancellationToken);
        }

        var seedViews = new (string Code, string Name, string SqlObjectName, string Description)[]
        {
            ("INVOICE",       "Fatura",         "vw_Invoice",        "Satis faturasi VIEW'i"),
            ("DELIVERY_NOTE", "Irsaliye",       "vw_DeliveryNote",   "Sevk irsaliyesi VIEW'i"),
            ("PROD_BARCODE",  "Urun Barkodu",   "vw_ProductBarcode", "Urun barkod etiketi VIEW'i"),
            ("SHELF_LABEL",   "Raf Etiketi",    "vw_ShelfLabel",     "Depo raf etiketi VIEW'i"),
            ("SALES_QUOTE",   "Satis Teklifi",  "vw_ReportDocument", "Satis teklifi VIEW'i")
        };

        foreach (var (code, name, sqlObj, desc) in seedViews)
        {
            // 1) RptView row
            await using var mergeCmd = connection.CreateCommand();
            mergeCmd.CommandText = $"""
                MERGE [{s}].[RptView] AS T
                USING (SELECT @Code AS Code) AS S ON T.[Code] = S.Code
                WHEN NOT MATCHED THEN
                    INSERT ([Code],[Name],[SqlObjectName],[Description],[IsActive])
                    VALUES (@Code,@Name,@SqlObj,@Desc,1);
                SELECT [Id] FROM [{s}].[RptView] WHERE [Code] = @Code;
                """;
            mergeCmd.Parameters.AddWithValue("@Code", code);
            mergeCmd.Parameters.AddWithValue("@Name", name);
            mergeCmd.Parameters.AddWithValue("@SqlObj", sqlObj);
            mergeCmd.Parameters.AddWithValue("@Desc", desc);
            var viewIdObj = await mergeCmd.ExecuteScalarAsync(cancellationToken);
            if (viewIdObj is null) continue;
            var viewId = Convert.ToInt32(viewIdObj);

            // 2) RptViewRole: SystemAdmin tam yetki
            await using var roleCmd = connection.CreateCommand();
            roleCmd.CommandText = $"""
                IF NOT EXISTS (SELECT 1 FROM [{s}].[RptViewRole] WHERE [ViewId] = @ViewId AND [Role] = 1)
                BEGIN
                    INSERT INTO [{s}].[RptViewRole] ([ViewId],[Role],[CanQuery],[CanDesign])
                    VALUES (@ViewId, 1, 1, 1);
                END;
                """;
            roleCmd.Parameters.AddWithValue("@ViewId", viewId);
            await roleCmd.ExecuteNonQueryAsync(cancellationToken);

            // 3) RptViewCol seed — sadece RptViewCol bos ise (tekrar seed bozmasin)
            await using var colCheckCmd = connection.CreateCommand();
            colCheckCmd.CommandText = $"SELECT COUNT(1) FROM [{s}].[RptViewCol] WHERE [ViewId] = @ViewId;";
            colCheckCmd.Parameters.AddWithValue("@ViewId", viewId);
            var existingCols = Convert.ToInt32(await colCheckCmd.ExecuteScalarAsync(cancellationToken));
            if (existingCols > 0) continue;

            await using var discoverCmd = connection.CreateCommand();
            discoverCmd.CommandText = """
                SELECT COLUMN_NAME, DATA_TYPE, IS_NULLABLE, ORDINAL_POSITION
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE TABLE_SCHEMA = @Schema AND TABLE_NAME = @ViewName
                ORDER BY ORDINAL_POSITION;
                """;
            discoverCmd.Parameters.AddWithValue("@Schema", _schema);
            discoverCmd.Parameters.AddWithValue("@ViewName", sqlObj);

            var discovered = new List<(string ColName, string SqlType, int Ordinal)>();
            await using (var rdr = await discoverCmd.ExecuteReaderAsync(cancellationToken))
            {
                while (await rdr.ReadAsync(cancellationToken))
                {
                    discovered.Add((rdr.GetString(0), rdr.GetString(1), rdr.GetInt32(3)));
                }
            }

            foreach (var (colName, sqlType, ordinal) in discovered)
            {
                var (dataType, isNumeric, isDateish) = MapSqlType(sqlType);
                await using var insertColCmd = connection.CreateCommand();
                insertColCmd.CommandText = $"""
                    INSERT INTO [{s}].[RptViewCol]
                        ([ViewId],[ColName],[DisplayName],[DataType],[IsFilterable],[IsGroupable],
                         [IsAggregatable],[DefaultAggregate],[Ordinal],[ContextBinding])
                    VALUES
                        (@ViewId,@ColName,@Display,@DataType,@Filt,@Grp,@Agg,@Def,@Ord,@Ctx);
                    """;
                insertColCmd.Parameters.AddWithValue("@ViewId", viewId);
                insertColCmd.Parameters.AddWithValue("@ColName", colName);
                insertColCmd.Parameters.AddWithValue("@Display", colName);
                insertColCmd.Parameters.AddWithValue("@DataType", (byte)dataType);
                insertColCmd.Parameters.AddWithValue("@Filt", true);
                insertColCmd.Parameters.AddWithValue("@Grp", isDateish || (!isNumeric && dataType == 1));
                insertColCmd.Parameters.AddWithValue("@Agg", isNumeric);
                insertColCmd.Parameters.AddWithValue("@Def",
                    isNumeric ? (object)(byte)3 /* Sum */ : DBNull.Value);
                insertColCmd.Parameters.AddWithValue("@Ord", ordinal);
                insertColCmd.Parameters.AddWithValue("@Ctx", (byte)InferContextBinding(colName));
                await insertColCmd.ExecuteNonQueryAsync(cancellationToken);
            }
        }
    }

    // DataType enum: 1=String, 2=Integer, 3=Decimal, 4=Date, 5=DateTime, 6=Boolean
    private static (byte DataType, bool IsNumeric, bool IsDateish) MapSqlType(string sqlType) =>
        sqlType.ToLowerInvariant() switch
        {
            "int" or "smallint" or "tinyint" or "bigint" => ((byte)2, true, false),
            "decimal" or "numeric" or "money" or "smallmoney" or "float" or "real" => ((byte)3, true, false),
            "date" => ((byte)4, false, true),
            "datetime" or "datetime2" or "smalldatetime" or "datetimeoffset" => ((byte)5, false, true),
            "bit" => ((byte)6, false, false),
            _ => ((byte)1, false, false)
        };

    // ContextBinding enum: 0=None, 1=CompanyId, 2=UserId, 3=OwnerUserId
    private static byte InferContextBinding(string colName) =>
        colName.ToLowerInvariant() switch
        {
            "companyid" or "company_id" => 1,
            "userid" or "user_id" => 2,
            "owneruserid" or "owner_user_id" or "createdby" or "created_by" => 3,
            _ => 0
        };

    /// <summary>
    /// Tum tablolardaki Updated kolonlarini nullable yapar. Ilk INSERT sonrasi UPDATE
    /// yapilmadigi surece NULL kalabilir; sadece guncellemede deger atanir.
    /// Idempotent — already nullable ise skip eder.
    /// </summary>
    private async Task MakeUpdatedNullableAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var sql = $"""
            DECLARE @schemaName NVARCHAR(128) = N'{s}';
            DECLARE @t NVARCHAR(200);
            DECLARE @sqlAlter NVARCHAR(500);

            DECLARE updated_nullable_cursor CURSOR FAST_FORWARD FOR
                SELECT t.[name]
                FROM sys.tables t
                INNER JOIN sys.schemas sch ON sch.[schema_id] = t.[schema_id]
                INNER JOIN sys.columns c ON c.[object_id] = t.[object_id]
                WHERE sch.[name] = @schemaName
                  AND c.[name] = N'Updated'
                  AND c.[is_nullable] = 0;

            OPEN updated_nullable_cursor;
            FETCH NEXT FROM updated_nullable_cursor INTO @t;
            WHILE @@FETCH_STATUS = 0
            BEGIN
                SET @sqlAlter = N'ALTER TABLE ' + QUOTENAME(@schemaName) + N'.' + QUOTENAME(@t)
                              + N' ALTER COLUMN [Updated] DATETIME NULL';
                EXEC (@sqlAlter);
                FETCH NEXT FROM updated_nullable_cursor INTO @t;
            END;

            CLOSE updated_nullable_cursor;
            DEALLOCATE updated_nullable_cursor;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    /// <summary>
    /// Tum tablolardaki created_at/updated_at kolonlarini Created/Updated'e donusturur (idempotent).
    /// Yeni install'larda no-op (kolonlar zaten yeni adda); mevcut DB'lerde tek seferde rename eder.
    /// String'lerde parantezsiz isim kullanilir, boylece Initializer SQL'inde [Created]/[Updated]
    /// replace_all ile bu metoda etki etmez.
    /// </summary>
    private async Task RenameLegacyTimestampColumnsAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var sql = $"""
            DECLARE @schemaName NVARCHAR(128) = N'{s}';
            DECLARE @t NVARCHAR(200);
            DECLARE @tblId INT;
            DECLARE @rn NVARCHAR(400);
            DECLARE @oldC NVARCHAR(50) = N'CreatedAt';
            DECLARE @oldU NVARCHAR(50) = N'updated_at';

            DECLARE rename_cursor CURSOR FAST_FORWARD FOR
                SELECT t.[name] FROM sys.tables t
                INNER JOIN sys.schemas sch ON sch.[schema_id] = t.[schema_id]
                WHERE sch.[name] = @schemaName AND (
                    EXISTS (SELECT 1 FROM sys.columns c WHERE c.[object_id] = t.[object_id] AND c.[name] = @oldC)
                 OR EXISTS (SELECT 1 FROM sys.columns c WHERE c.[object_id] = t.[object_id] AND c.[name] = @oldU)
                );

            OPEN rename_cursor;
            FETCH NEXT FROM rename_cursor INTO @t;
            WHILE @@FETCH_STATUS = 0
            BEGIN
                SET @tblId = OBJECT_ID(QUOTENAME(@schemaName) + N'.' + QUOTENAME(@t));
                IF @tblId IS NOT NULL
                BEGIN
                    IF EXISTS (SELECT 1 FROM sys.columns c WHERE c.[object_id] = @tblId AND c.[name] = @oldC)
                       AND NOT EXISTS (SELECT 1 FROM sys.columns c WHERE c.[object_id] = @tblId AND c.[name] = N'Created')
                    BEGIN
                        SET @rn = QUOTENAME(@schemaName) + N'.' + QUOTENAME(@t) + N'.' + QUOTENAME(@oldC);
                        EXEC sp_rename @objname = @rn, @newname = N'Created', @objtype = N'COLUMN';
                    END;

                    IF EXISTS (SELECT 1 FROM sys.columns c WHERE c.[object_id] = @tblId AND c.[name] = @oldU)
                       AND NOT EXISTS (SELECT 1 FROM sys.columns c WHERE c.[object_id] = @tblId AND c.[name] = N'Updated')
                    BEGIN
                        SET @rn = QUOTENAME(@schemaName) + N'.' + QUOTENAME(@t) + N'.' + QUOTENAME(@oldU);
                        EXEC sp_rename @objname = @rn, @newname = N'Updated', @objtype = N'COLUMN';
                    END;
                END;
                FETCH NEXT FROM rename_cursor INTO @t;
            END;

            CLOSE rename_cursor;
            DEALLOCATE rename_cursor;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    /// <summary>
    /// Faz 0 — uretim modulu icin ortak altyapi tablolari:
    /// - CompanyParameter: sirket bazli form/modul parametreleri
    /// - Numerator: belge sayaclari (atomik MERGE ile)
    /// - StockMovement: stok hareketi cekirdek tablosu (Faz 4'te genisletilecek)
    /// Idempotent — her startup'ta guvenle calisir.
    /// </summary>
    private async Task EnsureProductionInfrastructureAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var schemaForSql = _schema.Replace("]", "]]");
        var sql = $@"
            -- ===== CompanyParameter =====
            IF OBJECT_ID(N'[{schemaForSql}].[CompanyParameter]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[CompanyParameter]
                (
                    [Id]         INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_CompanyParameter] PRIMARY KEY,
                    [CompanyId]  INT NOT NULL,
                    [FormCode]   VARCHAR(40) NOT NULL,
                    [ParamKey]   VARCHAR(60) NOT NULL,
                    [ParamValue] NVARCHAR(400) NULL,
                    [DataType]   TINYINT NOT NULL CONSTRAINT [df_CompanyParameter_DataType] DEFAULT(1),
                    [CreatedById]  INT NULL,
                    [Created]    DATETIME NOT NULL CONSTRAINT [DF_CompanyParameter_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById]  INT NULL,
                    [Updated]    DATETIME NULL,
                    CONSTRAINT [CK_CompanyParameter_DataType] CHECK ([DataType] BETWEEN 1 AND 5)
                );
                CREATE UNIQUE INDEX [ux_CompanyParameter_Comp_Form_Key]
                    ON [{schemaForSql}].[CompanyParameter]([CompanyId], [FormCode], [ParamKey]);
            END;

            -- Migration: [CreatedBy]/[UpdatedBy] NVARCHAR -> [CreatedById]/[UpdatedById] INT
            IF OBJECT_ID(N'[{schemaForSql}].[CompanyParameter]', N'U') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[CompanyParameter]') AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[CompanyParameter] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{schemaForSql}].[CompanyParameter] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[CompanyParameter]') AND name = N'CreatedById')
                    ALTER TABLE [{schemaForSql}].[CompanyParameter] ADD [CreatedById] INT NULL;
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[CompanyParameter]') AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[CompanyParameter] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{schemaForSql}].[CompanyParameter] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[CompanyParameter]') AND name = N'UpdatedById')
                    ALTER TABLE [{schemaForSql}].[CompanyParameter] ADD [UpdatedById] INT NULL;
                -- UpdatedAt -> Updated: repo [Updated] kolonunu bekler; eski DB'lerde [UpdatedAt] olabilir.
                -- Guard'li sp_rename — [Updated] zaten varsa atlanir (yeni DB'ler etkilenmez).
                IF COL_LENGTH(N'[{schemaForSql}].[CompanyParameter]', N'UpdatedAt') IS NOT NULL
                   AND COL_LENGTH(N'[{schemaForSql}].[CompanyParameter]', N'Updated') IS NULL
                    EXEC sp_rename N'{schemaForSql}.CompanyParameter.UpdatedAt', N'Updated', 'COLUMN';
            END

            -- ===== Numerator =====
            IF OBJECT_ID(N'[{schemaForSql}].[Numerator]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[Numerator]
                (
                    [Id]           INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_Numerator] PRIMARY KEY,
                    [CompanyId]    INT NOT NULL,
                    [EntityType]   VARCHAR(40) NOT NULL,
                    [CurrentValue] INT NOT NULL CONSTRAINT [df_Numerator_CurrentValue] DEFAULT(0),
                    [LastResetAt]  DATETIME NULL
                );
                CREATE UNIQUE INDEX [ux_Numerator_Comp_Entity]
                    ON [{schemaForSql}].[Numerator]([CompanyId], [EntityType]);
            END;

            -- ===== StockMovement — 2026-07-02 emekliye ayrildi =====
            -- Stok hareketi konsolidasyonu: hicbir yerden INSERT almiyordu (sifir veri,
            -- ERP entegrasyon icin tasarlanmis ama hic bagli degildi). Yerini DocumentLine
            -- (MovementType/FromLocationId/UnitCost/LotNo kolonlari) aldi.
            IF OBJECT_ID(N'[{schemaForSql}].[StockMovement]', N'U') IS NOT NULL
                DROP TABLE [{schemaForSql}].[StockMovement];

            -- ===== WorkOrder (Faz 1: 1 mamul/emir) =====
            -- 2026-07-02: Document companion modeli (ArgeProject deseni). Belge kimligi
            -- (numara/tarih/revizyon/notlar) Document'ta tutulur; WorkOrder sadece
            -- production-specific alanlari + DocumentId (UNIQUE FK) tasir.
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[WorkOrder]
                (
                    [Id]                  INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_WorkOrder] PRIMARY KEY,
                    [CompanyId]           INT NOT NULL,
                    [DocumentId]          INT NOT NULL,
                    [ItemId]              INT NOT NULL,
                    [ConfigId]            INT NULL,
                    [PlannedQuantity]     DECIMAL(18,4) NOT NULL CONSTRAINT [df_WorkOrder_PlannedQty] DEFAULT(0),
                    [ProducedQuantity]    DECIMAL(18,4) NOT NULL CONSTRAINT [df_WorkOrder_ProducedQty] DEFAULT(0),
                    [ScrapQuantity]       DECIMAL(18,4) NOT NULL CONSTRAINT [df_WorkOrder_ScrapQty] DEFAULT(0),
                    [UnitId]              INT NULL,
                    [PlannedStartDate]    DATETIME NULL,
                    [PlannedEndDate]      DATETIME NULL,
                    [ActualStartDate]     DATETIME NULL,
                    [ActualEndDate]       DATETIME NULL,
                    [Status]              TINYINT NOT NULL CONSTRAINT [df_WorkOrder_Status] DEFAULT(0),
                    [Priority]            TINYINT NOT NULL CONSTRAINT [df_WorkOrder_Priority] DEFAULT(1),
                    [AssignedUserId]      INT NULL,
                    [WarehouseLocationId] INT NULL,
                    [CreatedById]           INT NULL,
                    [Created]             DATETIME NOT NULL CONSTRAINT [df_WorkOrder_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById]           INT NULL,
                    [Updated]             DATETIME NULL,
                    [IsActive]            BIT NOT NULL CONSTRAINT [df_WorkOrder_IsActive] DEFAULT(1),
                    CONSTRAINT [CK_WorkOrder_Status]   CHECK ([Status] BETWEEN 0 AND 5),
                    CONSTRAINT [CK_WorkOrder_Priority] CHECK ([Priority] BETWEEN 0 AND 2),
                    CONSTRAINT [UX_WorkOrder_Document] UNIQUE ([DocumentId]),
                    CONSTRAINT [FK_WorkOrder_Document] FOREIGN KEY ([DocumentId])
                        REFERENCES [{schemaForSql}].[Document]([id])
                );
                CREATE INDEX [ix_WorkOrder_Status]
                    ON [{schemaForSql}].[WorkOrder]([CompanyId], [Status]);
                CREATE INDEX [ix_WorkOrder_Item]
                    ON [{schemaForSql}].[WorkOrder]([CompanyId], [ItemId]);
            END;

            -- Migration: eski WorkOrder semasi (OrderNumber/OrderDate/RevisionNo/
            -- ParentWorkOrderId/RevisedFromId/Notes) -> Document companion modeli.
            -- Canli veri yok (2026-07-02 karari) — mevcut satirlar (varsa) test/gelistirme
            -- kalintisi sayilip silinir (Document karsiligi uretilemeyecegi icin backfill
            -- yapilmiyor); bagimli WorkOrderOperation/WorkOrderComponent/WorkOrderSource
            -- satirlari da temizlenir. Adim 1: kolon yoksa nullable ekle (ayri IF — yarim
            -- kalan onceki calistirmadan sonra kolon zaten eklenmis olabilir, batch icindeki
            -- her DDL statement kendi basina commit olur, bu yuzden adimlar birbirinden
            -- bagimsiz idempotent kontrol edilir).
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'DocumentId') IS NULL
                ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [DocumentId] INT NULL;

            -- Adim 2: kolon hala nullable ise (donusum tamamlanmamis — ilk kez ya da onceki
            -- calistirma bu noktadan once patladiysa) temizle + NOT NULL'a cevir.
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND EXISTS (SELECT 1 FROM sys.columns
                           WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]')
                             AND name = N'DocumentId' AND is_nullable = 1)
            BEGIN
                IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderComponent]', N'U') IS NOT NULL
                    DELETE FROM [{schemaForSql}].[WorkOrderComponent];
                IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperationActivity]', N'U') IS NOT NULL
                    DELETE FROM [{schemaForSql}].[WorkOrderOperationActivity];
                IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperation]', N'U') IS NOT NULL
                    DELETE FROM [{schemaForSql}].[WorkOrderOperation];
                IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderSource]', N'U') IS NOT NULL
                    DELETE FROM [{schemaForSql}].[WorkOrderSource];
                DELETE FROM [{schemaForSql}].[WorkOrder];
                ALTER TABLE [{schemaForSql}].[WorkOrder] ALTER COLUMN [DocumentId] INT NOT NULL;
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'OrderNumber') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'ux_WorkOrder_Comp_Number'
                           AND object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]'))
                    DROP INDEX [ux_WorkOrder_Comp_Number] ON [{schemaForSql}].[WorkOrder];
                IF EXISTS (SELECT 1 FROM sys.default_constraints WHERE name = N'df_WorkOrder_OrderDate'
                           AND parent_object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]'))
                    ALTER TABLE [{schemaForSql}].[WorkOrder] DROP CONSTRAINT [df_WorkOrder_OrderDate];
                IF EXISTS (SELECT 1 FROM sys.default_constraints WHERE name = N'df_WorkOrder_RevisionNo'
                           AND parent_object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]'))
                    ALTER TABLE [{schemaForSql}].[WorkOrder] DROP CONSTRAINT [df_WorkOrder_RevisionNo];
                ALTER TABLE [{schemaForSql}].[WorkOrder] DROP COLUMN
                    [OrderNumber], [OrderDate], [RevisionNo], [ParentWorkOrderId], [RevisedFromId], [Notes];
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'DocumentId') IS NOT NULL
               AND NOT EXISTS (SELECT 1 FROM sys.foreign_keys WHERE [name] = N'FK_WorkOrder_Document'
                               AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]'))
            BEGIN
                IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'UX_WorkOrder_Document'
                               AND object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]'))
                    CREATE UNIQUE INDEX [UX_WorkOrder_Document] ON [{schemaForSql}].[WorkOrder]([DocumentId]);
                ALTER TABLE [{schemaForSql}].[WorkOrder] WITH CHECK
                    ADD CONSTRAINT [FK_WorkOrder_Document] FOREIGN KEY ([DocumentId])
                        REFERENCES [{schemaForSql}].[Document]([id]);
            END;

            -- ===== WorkOrderSource (Faz 1: bolme + toplama icin many-to-many) =====
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderSource]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[WorkOrderSource]
                (
                    [Id]                INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_WorkOrderSource] PRIMARY KEY,
                    [WorkOrderId]       INT NOT NULL,
                    [SourceDocumentId]  INT NOT NULL,
                    [SourceLineId]      INT NOT NULL,
                    [AllocatedQuantity] DECIMAL(18,4) NOT NULL CONSTRAINT [df_WorkOrderSource_Qty] DEFAULT(0),
                    [Created]           DATETIME NOT NULL CONSTRAINT [df_WorkOrderSource_Created] DEFAULT(SYSUTCDATETIME())
                );
                CREATE INDEX [ix_WorkOrderSource_WorkOrder]
                    ON [{schemaForSql}].[WorkOrderSource]([WorkOrderId]);
                CREATE INDEX [ix_WorkOrderSource_SourceLine]
                    ON [{schemaForSql}].[WorkOrderSource]([SourceLineId]);
            END;

            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND OBJECT_ID(N'[{schemaForSql}].[WorkOrderSource]', N'U') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.foreign_keys
                   WHERE [name] = N'FK_WorkOrderSource_WorkOrder'
                     AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[WorkOrderSource]'))
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrderSource]
                WITH NOCHECK
                ADD CONSTRAINT [FK_WorkOrderSource_WorkOrder]
                    FOREIGN KEY ([WorkOrderId])
                    REFERENCES [{schemaForSql}].[WorkOrder]([Id]) ON DELETE CASCADE;
            END;

            -- 2026-06-11: Migration: WorkOrder.AssignedUserId → INT (Users.Id FK).
            -- CreatedById/UpdatedById → INT NULL (kullanici ID'si, soft-delete nedeniyle FK constraint yok).
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
            BEGIN
                -- AssignedUserId: uniqueidentifier → INT
                IF EXISTS (SELECT 1 FROM sys.columns
                           WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]')
                             AND name = N'AssignedUserId' AND system_type_id = TYPE_ID(N'uniqueidentifier'))
                BEGIN
                    ALTER TABLE [{schemaForSql}].[WorkOrder] DROP COLUMN [AssignedUserId];
                    ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [AssignedUserId] INT NULL;
                END;
                -- CreatedById migration: NVARCHAR veya uniqueidentifier → INT
                IF EXISTS (SELECT 1 FROM sys.columns
                           WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]')
                             AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[WorkOrder] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [CreatedById] INT NULL;
                END
                ELSE IF EXISTS (SELECT 1 FROM sys.columns
                           WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]')
                             AND name = N'CreatedById' AND system_type_id = TYPE_ID(N'uniqueidentifier'))
                BEGIN
                    ALTER TABLE [{schemaForSql}].[WorkOrder] DROP COLUMN [CreatedById];
                    ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns
                           WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]')
                             AND name = N'CreatedById')
                    ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [CreatedById] INT NULL;
                -- UpdatedById migration: NVARCHAR veya uniqueidentifier → INT
                IF EXISTS (SELECT 1 FROM sys.columns
                           WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]')
                             AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[WorkOrder] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [UpdatedById] INT NULL;
                END
                ELSE IF EXISTS (SELECT 1 FROM sys.columns
                           WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]')
                             AND name = N'UpdatedById' AND system_type_id = TYPE_ID(N'uniqueidentifier'))
                BEGIN
                    ALTER TABLE [{schemaForSql}].[WorkOrder] DROP COLUMN [UpdatedById];
                    ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns
                           WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]')
                             AND name = N'UpdatedById')
                    ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [UpdatedById] INT NULL;
            END;

            -- ===== Operation (uretim operasyon sozlugu) — Faz 3 routing temeli =====
            -- DATETIME (DATETIME degil) kullaniliyor: kullanici tercihi.
            IF OBJECT_ID(N'[{schemaForSql}].[Operation]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[Operation]
                (
                    [Id]               INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_Operation] PRIMARY KEY,
                    [CompanyId]        INT NOT NULL,
                    [Code]             NVARCHAR(50)  NOT NULL,
                    [Name]             NVARCHAR(200) NOT NULL,
                    [Description]      NVARCHAR(500) NULL,
                    [StandardDuration] DECIMAL(10,4) NULL,
                    [DurationUnit]     TINYINT NOT NULL CONSTRAINT [df_Operation_DurUnit]   DEFAULT(1),
                    [HourlyRate]       DECIMAL(18,4) NULL,
                    [SortOrder]        INT NOT NULL    CONSTRAINT [df_Operation_SortOrder]  DEFAULT(0),
                    [IsActive]         BIT NOT NULL    CONSTRAINT [df_Operation_IsActive]   DEFAULT(1),
                    [Created]          DATETIME NOT NULL CONSTRAINT [df_Operation_Created]  DEFAULT(GETUTCDATE()),
                    [Updated]          DATETIME NULL,
                    CONSTRAINT [CK_Operation_DurationUnit] CHECK ([DurationUnit] IN (1, 2))
                );
                CREATE UNIQUE INDEX [ux_Operation_Comp_Code]
                    ON [{schemaForSql}].[Operation]([CompanyId], [Code]);
            END;

            -- ===== Routing (uretim rotasi — operasyon dizisi sablonu) =====
            IF OBJECT_ID(N'[{schemaForSql}].[Routing]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[Routing]
                (
                    [Id]          INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_Routing] PRIMARY KEY,
                    [CompanyId]   INT NOT NULL,
                    [Code]        NVARCHAR(50)  NOT NULL,
                    [Name]        NVARCHAR(200) NOT NULL,
                    [ItemId]      INT NULL,
                    [ConfigId]    INT NULL,
                    [Description] NVARCHAR(500) NULL,
                    [IsActive]    BIT NOT NULL CONSTRAINT [df_Routing_IsActive] DEFAULT(1),
                    [Created]     DATETIME NOT NULL CONSTRAINT [df_Routing_Created] DEFAULT(GETUTCDATE()),
                    [Updated]     DATETIME NULL
                );
                CREATE UNIQUE INDEX [ux_Routing_Comp_Code]
                    ON [{schemaForSql}].[Routing]([CompanyId], [Code]);
                CREATE INDEX [ix_Routing_Comp_Item]
                    ON [{schemaForSql}].[Routing]([CompanyId], [ItemId]);
            END;

            -- ===== RoutingOperation (rota ici operasyon adimlari) =====
            IF OBJECT_ID(N'[{schemaForSql}].[RoutingOperation]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[RoutingOperation]
                (
                    [Id]               INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_RoutingOperation] PRIMARY KEY,
                    [RoutingId]        INT NOT NULL,
                    [Sequence]         INT NOT NULL,
                    [OperationId]      INT NOT NULL,
                    [MachineId]        INT NULL,
                    [OverrideDuration] DECIMAL(10,4) NULL,
                    [DurationUnit]     TINYINT NOT NULL CONSTRAINT [df_RoutingOp_DurUnit] DEFAULT(1),
                    [Notes]            NVARCHAR(500) NULL,
                    CONSTRAINT [FK_RoutingOperation_Routing]
                        FOREIGN KEY ([RoutingId])
                        REFERENCES [{schemaForSql}].[Routing]([Id]) ON DELETE CASCADE,
                    CONSTRAINT [CK_RoutingOp_DurationUnit] CHECK ([DurationUnit] IN (1, 2))
                );
                CREATE UNIQUE INDEX [ux_RoutingOp_Routing_Seq]
                    ON [{schemaForSql}].[RoutingOperation]([RoutingId], [Sequence]);
                CREATE INDEX [ix_RoutingOp_Operation]
                    ON [{schemaForSql}].[RoutingOperation]([OperationId]);
            END;

            -- ===== RoutingItemMap (rota → mamul/kombinasyon coka-cok eslestirmesi) =====
            IF OBJECT_ID(N'[{schemaForSql}].[RoutingItemMap]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[RoutingItemMap]
                (
                    [Id]        INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_RoutingItemMap] PRIMARY KEY,
                    [RoutingId] INT NOT NULL,
                    [ItemId]    INT NOT NULL,
                    [ConfigId]  INT NULL,
                    CONSTRAINT [FK_RIM_Routing]
                        FOREIGN KEY ([RoutingId])
                        REFERENCES [{schemaForSql}].[Routing]([Id]) ON DELETE CASCADE
                );
                CREATE UNIQUE INDEX [ux_RIM_Routing_Item_Config]
                    ON [{schemaForSql}].[RoutingItemMap]([RoutingId], [ItemId], [ConfigId])
                    WHERE [ConfigId] IS NOT NULL;
                CREATE UNIQUE INDEX [ux_RIM_Routing_Item_NoConfig]
                    ON [{schemaForSql}].[RoutingItemMap]([RoutingId], [ItemId])
                    WHERE [ConfigId] IS NULL;
                CREATE INDEX [ix_RIM_Item] ON [{schemaForSql}].[RoutingItemMap]([ItemId]);
            END;

            -- ===== OperationMachineTime (operasyon × makine × urun bazli sure) =====
            IF OBJECT_ID(N'[{schemaForSql}].[OperationMachineTime]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[OperationMachineTime]
                (
                    [Id]              INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_OpMachineTime] PRIMARY KEY,
                    [CompanyId]       INT NOT NULL,
                    [OperationId]     INT NOT NULL,
                    [MachineId]       INT NOT NULL,
                    [ItemId]          INT NULL,
                    [Quantity]        DECIMAL(18,4) NOT NULL CONSTRAINT [df_OpMT_Quantity] DEFAULT(1),
                    [DurationPerUnit] DECIMAL(10,4) NOT NULL,
                    [DurationUnit]    TINYINT NOT NULL CONSTRAINT [df_OpMT_DurUnit]   DEFAULT(1),
                    [IsActive]        BIT NOT NULL    CONSTRAINT [df_OpMT_IsActive]  DEFAULT(1),
                    [Created]         DATETIME NOT NULL CONSTRAINT [df_OpMT_Created] DEFAULT(GETUTCDATE()),
                    [Updated]         DATETIME NULL,
                    CONSTRAINT [CK_OpMT_DurationUnit] CHECK ([DurationUnit] IN (1, 2))
                );
                -- Filtered indexler: ItemId dolu (urune ozel) ve NULL (genel) durumlari ayri unique olur.
                CREATE UNIQUE INDEX [ux_OpMT_Op_Machine_Item]
                    ON [{schemaForSql}].[OperationMachineTime]([CompanyId], [OperationId], [MachineId], [ItemId])
                    WHERE [ItemId] IS NOT NULL;
                CREATE UNIQUE INDEX [ux_OpMT_Op_Machine_Generic]
                    ON [{schemaForSql}].[OperationMachineTime]([CompanyId], [OperationId], [MachineId])
                    WHERE [ItemId] IS NULL;
                CREATE INDEX [ix_OpMT_Operation]
                    ON [{schemaForSql}].[OperationMachineTime]([OperationId]);
            END;

            -- Idempotent migration: Quantity kolonu mevcut tabloda yoksa ekle.
            IF OBJECT_ID(N'[{schemaForSql}].[OperationMachineTime]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[OperationMachineTime]', N'Quantity') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[OperationMachineTime]
                    ADD [Quantity] DECIMAL(18,4) NOT NULL CONSTRAINT [df_OpMT_Quantity] DEFAULT(1);
            END;

            -- ===== Faz 3a (revize): Personnel tablosu — uretim personneli =====
            -- User'dan ayri tablo. PIN/NFC, vardiya, departman ve operator flag burada.
            -- Sistem kullanicisi olan personnellerde UserId baglar; kullanicisi olmayan
            -- (sadece tablette giren) operatorlerde NULL kalir.
            IF OBJECT_ID(N'[{schemaForSql}].[Personnel]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[Personnel]
                (
                    [Id]                   INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_Personnel] PRIMARY KEY,
                    [CompanyId]            INT NOT NULL,
                    [Code]                 NVARCHAR(30) NOT NULL,
                    [FullName]             NVARCHAR(100) NOT NULL,
                    [Title]                NVARCHAR(80) NULL,
                    [Department]           NVARCHAR(80) NULL,
                    [PinCode]              NVARCHAR(10) NULL,
                    [CardNo]               NVARCHAR(50) NULL,
                    [IsProductionOperator] BIT NOT NULL CONSTRAINT [df_Personnel_IsOperator] DEFAULT(0),
                    [IsActive]             BIT NOT NULL CONSTRAINT [df_Personnel_IsActive]   DEFAULT(1),
                    [UserId]               INT NULL,
                    [Phone]                NVARCHAR(40) NULL,
                    [Email]                NVARCHAR(120) NULL,
                    [Notes]                NVARCHAR(500) NULL,
                    [Created]              DATETIME NOT NULL CONSTRAINT [df_Personnel_Created] DEFAULT(GETUTCDATE()),
                    [Updated]              DATETIME NULL
                );
                CREATE UNIQUE INDEX [ux_Personnel_Comp_Code]
                    ON [{schemaForSql}].[Personnel]([CompanyId], [Code]);
                -- CardNo sirket icinde benzersiz, bos olabilir (filtered).
                CREATE UNIQUE INDEX [ux_Personnel_Comp_CardNo]
                    ON [{schemaForSql}].[Personnel]([CompanyId], [CardNo])
                    WHERE [CardNo] IS NOT NULL;
                -- PIN sirket icinde benzersiz olmali (cakismayi engellemek icin), bos olabilir.
                CREATE UNIQUE INDEX [ux_Personnel_Comp_Pin]
                    ON [{schemaForSql}].[Personnel]([CompanyId], [PinCode])
                    WHERE [PinCode] IS NOT NULL;
                CREATE INDEX [ix_Personnel_UserId]
                    ON [{schemaForSql}].[Personnel]([UserId])
                    WHERE [UserId] IS NOT NULL;
            END;
            -- 2026-05-25: Personnel.UserId UNIQUEIDENTIFIER → INT migration (eski tablo data wipe).
            IF OBJECT_ID(N'[{schemaForSql}].[Personnel]', N'U') IS NOT NULL
               AND EXISTS (SELECT 1 FROM sys.columns
                           WHERE [object_id] = OBJECT_ID(N'[{schemaForSql}].[Personnel]')
                             AND [name] = N'UserId'
                             AND system_type_id = TYPE_ID(N'uniqueidentifier'))
            BEGIN
                -- Eski FK varsa drop et
                IF EXISTS (SELECT 1 FROM sys.foreign_keys
                           WHERE [name] = N'FK_Personnel_User'
                             AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[Personnel]'))
                    ALTER TABLE [{schemaForSql}].[Personnel] DROP CONSTRAINT [FK_Personnel_User];
                IF EXISTS (SELECT 1 FROM sys.indexes
                           WHERE [name] = N'ix_Personnel_UserId'
                             AND [object_id] = OBJECT_ID(N'[{schemaForSql}].[Personnel]'))
                    DROP INDEX [ix_Personnel_UserId] ON [{schemaForSql}].[Personnel];
                ALTER TABLE [{schemaForSql}].[Personnel] DROP COLUMN [UserId];
                ALTER TABLE [{schemaForSql}].[Personnel] ADD [UserId] INT NULL;
                CREATE INDEX [ix_Personnel_UserId]
                    ON [{schemaForSql}].[Personnel]([UserId])
                    WHERE [UserId] IS NOT NULL;
            END;

            -- FK: Personnel.UserId → Users.Id (idempotent attach)
            IF OBJECT_ID(N'[{schemaForSql}].[Personnel]', N'U') IS NOT NULL
               AND OBJECT_ID(N'[{schemaForSql}].[Users]', N'U') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.foreign_keys
                   WHERE [name] = N'FK_Personnel_Users'
                     AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[Personnel]'))
            BEGIN
                ALTER TABLE [{schemaForSql}].[Personnel]
                    ADD CONSTRAINT [FK_Personnel_Users]
                    FOREIGN KEY ([UserId]) REFERENCES [{schemaForSql}].[Users]([Id]);
            END;

            -- LocationId — Personelin varsayilan depo/lokasyonu (Location.Id INT FK).
            -- Ihti­yac kaydinda otomatik dolar; NULL ise dropdown bos gelir.
            IF OBJECT_ID(N'[{schemaForSql}].[Personnel]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[Personnel]', N'LocationId') IS NULL
                ALTER TABLE [{schemaForSql}].[Personnel] ADD [LocationId] INT NULL;

            -- ===== Faz 3a revize: User'dan PIN/Card/IsProductionOperator alanlarini KALDIR =====
            -- Bu alanlar Personnel'e tasindi. Idempotent rollback.
            IF EXISTS (
                SELECT 1 FROM sys.indexes
                WHERE [name] = N'ux_User_CardNo'
                  AND [object_id] = OBJECT_ID(N'[{schemaForSql}].[User]'))
            BEGIN
                EXEC(N'DROP INDEX [ux_User_CardNo] ON [{schemaForSql}].[User];');
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[User]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[User]', N'pin_code') IS NOT NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[User] DROP COLUMN [pin_code];
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[User]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[User]', N'card_no') IS NOT NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[User] DROP COLUMN [card_no];
            END;
            -- is_production_operator default constraint ile birlikte kaldirilmali.
            IF EXISTS (
                SELECT 1 FROM sys.default_constraints
                WHERE [name] = N'df_User_IsOperator'
                  AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[User]'))
            BEGIN
                ALTER TABLE [{schemaForSql}].[User] DROP CONSTRAINT [df_User_IsOperator];
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[User]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[User]', N'is_production_operator') IS NOT NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[User] DROP COLUMN [is_production_operator];
            END;

            -- ===== Faz 3a: WorkOrder.RoutingId (Release auto-explosion icin) =====
            -- Mevcut WorkOrder kayitlari korunur, RoutingId nullable olarak eklenir.
            -- Yeni emirlerde service katmaninda zorunlu hale getirilir; Release sirasinda
            -- bos kalmissa Item bazinda otomatik aranir. FK Routing tablosuna baglar.
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'RoutingId') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [RoutingId] INT NULL;
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'RoutingId') IS NOT NULL
               AND OBJECT_ID(N'[{schemaForSql}].[Routing]', N'U') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.foreign_keys
                   WHERE [name] = N'FK_WorkOrder_Routing'
                     AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]'))
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrder]
                    ADD CONSTRAINT [FK_WorkOrder_Routing]
                    FOREIGN KEY ([RoutingId])
                    REFERENCES [{schemaForSql}].[Routing]([Id]);
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'RoutingId') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.indexes
                   WHERE [name] = N'ix_WorkOrder_RoutingId'
                     AND [object_id] = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]'))
            BEGIN
                EXEC(N'
                    CREATE INDEX [ix_WorkOrder_RoutingId]
                        ON [{schemaForSql}].[WorkOrder]([RoutingId])
                        WHERE [RoutingId] IS NOT NULL;
                ');
            END;

            -- ===== Faz 3: WorkOrder.AssignedPersonnelId (User'dan bagimsiz Personnel atamasi) =====
            -- AssignedUserId (User FK) Personnel.UserId zorunluluğu yaratiyordu — kaldirildi.
            -- Yeni atama dogrudan Personnel.Id'ye yapilir; eski sutun (AssignedUserId) backward
            -- compat icin saklanir, runtime'da artik kullanilmiyor.
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'AssignedPersonnelId') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [AssignedPersonnelId] INT NULL;
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'AssignedPersonnelId') IS NOT NULL
               AND OBJECT_ID(N'[{schemaForSql}].[Personnel]', N'U') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.foreign_keys
                   WHERE [name] = N'FK_WorkOrder_AssignedPersonnel'
                     AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]'))
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrder]
                    ADD CONSTRAINT [FK_WorkOrder_AssignedPersonnel]
                    FOREIGN KEY ([AssignedPersonnelId])
                    REFERENCES [{schemaForSql}].[Personnel]([Id]);
            END;

            -- ===== Faz 3: WorkOrder.DefaultMachineId (header'dan operasyonlara fallback makine) =====
            -- Patlatma sirasinda RoutingOperation'da MachineId NULL ise WO.DefaultMachineId kullanilir.
            -- Salt header tercihi — operasyon bazinda override edilebilir.
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'DefaultMachineId') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [DefaultMachineId] INT NULL;
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'DefaultMachineId') IS NOT NULL
               AND OBJECT_ID(N'[{schemaForSql}].[Machine]', N'U') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.foreign_keys
                   WHERE [name] = N'FK_WorkOrder_DefaultMachine'
                     AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[WorkOrder]'))
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrder]
                    ADD CONSTRAINT [FK_WorkOrder_DefaultMachine]
                    FOREIGN KEY ([DefaultMachineId])
                    REFERENCES [{schemaForSql}].[Machine]([Id]);
            END;

            -- ===== AR-GE Faz 3: WorkOrder.ArgeProjectId (is emri ↔ AR-GE/ÜR-GE projesi) =====
            -- Iş emri bir AR-GE/ÜR-GE projesine baglanabilir (Document.id). AR-GE seri/prototip
            -- mamulu icin WO acildiginda WorkOrderService otomatik turetir; manuel de secilebilir.
            -- Maliyet rollup (proje isciligi) bu kolon uzerinden toplanir. FK yok (stock_doc deseni).
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrder]', N'ArgeProjectId') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrder] ADD [ArgeProjectId] INT NULL;
            END;

            -- ===== Faz 2: WorkOrderComponent (BOM patlatma ciktisi) =====
            -- Iş emri reçetesinin patlatilmis bilesen listesi. ExplodeBomAsync
            -- mevcut satirlari silip yeniden yazar (idempotent re-explode).
            -- RequiredQuantity = bomLine.Quantity * wo.PlannedQuantity * (1 + ScrapRate)
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderComponent]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[WorkOrderComponent]
                (
                    [Id]               INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_WorkOrderComponent] PRIMARY KEY,
                    [WorkOrderId]      INT NOT NULL,
                    [ItemId]           INT NOT NULL,
                    [ConfigId]         INT NULL,
                    [RequiredQuantity] DECIMAL(18,4) NOT NULL CONSTRAINT [df_WorkOrderComponent_Req] DEFAULT(0),
                    [IssuedQuantity]   DECIMAL(18,4) NOT NULL CONSTRAINT [df_WorkOrderComponent_Issued] DEFAULT(0),
                    [ScrapRate]        DECIMAL(18,4) NOT NULL CONSTRAINT [df_WorkOrderComponent_Scrap] DEFAULT(0),
                    [UnitId]           INT NULL,
                    [Notes]            NVARCHAR(500) NULL,
                    [Created]          DATETIME NOT NULL CONSTRAINT [df_WorkOrderComponent_Created] DEFAULT(SYSUTCDATETIME()),
                    [Updated]          DATETIME NULL
                );
                CREATE INDEX [ix_WorkOrderComponent_WorkOrder]
                    ON [{schemaForSql}].[WorkOrderComponent]([WorkOrderId]);
                CREATE INDEX [ix_WorkOrderComponent_Item]
                    ON [{schemaForSql}].[WorkOrderComponent]([ItemId]);
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderComponent]', N'U') IS NOT NULL
               AND OBJECT_ID(N'[{schemaForSql}].[WorkOrder]', N'U') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.foreign_keys
                   WHERE [name] = N'FK_WorkOrderComponent_WorkOrder'
                     AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[WorkOrderComponent]'))
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrderComponent]
                    ADD CONSTRAINT [FK_WorkOrderComponent_WorkOrder]
                    FOREIGN KEY ([WorkOrderId])
                    REFERENCES [{schemaForSql}].[WorkOrder]([Id]) ON DELETE CASCADE;
            END;

            -- ===== Faz 3a: WorkOrderOperation (is emri operasyon adimlari) =====
            -- Release sirasinda Routing'in operasyonlari kopyalanir, shop-floor uzerinden takip edilir.
            -- StartedBy/CompletedBy referansi Personnel.Id (INT) — User degil, ciddi bicimde uretim katindaki
            -- operatorler bu hareketleri kayda gecirir.
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperation]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[WorkOrderOperation]
                (
                    [Id]                    INT NOT NULL IDENTITY(1,1) CONSTRAINT [PK_WorkOrderOperation] PRIMARY KEY,
                    [WorkOrderId]           INT NOT NULL,
                    [Sequence]              INT NOT NULL,
                    [OperationId]           INT NOT NULL,
                    [MachineId]             INT NULL,
                    [PlannedDuration]       DECIMAL(10,4) NULL,
                    [DurationUnit]          TINYINT NOT NULL CONSTRAINT [df_WOO_DurUnit] DEFAULT(1),
                    [ActualDuration]        DECIMAL(10,4) NULL,
                    [ProducedQuantity]      DECIMAL(18,4) NOT NULL CONSTRAINT [df_WOO_Produced] DEFAULT(0),
                    [ScrapQuantity]         DECIMAL(18,4) NOT NULL CONSTRAINT [df_WOO_Scrap] DEFAULT(0),
                    [Status]                TINYINT NOT NULL CONSTRAINT [df_WOO_Status] DEFAULT(0),
                    [StartedByPersonnelId]  INT NULL,
                    [StartedAt]             DATETIME NULL,
                    [CompletedByPersonnelId] INT NULL,
                    [CompletedAt]           DATETIME NULL,
                    [Notes]                 NVARCHAR(500) NULL,
                    CONSTRAINT [FK_WorkOrderOperation_WorkOrder]
                        FOREIGN KEY ([WorkOrderId])
                        REFERENCES [{schemaForSql}].[WorkOrder]([Id]) ON DELETE CASCADE,
                    CONSTRAINT [CK_WorkOrderOperation_Status]
                        CHECK ([Status] IN (0,1,2,3)),
                    CONSTRAINT [CK_WorkOrderOperation_DurUnit]
                        CHECK ([DurationUnit] IN (1,2))
                );
                CREATE UNIQUE INDEX [ux_WorkOrderOperation_WO_Seq]
                    ON [{schemaForSql}].[WorkOrderOperation]([WorkOrderId], [Sequence]);
                CREATE INDEX [ix_WorkOrderOperation_Machine]
                    ON [{schemaForSql}].[WorkOrderOperation]([MachineId])
                    WHERE [MachineId] IS NOT NULL;
                CREATE INDEX [ix_WorkOrderOperation_Status]
                    ON [{schemaForSql}].[WorkOrderOperation]([Status]);
            END;

            -- ===== Faz 3a revize: WorkOrderOperation StartedBy/CompletedBy alanlari =====
            -- User (UNIQUEIDENTIFIER) yerine Personnel (INT) referansi. Idempotent migration:
            -- eski kolonlar varsa kaldirilir (tablo yeni olustugu icin veri yok), yeni kolonlar eklenir.
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperation]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrderOperation]', N'StartedByUserId') IS NOT NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrderOperation] DROP COLUMN [StartedByUserId];
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperation]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrderOperation]', N'CompletedByUserId') IS NOT NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrderOperation] DROP COLUMN [CompletedByUserId];
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperation]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrderOperation]', N'StartedByPersonnelId') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrderOperation] ADD [StartedByPersonnelId] INT NULL;
            END;
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperation]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrderOperation]', N'CompletedByPersonnelId') IS NULL
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrderOperation] ADD [CompletedByPersonnelId] INT NULL;
            END;

            -- ===== 2026-05-21 Faz 3: Shift (vardiya tanimlari) =====
            -- Vardiya = personelin calistigi sabit zaman dilimi (Gunduz 07-15, Aksam 15-23, Gece 23-07).
            -- IsOvernight: EndTime < StartTime ise gece (00:00 sinirini gecer); UI/raporlama bunu kullanir.
            -- ColorHex: vardiya rozetleri ve raporlama grafikleri icin opsiyonel tematik renk.
            IF OBJECT_ID(N'[{schemaForSql}].[Shift]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[Shift]
                (
                    [Id]          INT IDENTITY(1,1) NOT NULL
                        CONSTRAINT [PK_Shift] PRIMARY KEY,
                    [Code]        NVARCHAR(50)  NOT NULL,
                    [Name]        NVARCHAR(200) NOT NULL,
                    [StartTime]   TIME(0) NOT NULL,
                    [EndTime]     TIME(0) NOT NULL,
                    [IsOvernight] BIT NOT NULL CONSTRAINT [df_Shift_Overnight] DEFAULT(0),
                    [ColorHex]    NVARCHAR(9) NULL,
                    [SortOrder]   INT NOT NULL CONSTRAINT [df_Shift_SortOrder] DEFAULT(0),
                    [IsActive]    BIT NOT NULL CONSTRAINT [df_Shift_IsActive]  DEFAULT(1),
                    [CreatedById]   INT NULL,
                    [Created]     DATETIME NOT NULL CONSTRAINT [df_Shift_Created] DEFAULT(SYSUTCDATETIME()),
                    [UpdatedById]   INT NULL,
                    [Updated]     DATETIME NULL
                );
                -- Aktif kayitlar icinde Code unique (pasif kayit duplikat olabilir)
                CREATE UNIQUE INDEX [UX_Shift_Code]
                    ON [{schemaForSql}].[Shift]([Code]) WHERE [IsActive] = 1;
                CREATE INDEX [IX_Shift_Sort]
                    ON [{schemaForSql}].[Shift]([SortOrder], [Code]);
            END;

            -- Migration: [CreatedBy]/[UpdatedBy] NVARCHAR -> [CreatedById]/[UpdatedById] INT
            IF OBJECT_ID(N'[{schemaForSql}].[Shift]', N'U') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[Shift]') AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[Shift] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{schemaForSql}].[Shift] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[Shift]') AND name = N'CreatedById')
                    ALTER TABLE [{schemaForSql}].[Shift] ADD [CreatedById] INT NULL;
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[Shift]') AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[Shift] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{schemaForSql}].[Shift] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[Shift]') AND name = N'UpdatedById')
                    ALTER TABLE [{schemaForSql}].[Shift] ADD [UpdatedById] INT NULL;
            END

            -- ===== 2026-05-21 Faz 3: ShiftBreak (vardiya ici molalar: cay/yemek) =====
            -- Net calisma suresi = vardiya suresi - toplam ara. IsPaid: ucretli mola
            -- ise yine vardiya suresine dahil (sadece raporlama icin ayri tutulur).
            -- Mola her zaman vardiya icinde olmali (validation domain'de).
            IF OBJECT_ID(N'[{schemaForSql}].[ShiftBreak]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[ShiftBreak]
                (
                    [Id]        INT IDENTITY(1,1) NOT NULL
                        CONSTRAINT [PK_ShiftBreak] PRIMARY KEY,
                    [ShiftId]   INT NOT NULL,
                    [Name]      NVARCHAR(100) NOT NULL,
                    [StartTime] TIME(0) NOT NULL,
                    [EndTime]   TIME(0) NOT NULL,
                    [IsPaid]    BIT NOT NULL CONSTRAINT [df_SB_IsPaid] DEFAULT(0),
                    [SortOrder] INT NOT NULL CONSTRAINT [df_SB_Sort]   DEFAULT(0),
                    [Created]   DATETIME NOT NULL CONSTRAINT [df_SB_Created] DEFAULT(SYSUTCDATETIME()),
                    CONSTRAINT [FK_ShiftBreak_Shift]
                        FOREIGN KEY ([ShiftId])
                        REFERENCES [{schemaForSql}].[Shift]([Id]) ON DELETE CASCADE,
                    CONSTRAINT [CK_ShiftBreak_EndAfterStart]
                        CHECK ([EndTime] > [StartTime])
                );
                CREATE INDEX [IX_ShiftBreak_Shift]
                    ON [{schemaForSql}].[ShiftBreak]([ShiftId], [StartTime]);
            END;

            -- ===== 2026-05-21 Faz 3: ShiftAssignment (personel x vardiya x gun) =====
            -- Haftalik tekrar pattern: bir personelin hangi gunlerde hangi vardiyada
            -- calistigi. DayOfWeek: 0=Pazar, 1=Pzt, ..., 6=Cumartesi (.NET DayOfWeek enum).
            -- Filtered unique: ayni personel + gun + aktif kayit tekildir (cakisma engellenir).
            IF OBJECT_ID(N'[{schemaForSql}].[ShiftAssignment]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[ShiftAssignment]
                (
                    [Id]           INT IDENTITY(1,1) NOT NULL
                        CONSTRAINT [PK_ShiftAssignment] PRIMARY KEY,
                    [PersonnelId]  INT NOT NULL,
                    [ShiftId]      INT NOT NULL,
                    [DayOfWeek]    TINYINT NOT NULL,
                    [EffectiveFrom] DATE NULL,
                    [EffectiveTo]   DATE NULL,
                    [IsActive]     BIT NOT NULL CONSTRAINT [df_SA_IsActive] DEFAULT(1),
                    [CreatedById]    INT NULL,
                    [Created]      DATETIME NOT NULL CONSTRAINT [df_SA_Created] DEFAULT(SYSUTCDATETIME()),
                    [UpdatedById]    INT NULL,
                    [Updated]      DATETIME NULL,
                    CONSTRAINT [CK_SA_DayOfWeek] CHECK ([DayOfWeek] BETWEEN 0 AND 6),
                    CONSTRAINT [FK_SA_Personnel]
                        FOREIGN KEY ([PersonnelId])
                        REFERENCES [{schemaForSql}].[Personnel]([Id]) ON DELETE CASCADE,
                    CONSTRAINT [FK_SA_Shift]
                        FOREIGN KEY ([ShiftId])
                        REFERENCES [{schemaForSql}].[Shift]([Id])
                );
                -- Bir personelin bir gununde sadece bir aktif vardiya olur
                CREATE UNIQUE INDEX [UX_SA_PersonnelDay]
                    ON [{schemaForSql}].[ShiftAssignment]([PersonnelId], [DayOfWeek])
                    WHERE [IsActive] = 1;
                CREATE INDEX [IX_SA_Shift]
                    ON [{schemaForSql}].[ShiftAssignment]([ShiftId]);
            END;

            -- Migration: [CreatedBy]/[UpdatedBy] NVARCHAR -> [CreatedById]/[UpdatedById] INT
            IF OBJECT_ID(N'[{schemaForSql}].[ShiftAssignment]', N'U') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[ShiftAssignment]') AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[ShiftAssignment] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{schemaForSql}].[ShiftAssignment] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[ShiftAssignment]') AND name = N'CreatedById')
                    ALTER TABLE [{schemaForSql}].[ShiftAssignment] ADD [CreatedById] INT NULL;
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[ShiftAssignment]') AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[ShiftAssignment] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{schemaForSql}].[ShiftAssignment] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[ShiftAssignment]') AND name = N'UpdatedById')
                    ALTER TABLE [{schemaForSql}].[ShiftAssignment] ADD [UpdatedById] INT NULL;
            END

            -- ===== 2026-05-21 Faz 2: ActivityReason (saha aktivite sebep sozlugu) =====
            -- Operatorun arzaya/malzeme beklemeye/molaya basarken sectigi alt sebep.
            -- Admin tanimlar (ornek: Ariza icin 'Sensor arizasi', 'Elektrik', 'Mekanik').
            -- Activity'de opsiyonel FK (ActivityReasonId). ActivityType + Code unique.
            IF OBJECT_ID(N'[{schemaForSql}].[ActivityReason]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[ActivityReason]
                (
                    [Id]              INT IDENTITY(1,1) NOT NULL
                        CONSTRAINT [PK_ActivityReason] PRIMARY KEY,
                    [ActivityType]    TINYINT NOT NULL,
                    [Code]            NVARCHAR(50)  NOT NULL,
                    [Name]            NVARCHAR(200) NOT NULL,
                    [Description]     NVARCHAR(500) NULL,
                    [ColorHex]        NVARCHAR(9)   NULL,
                    [SortOrder]       INT NOT NULL CONSTRAINT [df_AR_SortOrder] DEFAULT(0),
                    [IsActive]        BIT NOT NULL CONSTRAINT [df_AR_IsActive]  DEFAULT(1),
                    [CreatedById]       INT NULL,
                    [Created]         DATETIME NOT NULL CONSTRAINT [df_AR_Created] DEFAULT(SYSUTCDATETIME()),
                    [UpdatedById]       INT NULL,
                    [Updated]         DATETIME NULL
                );
                -- Filtered unique — pasif kayit duplikat olabilir (eskinden kalma)
                CREATE UNIQUE INDEX [UX_ActivityReason_TypeCode]
                    ON [{schemaForSql}].[ActivityReason]([ActivityType], [Code])
                    WHERE [IsActive] = 1;
                CREATE INDEX [IX_ActivityReason_Type]
                    ON [{schemaForSql}].[ActivityReason]([ActivityType], [SortOrder]);
            END;

            -- Migration: [CreatedBy]/[UpdatedBy] NVARCHAR -> [CreatedById]/[UpdatedById] INT
            IF OBJECT_ID(N'[{schemaForSql}].[ActivityReason]', N'U') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[ActivityReason]') AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[ActivityReason] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{schemaForSql}].[ActivityReason] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[ActivityReason]') AND name = N'CreatedById')
                    ALTER TABLE [{schemaForSql}].[ActivityReason] ADD [CreatedById] INT NULL;
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[ActivityReason]') AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[ActivityReason] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{schemaForSql}].[ActivityReason] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[ActivityReason]') AND name = N'UpdatedById')
                    ALTER TABLE [{schemaForSql}].[ActivityReason] ADD [UpdatedById] INT NULL;
            END

            -- ===== 2026-05-20 Faz 1 MVP: WorkOrderOperationActivity (saha aktivite log) =====
            -- Her operasyonda yapilan eylemler (Hazirlik/Uretim/Malzeme Bekleme/Ariza/Mola/...)
            -- ayri satir olarak loglanir. Filtered unique index ile ayni operasyonda anda
            -- yalniz bir 'aktif' (EndedAt NULL) satir olabilir — Domain invariant ile uyumlu.
            -- ActivityReasonId opsiyonel FK (Faz 2 — ActivityReason tablosu eklendiginde).
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperationActivity]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{schemaForSql}].[WorkOrderOperationActivity]
                (
                    [Id]                    INT NOT NULL IDENTITY(1,1)
                        CONSTRAINT [PK_WorkOrderOperationActivity] PRIMARY KEY,
                    [WorkOrderOperationId]  INT NOT NULL,
                    [PersonnelId]           INT NOT NULL,
                    [ActivityType]          TINYINT NOT NULL,
                    [ActivityReasonId]      INT NULL,
                    [StartedAt]             DATETIME NOT NULL
                        CONSTRAINT [df_WOOA_StartedAt] DEFAULT(SYSUTCDATETIME()),
                    [EndedAt]               DATETIME NULL,
                    [Quantity]              DECIMAL(18,4) NULL,
                    [ScrapQuantity]         DECIMAL(18,4) NULL,
                    [Notes]                 NVARCHAR(500) NULL,
                    [CreatedById]             INT NULL,
                    [Created]               DATETIME NOT NULL
                        CONSTRAINT [df_WOOA_Created] DEFAULT(SYSUTCDATETIME()),
                    [UpdatedById]             INT NULL,
                    [Updated]               DATETIME NULL,
                    CONSTRAINT [FK_WOOA_WorkOrderOperation]
                        FOREIGN KEY ([WorkOrderOperationId])
                        REFERENCES [{schemaForSql}].[WorkOrderOperation]([Id]) ON DELETE CASCADE,
                    CONSTRAINT [CK_WOOA_EndAfterStart]
                        CHECK ([EndedAt] IS NULL OR [EndedAt] >= [StartedAt]),
                    CONSTRAINT [CK_WOOA_QuantityNonNeg]
                        CHECK ([Quantity] IS NULL OR [Quantity] >= 0),
                    CONSTRAINT [CK_WOOA_ScrapNonNeg]
                        CHECK ([ScrapQuantity] IS NULL OR [ScrapQuantity] >= 0)
                );

                -- Filtered unique: ayni operasyonda anda yalniz bir aktif (EndedAt NULL) satir
                -- olabilir. Yeni aktivite baslarken eski kapanmali (service sorumlulugu).
                CREATE UNIQUE INDEX [UX_WOOA_OneActivePerOp]
                    ON [{schemaForSql}].[WorkOrderOperationActivity]([WorkOrderOperationId])
                    WHERE [EndedAt] IS NULL;

                -- Sorgular: operasyon bazli geçmiş listesi (Sequence: StartedAt DESC)
                CREATE INDEX [IX_WOOA_OpStartedAt]
                    ON [{schemaForSql}].[WorkOrderOperationActivity]
                       ([WorkOrderOperationId], [StartedAt] DESC);

                -- Sorgular: personel bazli aktivite gecmisi (vardiya raporlari + Faz 4 OEE icin)
                CREATE INDEX [IX_WOOA_PersonnelStarted]
                    ON [{schemaForSql}].[WorkOrderOperationActivity]
                       ([PersonnelId], [StartedAt] DESC);
            END;

            -- Migration: [CreatedBy]/[UpdatedBy] NVARCHAR -> [CreatedById]/[UpdatedById] INT
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperationActivity]', N'U') IS NOT NULL
            BEGIN
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperationActivity]') AND name = N'CreatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[WorkOrderOperationActivity] DROP COLUMN [CreatedBy];
                    ALTER TABLE [{schemaForSql}].[WorkOrderOperationActivity] ADD [CreatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperationActivity]') AND name = N'CreatedById')
                    ALTER TABLE [{schemaForSql}].[WorkOrderOperationActivity] ADD [CreatedById] INT NULL;
                IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperationActivity]') AND name = N'UpdatedBy')
                BEGIN
                    ALTER TABLE [{schemaForSql}].[WorkOrderOperationActivity] DROP COLUMN [UpdatedBy];
                    ALTER TABLE [{schemaForSql}].[WorkOrderOperationActivity] ADD [UpdatedById] INT NULL;
                END
                ELSE IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperationActivity]') AND name = N'UpdatedById')
                    ALTER TABLE [{schemaForSql}].[WorkOrderOperationActivity] ADD [UpdatedById] INT NULL;
            END

            -- ===== 2026-05-21 Faz 2: WorkOrderOperationActivity → ActivityReason FK =====
            -- Tablo zaten varsa idempotent ekle. Hem tablo hem sutun var olmasi + FK
            -- olmamasi kosullarinda olusturulur.
            IF OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperationActivity]', N'U') IS NOT NULL
               AND OBJECT_ID(N'[{schemaForSql}].[ActivityReason]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{schemaForSql}].[WorkOrderOperationActivity]', N'ActivityReasonId') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.foreign_keys
                   WHERE [name] = N'FK_WOOA_ActivityReason'
                     AND [parent_object_id] = OBJECT_ID(N'[{schemaForSql}].[WorkOrderOperationActivity]'))
            BEGIN
                ALTER TABLE [{schemaForSql}].[WorkOrderOperationActivity]
                WITH NOCHECK
                ADD CONSTRAINT [FK_WOOA_ActivityReason]
                    FOREIGN KEY ([ActivityReasonId])
                    REFERENCES [{schemaForSql}].[ActivityReason]([Id]);
            END;
            ";

        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    private async Task EnsureDocLayoutTableAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var schemaLiteral = _schema.Replace("'", "''");
        var sql = $"""
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[DocLayout]
                (
                    [Id]              INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_DocLayout] PRIMARY KEY,
                    [Code]            NVARCHAR(60)      NOT NULL,
                    [Name]            NVARCHAR(200)     NOT NULL,
                    -- Legacy string code (backward-compat). Yeni kayitlar DocumentTypeId kullanir;
                    -- DocType degeri DocumentType.Code'dan turetilir. NULL = "custom" (ozgur tasarim).
                    [DocType]         NVARCHAR(60)      NULL,
                    -- FK to DocumentType. NULL = "custom" tasarim (ozgur/belirli tipe bagli degil).
                    [DocumentTypeId]  INT               NULL,
                    [Description]     NVARCHAR(500)     NULL,
                    [LayoutJson]      NVARCHAR(MAX)     NOT NULL,
                    [PageW]           DECIMAL(8,2)      NOT NULL CONSTRAINT [DF_DocLayout_PageW]   DEFAULT(210),
                    [PageH]           DECIMAL(8,2)      NOT NULL CONSTRAINT [DF_DocLayout_PageH]   DEFAULT(297),
                    [MarginTop]       DECIMAL(6,2)      NOT NULL CONSTRAINT [DF_DocLayout_MT]      DEFAULT(10),
                    [MarginBot]       DECIMAL(6,2)      NOT NULL CONSTRAINT [DF_DocLayout_MB]      DEFAULT(10),
                    [MarginLeft]      DECIMAL(6,2)      NOT NULL CONSTRAINT [DF_DocLayout_ML]      DEFAULT(15),
                    [MarginRight]     DECIMAL(6,2)      NOT NULL CONSTRAINT [DF_DocLayout_MR]      DEFAULT(10),
                    [OwnerUserId]     INT               NOT NULL,
                    [IsDefault]       BIT               NOT NULL CONSTRAINT [DF_DocLayout_IsDefault] DEFAULT(0),
                    [IsActive]        BIT               NOT NULL CONSTRAINT [DF_DocLayout_IsActive]  DEFAULT(1),
                    [Created]         DATETIME      NOT NULL CONSTRAINT [DF_DocLayout_Created] DEFAULT(SYSUTCDATETIME()),
                    [Updated]         DATETIME      NOT NULL CONSTRAINT [DF_DocLayout_Updated] DEFAULT(SYSUTCDATETIME()),
                    -- LEGACY: 'pdf' (default) | 'email' — render hedefi.
                    -- 2026-05-20: UI'da Cikti Turu dropdown'i kaldirildi; sutun
                    -- backward-compat icin korunur, yeni kayitlar her zaman 'pdf'.
                    [OutputFormat]    NVARCHAR(20)      NOT NULL CONSTRAINT [df_DocLayout_OutputFormat] DEFAULT(N'pdf'),
                    -- 2026-05-20: Mail sablonu olarak da kullanim bayragi.
                    [UseAsMailTemplate] BIT             NOT NULL CONSTRAINT [df_DocLayout_UseAsMail]   DEFAULT(0),
                    CONSTRAINT [FK_DocLayout_DocumentType] FOREIGN KEY ([DocumentTypeId])
                        REFERENCES [{s}].[DocumentType]([Id])
                );
                CREATE UNIQUE INDEX [ux_DocLayout_Code]            ON [{s}].[DocLayout]([Code]);
                CREATE INDEX [ix_DocLayout_DocType]                ON [{s}].[DocLayout]([DocType])        WHERE [IsActive] = 1;
                CREATE INDEX [ix_DocLayout_DocumentTypeId]         ON [{s}].[DocLayout]([DocumentTypeId]) WHERE [IsActive] = 1;
                CREATE INDEX [ix_DocLayout_Owner]                  ON [{s}].[DocLayout]([OwnerUserId])    WHERE [IsActive] = 1;
            END;

            -- ── Idempotent ALTER: mevcut DB'lere DocumentTypeId FK kolonu ────────
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'DocumentTypeId') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayout] ADD [DocumentTypeId] INT NULL;
            END;

            -- 2026-05-31: Mail sablonu icin varsayilan Konu + Govde alanlari.
            -- Toplu mail Compose ekraninda sablon secilince bu degerler otomatik dolar.
            -- NVARCHAR(MAX) — token + uzun metin destegi.
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'DefaultSubject') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayout] ADD [DefaultSubject] NVARCHAR(500) NULL;
            END;
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'DefaultBody') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayout] ADD [DefaultBody] NVARCHAR(MAX) NULL;
            END;

            -- 2026-05-31 (v2): Mail sablonu varsayilanlari icin view binding.
            -- Compose ekraninda sablon secilince Konu + Govde view'in ilk satirinin
            -- kolonlarindan turetilir. WHERE serbest, opsiyonel.
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'DefaultsViewName') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayout] ADD [DefaultsViewName] NVARCHAR(128) NULL;
            END;
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'DefaultsSubjectColumn') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayout] ADD [DefaultsSubjectColumn] NVARCHAR(128) NULL;
            END;
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'DefaultsBodyColumn') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayout] ADD [DefaultsBodyColumn] NVARCHAR(128) NULL;
            END;
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'DefaultsWhere') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayout] ADD [DefaultsWhere] NVARCHAR(2000) NULL;
            END;

            -- 2026-05-20: Mail sablonu kullanim bayragi.
            -- Eski 'OutputFormat=email' modu kaldirildi. Bunun yerine her dizayn
            -- standart bir DocLayout'tur; bu BIT acikken dizayn mail compose
            -- ekraninda da sablon olarak listelenir.
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'UseAsMailTemplate') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayout]
                    ADD [UseAsMailTemplate] BIT NOT NULL
                        CONSTRAINT [df_DocLayout_UseAsMail] DEFAULT(0);
            END;
            -- Geri uyumluluk: eski OutputFormat='email' kayitlarini, yeni bayraga tasi.
            -- (UI'da artik OutputFormat dropdown'i yok, ama eski kayitlarda alan dolu olabilir.)
            -- EXEC() icine sarildi: ayni batch'te ALTER ADD'den sonra T-SQL parser
            -- yeni kolonu compile-time'da goremedigi icin 'Invalid column' atiyor.
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'UseAsMailTemplate') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'OutputFormat') IS NOT NULL
            BEGIN
                EXEC(N'
                    UPDATE [{s}].[DocLayout]
                       SET [UseAsMailTemplate] = 1
                     WHERE [OutputFormat] = ''email'' AND [UseAsMailTemplate] = 0;
                ');
            END;

            -- DocType kolonu mevcut DB'lerde NOT NULL olabilir; "custom" rows icin
            -- DocumentTypeId NULL'a izin verecek sekilde NULL'a indir.
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND EXISTS (
                   SELECT 1 FROM sys.columns c
                   WHERE c.object_id = OBJECT_ID(N'[{s}].[DocLayout]')
                     AND c.[name] = N'DocType' AND c.is_nullable = 0)
            BEGIN
                ALTER TABLE [{s}].[DocLayout] ALTER COLUMN [DocType] NVARCHAR(60) NULL;
            END;

            -- FK constraint (mevcut DB'lere ekle)
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND OBJECT_ID(N'[{s}].[DocumentType]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'DocumentTypeId') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.foreign_keys
                   WHERE name = N'FK_DocLayout_DocumentType'
                     AND parent_object_id = OBJECT_ID(N'[{s}].[DocLayout]'))
            BEGIN
                ALTER TABLE [{s}].[DocLayout]
                    ADD CONSTRAINT [FK_DocLayout_DocumentType] FOREIGN KEY ([DocumentTypeId])
                        REFERENCES [{s}].[DocumentType]([Id]);
            END;

            -- Index for new FK column
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'DocumentTypeId') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.indexes
                   WHERE name = N'ix_DocLayout_DocumentTypeId'
                     AND object_id = OBJECT_ID(N'[{s}].[DocLayout]'))
            BEGIN
                EXEC(N'CREATE INDEX [ix_DocLayout_DocumentTypeId] ON [{s}].[DocLayout]([DocumentTypeId]) WHERE [IsActive] = 1;');
            END;

            -- ── Idempotent ALTER: mevcut DB'lere OutputFormat kolonu ──────────────
            -- Mail sablonu desteg​i (Faz 1). PDF default; "email" set edilirse render
            -- pipeline'i HTML mail govdesi uretir.
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'OutputFormat') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayout] ADD [OutputFormat] NVARCHAR(20) NOT NULL CONSTRAINT [df_DocLayout_OutputFormat] DEFAULT(N'pdf');
            END;

            -- ── Idempotent data backfill: DocType (string) → DocumentTypeId (INT) ──
            -- EXEC() ile deferred — ayni batch icinde ALTER ADD COLUMN ile UPDATE birlikte
            -- olursa parser column'i bulamiyordu. EXEC() yeni batch acar, schema visible.
            IF COL_LENGTH(N'{schemaLiteral}.[DocLayout]', N'DocumentTypeId') IS NOT NULL
            BEGIN
                EXEC(N'
                    IF EXISTS (SELECT 1 FROM [{s}].[DocLayout]
                               WHERE [DocumentTypeId] IS NULL
                                 AND [DocType] IS NOT NULL
                                 AND [DocType] <> N''custom'')
                    BEGIN
                        ;WITH map AS (
                            SELECT N''sales_quote''    AS old, N''satis_teklifi''  AS new_code UNION ALL
                            SELECT N''sales_order''    , N''satis_siparisi''                   UNION ALL
                            SELECT N''purchase_order'' , N''alis_siparisi''                    UNION ALL
                            SELECT N''delivery_note''  , N''irsaliye''                         UNION ALL
                            SELECT N''invoice''        , N''fatura''
                        )
                        UPDATE l SET l.[DocumentTypeId] = dt.[Id]
                        FROM [{s}].[DocLayout] l
                        LEFT JOIN map m ON m.old = l.[DocType]
                        INNER JOIN [{s}].[DocumentType] dt
                               ON dt.[Code] = COALESCE(m.new_code, l.[DocType])
                        WHERE l.[DocumentTypeId] IS NULL
                          AND l.[DocType] IS NOT NULL
                          AND l.[DocType] <> N''custom'';
                    END;
                ');
            END;

            -- 2026-07-05: DocLayout — CreatedAt → Created, UpdatedAt → Updated kolon rename.
            -- Eski DB'lerde kolonlar farkli isimde olabilir; idempotent EXEC ile rename.
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'CreatedAt') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'Created') IS NULL
            BEGIN
                EXEC sp_rename N'[{s}].[DocLayout].[CreatedAt]', N'Created', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{s}].[DocLayout]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'UpdatedAt') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayout]', N'Updated') IS NULL
            BEGIN
                EXEC sp_rename N'[{s}].[DocLayout].[UpdatedAt]', N'Updated', N'COLUMN';
            END;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    private async Task EnsureDocLayoutRuleTableAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        // Dinamik Tasarım Seçim Motoru — hiyerarşik kural tablosu.
        // Her kriter (Customer, User, Branch, Warehouse, ContactGroup) NULLable kolon olarak
        // saklanır; "bu kolonun null olması" = "tüm değerler için geçerli kural".
        // Repository sorgusu 2^n ağırlık toplamı ile en spesifik kuralı seçer.
        var s = _schema.Replace("]", "]]");
        var schemaLiteral = _schema.Replace("'", "''");
        var sql = $"""
            IF OBJECT_ID(N'[{s}].[DocLayoutRule]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[DocLayoutRule]
                (
                    [Id]              INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_DocLayoutRule] PRIMARY KEY,
                    -- Legacy string code (backward-compat). Yeni kayitlar DocumentTypeId kullanir.
                    [DocType]         NVARCHAR(60)      NULL,
                    -- FK to DocumentType (Document.DocumentTypeId ile hizalanir).
                    [DocumentTypeId]  INT               NULL,
                    [LayoutId]        INT               NOT NULL,
                    [CustomerId]      INT               NULL,
                    [ContactGroupId]  INT               NULL,
                    [UserId]          INT               NULL,
                    [BranchId]        INT               NULL,
                    [WarehouseId]     INT               NULL,
                    [IsActive]        BIT               NOT NULL CONSTRAINT [DF_DocLayoutRule_IsActive]  DEFAULT(1),
                    [Created]         DATETIME      NOT NULL CONSTRAINT [DF_DocLayoutRule_Created] DEFAULT(SYSUTCDATETIME()),
                    [Updated]         DATETIME      NOT NULL CONSTRAINT [DF_DocLayoutRule_Updated] DEFAULT(SYSUTCDATETIME()),
                    CONSTRAINT [FK_DocLayoutRule_Layout]       FOREIGN KEY ([LayoutId])       REFERENCES [{s}].[DocLayout]([Id]),
                    CONSTRAINT [FK_DocLayoutRule_DocumentType] FOREIGN KEY ([DocumentTypeId]) REFERENCES [{s}].[DocumentType]([Id])
                );

                -- Sorgu desenine optimize edilmiş kapsayıcı (covering) index:
                -- (DocType, IsActive) filtresinden sonra kriter kolonları + LayoutId + Updated
                -- INCLUDE'da geldiği için sorgu key-lookup yapmadan tamamlanır.
                -- 2026-07-10: INCLUDE [UpdatedAt] → [Updated] — taze tablo [Updated] ile
                -- dogar; eski referans taze DB'de 1911 ile tum init'i durduruyordu.
                CREATE NONCLUSTERED INDEX [ix_DocLayoutRule_Lookup]
                    ON [{s}].[DocLayoutRule]([DocType], [IsActive])
                    INCLUDE ([CustomerId], [ContactGroupId], [UserId], [BranchId], [WarehouseId], [LayoutId], [Updated]);

                -- Aynı (DocType + kriter kombinasyonu) için iki aktif kural olamaz.
                -- Filtered UNIQUE index NULL'leri "değer" olarak kabul ettiğinden bu örtüşür.
                CREATE UNIQUE NONCLUSTERED INDEX [ux_DocLayoutRule_Combo]
                    ON [{s}].[DocLayoutRule]([DocType], [CustomerId], [ContactGroupId], [UserId], [BranchId], [WarehouseId])
                    WHERE [IsActive] = 1;
            END;

            -- 2026-07-05: DocLayoutRule — CreatedAt → Created, UpdatedAt → Updated kolon rename.
            -- 2026-07-10: Rename'ler index bloklarindan ONCEye tasindi — asagidaki
            -- ix_DocLayoutRule_Lookup INCLUDE listeleri [Updated] kullanir; rename metodun
            -- sonunda kalirsa eski DB'lerde kolon henuz [UpdatedAt] iken index yeniden
            -- olusturma 1911 ile patlar.
            IF OBJECT_ID(N'[{s}].[DocLayoutRule]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayoutRule]', N'CreatedAt') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayoutRule]', N'Created') IS NULL
            BEGIN
                EXEC sp_rename N'[{s}].[DocLayoutRule].[CreatedAt]', N'Created', N'COLUMN';
            END;
            IF OBJECT_ID(N'[{s}].[DocLayoutRule]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayoutRule]', N'UpdatedAt') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayoutRule]', N'Updated') IS NULL
            BEGIN
                EXEC sp_rename N'[{s}].[DocLayoutRule].[UpdatedAt]', N'Updated', N'COLUMN';
            END;

            -- Mevcut DB'ler icin migrate: ContactGroupId kolonu (Cari Grup kriteri)
            IF OBJECT_ID(N'[{s}].[DocLayoutRule]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.DocLayoutRule', N'ContactGroupId') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayoutRule] ADD [ContactGroupId] INT NULL;

                -- Eski UNIQUE index'i yeniden olustur (ContactGroupId dahil)
                IF EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'ux_DocLayoutRule_Combo' AND object_id = OBJECT_ID(N'[{s}].[DocLayoutRule]'))
                    EXEC(N'DROP INDEX [ux_DocLayoutRule_Combo] ON [{s}].[DocLayoutRule];');

                EXEC(N'CREATE UNIQUE NONCLUSTERED INDEX [ux_DocLayoutRule_Combo]
                       ON [{s}].[DocLayoutRule]([DocType], [CustomerId], [ContactGroupId], [UserId], [BranchId], [WarehouseId])
                       WHERE [IsActive] = 1;');

                -- Eski covering index'i drop+yeniden olustur (ContactGroupId INCLUDE'a eklenmeli)
                IF EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'ix_DocLayoutRule_Lookup' AND object_id = OBJECT_ID(N'[{s}].[DocLayoutRule]'))
                    EXEC(N'DROP INDEX [ix_DocLayoutRule_Lookup] ON [{s}].[DocLayoutRule];');

                EXEC(N'CREATE NONCLUSTERED INDEX [ix_DocLayoutRule_Lookup]
                       ON [{s}].[DocLayoutRule]([DocType], [IsActive])
                       INCLUDE ([CustomerId], [ContactGroupId], [UserId], [BranchId], [WarehouseId], [LayoutId], [Updated]);');
            END;

            -- ── Mevcut DB'ler için AccountType kolonu (Cari tipi kriteri) ──
            IF OBJECT_ID(N'[{s}].[DocLayoutRule]', N'U') IS NOT NULL
               AND COL_LENGTH(N'{schemaLiteral}.DocLayoutRule', N'AccountType') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayoutRule] ADD [AccountType] TINYINT NULL;

                -- UNIQUE index'e AccountType ekle (aynı kombinasyon farklı tip için iki kural olabilir)
                IF EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'ux_DocLayoutRule_Combo' AND object_id = OBJECT_ID(N'[{s}].[DocLayoutRule]'))
                    EXEC(N'DROP INDEX [ux_DocLayoutRule_Combo] ON [{s}].[DocLayoutRule];');

                EXEC(N'CREATE UNIQUE NONCLUSTERED INDEX [ux_DocLayoutRule_Combo]
                       ON [{s}].[DocLayoutRule]([DocType], [CustomerId], [ContactGroupId], [UserId], [BranchId], [WarehouseId], [AccountType])
                       WHERE [IsActive] = 1;');

                -- Covering index INCLUDE'a AccountType ekle
                IF EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'ix_DocLayoutRule_Lookup' AND object_id = OBJECT_ID(N'[{s}].[DocLayoutRule]'))
                    EXEC(N'DROP INDEX [ix_DocLayoutRule_Lookup] ON [{s}].[DocLayoutRule];');

                EXEC(N'CREATE NONCLUSTERED INDEX [ix_DocLayoutRule_Lookup]
                       ON [{s}].[DocLayoutRule]([DocType], [IsActive])
                       INCLUDE ([CustomerId], [ContactGroupId], [UserId], [BranchId], [WarehouseId], [AccountType], [LayoutId], [Updated]);');
            END;

            -- ── Mevcut DB icin DocumentTypeId kolonu (Phase: tip FK konsolidasyon) ──
            IF OBJECT_ID(N'[{s}].[DocLayoutRule]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayoutRule]', N'DocumentTypeId') IS NULL
            BEGIN
                ALTER TABLE [{s}].[DocLayoutRule] ADD [DocumentTypeId] INT NULL;
            END;

            -- DocType kolonu mevcut DB'lerde NOT NULL olabilir; DocumentTypeId tabanli
            -- yeni kayitlarda DocType opsiyonel olsun diye NULL'a indir.
            IF OBJECT_ID(N'[{s}].[DocLayoutRule]', N'U') IS NOT NULL
               AND EXISTS (
                   SELECT 1 FROM sys.columns c
                   WHERE c.object_id = OBJECT_ID(N'[{s}].[DocLayoutRule]')
                     AND c.[name] = N'DocType' AND c.is_nullable = 0)
            BEGIN
                ALTER TABLE [{s}].[DocLayoutRule] ALTER COLUMN [DocType] NVARCHAR(60) NULL;
            END;

            -- FK constraint
            IF OBJECT_ID(N'[{s}].[DocLayoutRule]', N'U') IS NOT NULL
               AND OBJECT_ID(N'[{s}].[DocumentType]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[DocLayoutRule]', N'DocumentTypeId') IS NOT NULL
               AND NOT EXISTS (
                   SELECT 1 FROM sys.foreign_keys
                   WHERE name = N'FK_DocLayoutRule_DocumentType'
                     AND parent_object_id = OBJECT_ID(N'[{s}].[DocLayoutRule]'))
            BEGIN
                ALTER TABLE [{s}].[DocLayoutRule]
                    ADD CONSTRAINT [FK_DocLayoutRule_DocumentType] FOREIGN KEY ([DocumentTypeId])
                        REFERENCES [{s}].[DocumentType]([Id]);
            END;

            -- ── Idempotent data backfill: DocType (string) → DocumentTypeId (INT) ──
            -- EXEC() ile deferred — ayni batch icinde ALTER ADD COLUMN ile UPDATE birlikte
            -- olursa parser column'i bulamiyordu.
            IF COL_LENGTH(N'{schemaLiteral}.[DocLayoutRule]', N'DocumentTypeId') IS NOT NULL
            BEGIN
                EXEC(N'
                    IF EXISTS (SELECT 1 FROM [{s}].[DocLayoutRule]
                               WHERE [DocumentTypeId] IS NULL
                                 AND [DocType] IS NOT NULL
                                 AND [DocType] <> N''custom'')
                    BEGIN
                        ;WITH map AS (
                            SELECT N''sales_quote''    AS old, N''satis_teklifi''  AS new_code UNION ALL
                            SELECT N''sales_order''    , N''satis_siparisi''                   UNION ALL
                            SELECT N''purchase_order'' , N''alis_siparisi''                    UNION ALL
                            SELECT N''delivery_note''  , N''irsaliye''                         UNION ALL
                            SELECT N''invoice''        , N''fatura''
                        )
                        UPDATE r SET r.[DocumentTypeId] = dt.[Id]
                        FROM [{s}].[DocLayoutRule] r
                        LEFT JOIN map m ON m.old = r.[DocType]
                        INNER JOIN [{s}].[DocumentType] dt
                               ON dt.[Code] = COALESCE(m.new_code, r.[DocType])
                        WHERE r.[DocumentTypeId] IS NULL
                          AND r.[DocType] IS NOT NULL
                          AND r.[DocType] <> N''custom'';
                    END;
                ');
            END;

            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

    /// <summary>
    /// 2026-07-02: stock_doc/stock_doc_line (native depo modulu) emekliye ayrildi — stok
    /// hareketi konsolidasyonu kapsaminda Document/DocumentLine'a tasindi (canli veri yok,
    /// dogrudan DROP). Yerine Sayim'in taslak/gercek ayrimini tasiyan InventoryCount/
    /// InventoryCountLine companion cifti geliyor (ham sayim girisleri stok hareketi
    /// DEGILDIR — sadece "Yansit" ile turetilen farklar DocumentLine'a yazilir).
    /// </summary>
    private async Task EnsureInventoryCountTablesAsync(SqlConnection connection, CancellationToken cancellationToken)
    {
        var s = _schema.Replace("]", "]]");
        var sql = $"""
            IF OBJECT_ID(N'[{s}].[stock_doc_line]', N'U') IS NOT NULL
                DROP TABLE [{s}].[stock_doc_line];
            IF OBJECT_ID(N'[{s}].[stock_doc]', N'U') IS NOT NULL
                DROP TABLE [{s}].[stock_doc];

            IF OBJECT_ID(N'[{s}].[InventoryCount]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[InventoryCount]
                (
                    [Id]         INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_InventoryCount] PRIMARY KEY,
                    [DocumentId] INT NOT NULL,
                    [LocationId] INT NULL,
                    [CountDate]  DATETIME NOT NULL CONSTRAINT [DF_InventoryCount_CountDate] DEFAULT SYSUTCDATETIME(),
                    -- Status: 0=Draft (serbestce duzenlenebilir), 1=Applied (Yansitildi — DocumentLine'a
                    -- fark satirlari yazildi, immutable), 2=Cancelled.
                    [Status]     TINYINT NOT NULL CONSTRAINT [DF_InventoryCount_Status] DEFAULT(0),
                    [CreatedById] INT NULL,
                    [Created]    DATETIME NOT NULL CONSTRAINT [DF_InventoryCount_Created] DEFAULT SYSUTCDATETIME(),
                    [UpdatedById] INT NULL,
                    [Updated]    DATETIME NULL,
                    CONSTRAINT [UX_InventoryCount_Document] UNIQUE ([DocumentId]),
                    CONSTRAINT [FK_InventoryCount_Document] FOREIGN KEY ([DocumentId])
                        REFERENCES [{s}].[Document]([id]),
                    CONSTRAINT [CK_InventoryCount_Status] CHECK ([Status] BETWEEN 0 AND 2)
                );
                CREATE INDEX [IX_InventoryCount_Status] ON [{s}].[InventoryCount]([Status]);
            END;

            IF OBJECT_ID(N'[{s}].[InventoryCountLine]', N'U') IS NULL
            BEGIN
                CREATE TABLE [{s}].[InventoryCountLine]
                (
                    [Id]               INT IDENTITY(1,1) NOT NULL CONSTRAINT [PK_InventoryCountLine] PRIMARY KEY,
                    [InventoryCountId] INT NOT NULL,
                    [ItemId]           INT NOT NULL,
                    [ConfigId]         INT NULL,
                    [UnitId]           INT NULL,
                    -- SystemQtyAtCount: sadece referans/gorsel amacli (taslakta doldurulan) snapshot.
                    -- "Yansit" gercek farki hesaplarken bakiyeyi YENIDEN sorgular (staleness onlemi).
                    [SystemQtyAtCount] DECIMAL(18,4) NULL,
                    [CountedQty]       DECIMAL(18,4) NOT NULL CONSTRAINT [DF_InventoryCountLine_CountedQty] DEFAULT(0),
                    [Notes]            NVARCHAR(500) NULL,
                    CONSTRAINT [FK_InventoryCountLine_InventoryCount] FOREIGN KEY ([InventoryCountId])
                        REFERENCES [{s}].[InventoryCount]([Id]) ON DELETE CASCADE
                );
                CREATE INDEX [IX_InventoryCountLine_Count] ON [{s}].[InventoryCountLine]([InventoryCountId]);
            END;

            -- 2026-07-06: Kalem bazinda depo — satir kendi lokasyonunu tasiyabilir (NULL = header lokasyonu).
            IF OBJECT_ID(N'[{s}].[InventoryCountLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[InventoryCountLine]', N'LocationId') IS NULL
            BEGIN
                ALTER TABLE [{s}].[InventoryCountLine] ADD [LocationId] INT NULL;
            END;

            -- 2026-07-12: Izlenebilirlik — sayim satirinda lot/seri (lot-takipli LotNo zorunlu;
            -- seri-takipli Serials = satir\virgul ile ayrilmis liste, adedi CountedQty'ye esit).
            -- Enforcement SaveInventoryCountAsync'te; yansitmada lot DocumentLine'a tasinir.
            IF OBJECT_ID(N'[{s}].[InventoryCountLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[InventoryCountLine]', N'LotNo') IS NULL
                ALTER TABLE [{s}].[InventoryCountLine] ADD [LotNo] NVARCHAR(50) NULL;
            IF OBJECT_ID(N'[{s}].[InventoryCountLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[InventoryCountLine]', N'Serials') IS NULL
                ALTER TABLE [{s}].[InventoryCountLine] ADD [Serials] NVARCHAR(MAX) NULL;
            -- 2026-07-12: Çoklu lot kırılımı (sayım) — JSON dizisi (lotNo + qty nesneleri).
            -- Bir kalemde birden fazla lot sayılabilir; CountedQty = qty toplamı.
            IF OBJECT_ID(N'[{s}].[InventoryCountLine]', N'U') IS NOT NULL
               AND COL_LENGTH(N'[{s}].[InventoryCountLine]', N'LotBreakdown') IS NULL
                ALTER TABLE [{s}].[InventoryCountLine] ADD [LotBreakdown] NVARCHAR(MAX) NULL;
            """;
        await using var cmd = connection.CreateCommand();
        cmd.CommandText = sql;
        await cmd.ExecuteNonQueryAsync(cancellationToken);
    }

