            -- ── ApprovalFlowEdge ─────────────────────────────────────────────────────
            -- 2026-05-25: Branching destekli akış — node'lar arasi edge'ler.
            -- SourceStepId → TargetStepId, Label (Onay/Red/koşul), EdgeKind (default/true/false/custom)
            IF OBJECT_ID(N'[{s}].[ApprovalFlowEdge]', N'U') IS NULL
