                IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(N'[{s}].[ApprovalFlowVariable]') AND name = N'SqlQuery')
                    ALTER TABLE [{s}].[ApprovalFlowVariable] ADD [SqlQuery] NVARCHAR(MAX) NULL;
